(50561, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "2J", "Common_Name": "A330-900 Neo", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Airbus A330-900 Neo", "Generation": "", "Height_m": "", "IATA_Code": "339", "ICAO_Code": "A339", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Airbus", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "A330-900 Neo", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "H", "Weights": "", "Wingspan_m": ""}'),
(50562, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Long range widebody airliner", "Bibliography": "Airliners.net", "Category": "4J", "Common_Name": "A340-200", "Country_Origin": "European consortium", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The A340-200 and 300 are the initial variants of the successful quad engined A340 family of long haul widebodies. \\n\\nThe A340 and closely related A330 were launched in June 1987, with the A340''s first flight occurring on October 25 1991 (an A340-300). The A340 entered service with Lufthansa and Air France in March 1993, following JAA certification the previous December. \\n\\nThe A340 shares the same flightdeck including side stick controllers and EFIS, plus flybywire, basic airframe, systems, fuselage and wing with the A330 (the flightdeck is also common to the A320 series). Power is from four CFM56s, the four engine configuration being more efficient for long range flights (as twins need more power for a given weight for engine out on takeoff performance) and free from ETOPS restrictions. \\n\\nThe A340-300 has the same fuselage length as the A330-300, while the shortened A340-200 trades seating capacity for greater range (first flight April 1 1992). \\n\\nThe heavier A340-300E is available in 271,000kg (597,450lb) and 275,000kg (606,275lb) max takeoff weights, their typical ranges with 295 passengers are 13,155km (7100nm) and 13,525km (7300nm) respectively. Power for these models is from 152.3kN (34,000lb) CFM56-5C4s (the most powerful CFM56s built). The first A340-300Es were delivered to Singapore Airlines in April 1996. \\n\\nThe 275,000kg (606,275lb) max takeoff weight A340-8000 is based on the 200 but has extra fuel in three additional rear cargo hold tanks and offers a 15,000km (8100nm) range with 232 three class passengers (hence the A340-8000 designation). It too is powered by CFM56-5C4s. One has been built for the Sultan of Brunei. \\n\\nAll versions are offered with underfloor passenger sleepers.", "Dimensions": "A340-200 - Wing span 60.30m (197ft 0in), length 59.39m (194ft 10in), height 16.74m (54ft 11in). Wing area 363.1m2 (3908.4sq ft). \\nA340-300 - Same except for length 63.70m (209ft 0in).", "Engine_Count": "4", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Airbus A340-200", "Generation": "", "Height_m": "", "IATA_Code": "342", "ICAO_Code": "A342", "Length_m": "59.39", "MTOW_kg": "126000", "Manufacturer": "Airbus", "Max_Pax": "", "Max_Speed_kmh": "914", "Mission_Type": "Passenger", "Model": "A340-200", "Name": "Airbus A340-200/300", "Origin": "European consortium", "Performance": "A340-200 - Max cruising speed 914km/h (494kt), economical cruising speed 880km/h (475kt). Range at typical airline operating weight with 263 passengers and reserves 13,805km (7450nm). \\nA340-300 - Speeds same. Range at typical airline operating weight with 295 passengers and reserves 12,415km (6700nm).", "Powerplant_Desc": "Four 138.8kN (31,200lb) CFM International CFM56-5C or 145kN (32,550lb) CFM56-5C3 turbofans.", "Powerplants": "Four 138.8kN (31,200lb) CFM International CFM56-5C or 145kN (32,550lb) CFM56-5C3 turbofans.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "805", "Range_nm": "7450", "Record_Status": "active", "Role": "Long range widebody airliner", "Seating_Config": "Flightcrew of two. \\nA340-200 - Typical three class arrangement for 263 pax, or 303 in two classes. \\nA340-300 - Typical three class accommodation for 303, or 335 in two classes. Fore and aft underbelly holds can accommodate LD3 containers or pallets.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/airbus-a340-200300/27", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. \\nA340-200 - Typical three class arrangement for 263 pax, or 303 in two classes. \\nA340-300 - Typical three class accommodation for 303, or 335 in two classes. Fore and aft underbelly holds can accommodate LD3 containers or pallets.", "Units_Built": "A total of 321 A340 (including all series) had been ordered by May 2002, of which 217 had been delivered.", "WTC": "H", "Weights": "A340-200 - Operating empty 126,000kg (277,775lb), max takeoff 260,000kg (573,200lb). \\nA340-300 - Operating empty 129,800kg (286,150lb), max takeoff 260,000kg (573,200lb). \\nA340-300E - Operating empty 129,300-130,200kg (285,050-287,050lb), MTOW 271,000kg (597,450lb) or 275,000kg (606,275lb).", "Wingspan_m": "60.30"}'),
(50563, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "4J", "Common_Name": "A340-300", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "4", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Airbus A340-300", "Generation": "", "Height_m": "", "IATA_Code": "343", "ICAO_Code": "A343", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Airbus", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "A340-300", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "H", "Weights": "", "Wingspan_m": ""}'),
(50564, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Long range widebody airliners", "Bibliography": "Airliners.net", "Category": "4J", "Common_Name": "A340-500", "Country_Origin": "European consortium", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The 15,740km (8500nm) ultra long range A340-500 and stretched 372 seat A340-600 are new variants of the Airbus A340 family, and are currently the world''s longest range airliners.\\n\\nCompared with the A340-300, the A340-600 features a 9.07m (35ft 1in) stretch (5.87m/19ft 3in ahead of the wing and 3.20m/10ft 6in behind), allowing it to seat 372 passengers in a typical three class arrangement. This gives Airbus a true early model 747 replacement and near direct competitor to the 747-400, with similar range, but, Airbus claims, better operating economics (per seat). \\n\\nThe A340-500 meanwhile is stretched by only 3.19m (10ft 6in) compared with the A340-300, and so seats 313 in three classes, but it has a massive range of 15,740km (8500nm), which makes it the longest ranging airliner in the world, capable for example of operating Los Angeles-Singapore nonstop. \\n\\nThe two new A340 models share a common wing. The wing is based on the A330/A340''s but is 1.6m (5.2ft) longer and has a tapered wingbox insert, increasing wing area and fuel capacity. Both models feature three fuselage plugs. The other change to the A340 airframe is the use of the A330-200 twin''s larger fin and enlarged horizontal area stabilisers. To cope with the increased weights the centre undercarriage main gear is a four wheel bogie, rather than a two wheel unit. \\n\\nBoth new A340s have a high degree of commonality with the A330 and other A340 models. They feature Airbus'' common two crew flightdeck, but with some improvements such as LCD rather than CRT displays and modernised systems. \\n\\nThe A340-500 is powered by four 236kN (53,000lb) thrust Rolls-Royce Trent 556 turbofans, and the A340-600 by the 249kN (56,000lb) thrust Trent 556. \\n\\nThe commercial launch for the A340-500/600 was at the 1997 Paris Airshow, the program''s industrial launch was in December that year when Virgin Atlantic ordered eight A340-600s and optioned eight. First flight of the A340-600 was made on April 23, 2001. After a 1600 hour flight test program, certification was received on May 29, 2002. Virgin Atlantic took delivery of its first A340-600 at the 2002 Farnborough International Airshow, and began commercial services in August.\\n\\nThe A340-500 made its first flight on February 11, 2002, and was certificated on December 3 after 400 hours of flight test.", "Dimensions": "A340-500 - Wing span 63.70m (208ft 11in), length 67.80m (222ft 5in), height 17.80m (58ft 5in). Wing area 437.0m2 (4704sq ft).\\nA340-600 - Same, except length 75.30m (247ft 0in).", "Engine_Count": "4", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Airbus A340-500", "Generation": "", "Height_m": "", "IATA_Code": "345", "ICAO_Code": "A345", "Length_m": "67.80", "MTOW_kg": "170400", "Manufacturer": "Airbus", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "A340-500", "Name": "Airbus A340-500/600", "Origin": "European consortium", "Performance": "Typical cruising speed Mach 0.83.\\nA340-500 - Range with 313 passengers 15,742km (8500nm). \\nA340-600 - Range with 380 passengers 13,890km (7500nm).", "Powerplant_Desc": "A340-500 - Four 236kN (53,000lb) Rolls-Royce Trent 553 turbofans\\nA340-600 - Four 249kN (56,000lb) Rolls-Royce Trent 556 turbofans.", "Powerplants": "A340-500 - Four 236kN (53,000lb) Rolls-Royce Trent 553 turbofans\\nA340-600 - Four 249kN (56,000lb) Rolls-Royce Trent 556 turbofans.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "742", "Range_nm": "8500", "Record_Status": "active", "Role": "Long range widebody airliners", "Seating_Config": "A340-500 - Flightcrew of two. Typical three class seating for 316 passengers. A340-600 Typical three class seating for 372.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/airbus-a340-500600/28", "Status": "In Service", "Typical_Capacity": "A340-500 - Flightcrew of two. Typical three class seating for 316 passengers. A340-600 Typical three class seating for 372.", "Units_Built": "69 A340-500s/600s ordered by early 2003, of which 11 delivered. These include 17 A340-500 (1 delivered) and 52 A340-600 (10 delivered).", "WTC": "H", "Weights": "A340-500 - Operating empty 170,400kg (375,665lb), max takeoff 365,000kg (804,675lb).\\nA340-600 - Operating empty 177,000kg (390,220lb), max takeoff 365,000kg (804,675lb).", "Wingspan_m": "63.70"}'),
(50565, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "4J", "Common_Name": "A340-600", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "4", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Airbus A340-600", "Generation": "", "Height_m": "", "IATA_Code": "346", "ICAO_Code": "A346", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Airbus", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "A340-600", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "H", "Weights": "", "Wingspan_m": ""}'),
(50566, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "Superjet 100-75", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The Superjet 100 design was launched in 2000, with the aim being to produce a modern regional airliner for the traditional Eastern European/CIS markets. It is also intended to be attractive to Western customers due to lower purchase and operating costs than competing Western designs, but with the required safety and performance features that were often perceived as lacking in older  designs from the Soviet era, preventing sales to that market.\\n\\nSukhoi worked with new partners, notably including Boeing, as they developed the aircraft for the post-Cold War airline environment. The aircraft that emerged is modern and targeted to compete with close competitors such as the Embraer ERJ-190/195 and Bombardier designs, as well as the smaller Airbus and Boeing designs such as the A318 and 737-600.\\n\\nDevelopment was more protracted than expected, but successful, with the first of four prototypes flying on 19 May 2008. Certification was reasonably  straightforward, with a few problems requiring attention, particularly with the new engines. \\n\\nCustomer deliveries began in 2011 when Armenian airline Armavia took delivery of the first production aircraft, with Aeroflot taking its first aircraft later the same year.", "Dimensions": "SSJ 100-95 - Wing span 27.80m (91ft 2in), length 29.94m (98ft 3in). Wing area 84m2 (900sq ft).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Sukhoi Superjet 100-75", "Generation": "", "Height_m": "", "IATA_Code": "SU7", "ICAO_Code": "ZZZZ", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Sukhoi", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "Superjet 100-75", "Name": "Sukhoi Superjet 100", "Origin": "Russia", "Performance": "SSJ 100-95 - Max cruising speed 870km/h (470kt), typical cruising speed 828km/h (448kt). Range with typical payload 3048km.", "Powerplant_Desc": "SSJ 100-95 - Two 69kN/15,400lb (NTO) PowerJet SaM146 turbofans (78kN/17,500lb APR).", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "Regional jet airliner", "Seating_Config": "Flightcrew of two. \\nSSJ 100-95 - 86 to 103 passengers depending on configuration.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/sukhoi-superjet-100/408", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "The first production Superjet 100 was handed over to launch customer Armavia on 19 April 2011.", "WTC": "", "Weights": "SSJ 100-95  - Empty 25,100kg (55,000lb), max takeoff 45,880kg (101,100lb).", "Wingspan_m": ""}'),
(50567, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "High capacity, long range, twindeck, widebody airliner", "Bibliography": "Airliners.net", "Category": "4J", "Common_Name": "A380F", "Country_Origin": "Europe (France, Germany, Spain, UK)", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The 555 seat, double deck Airbus A380 is the world''s largest airliner, easily eclipsing Boeing''s 747. The A380 base model is the 555 seat A380-800 (launch customer Emirates). Potential future models include the 590 ton MTOW 10,410km (5620nm) A380-800F freighter, able to carry a 150 tonne payload, and the stretched, 656 seat, A380-900.\\n\\nAirbus first began studies on a very large 500 seat airliner in the early 1990s. The European manufacturer saw developing a competitor and successor to the Boeing 747 as a strategic play to end Boeing''s dominance of the very large airliner market and round out Airbus'' product line-up. \\n\\nAirbus began engineering development work on such an aircraft, then designated the A3XX, in June 1994. Airbus studied numerous design configurations for the A3XX and gave serious consideration to a single deck aircraft which would have seated 12 abreast and twin vertical tails. However Airbus settled upon a twin deck configuration, largely because of the significantly lighter structure required. \\n\\nKey design aims include the ability to use existing airport infrastructure with little modifications to the airports, and direct operating costs per seat 15-20% less than those for the 747-400. With 49% more floor space and only 35% more seating than the previous largest aircraft, Airbus is ensuring wider seats and aisles for more passenger comfort. Using the most advanced technologies, the A380 is also designed to have 10-15% more range, lower fuel burn and emissions, and produce less noise. \\n\\nThe A380 features an advanced version of the Airbus common two crew cockpit, with pull-out keyboards for the pilots, extensive use of composite materials such as GLARE (an aluminium/glass fibre composite), and four 302 to 374kN (68,000 to 84,000lb) class Rolls-Royce Trent 900 or Engine Alliance (General Electric/Pratt & Whitney) GP7200 turbofans now under development. \\nOn July 24, 2000, Emirates became the first customer making a firm order commitment, followed by Air France, International Lease Finance Corporation (ILFC), Singapore Airlines, Qantas and Virgin Atlantic. Together these companies completed the 50 orders needed to launch the programme. \\n\\nOn receipt of the required 50th launch order commitment, the Airbus A3XX was renamed A380 and officially launched on December 19, 2000. The out of sequence A380 designation was chosen as the \\"8\\" represents the cross-section of the twin decks. In early 2001 the general configuration design was frozen, and metal cutting for the first A380 component occurred on January 23, 2002, at Nantes in France. In 2002 more than 6000 people were working on A380 development. \\n\\nApart from the prime contractors in France, Germany, the United Kingdom and Spain, components for the A380 airframe are also manufactured by industrial partners in Australia, Austria, Belgium, Canada, Finland, Italy, Japan, South Korea, Malaysia, Netherlands, Sweden, Switzerland and the United States. A380 final assembly is taking place in Toulouse, France, with interior fitment in Hamburg, Germany. Major A380 assemblies are transported to Toulouse by ship, barge and road. \\n\\nOn January 18, 2005, the first Airbus A380 was officially revealed in a lavish ceremony, attended by 5000 invited guests including the French, German, British and Spanish president and prime ministers, representing the countries that invested heavily in the 10-year, â�¬10 billion+ ($13 billion+) aircraft program, and the CEOs of the 14 A380 customers, who had placed firm orders for 149 aircraft by then. \\n\\nLater, the following companies also ordered the A380: FedEx (the launch customer for the A380-800F freighter), Qatar Airways, Lufthansa, Korean Air, Malaysia Airlines, Etihad Airways, Thai Airways and UPS. \\n\\nHowever, in 2007, amid production delays, Airbus announced that it was halting design work on the A380 freighter to concentrate on the passenger version of the aircraft.  FedEx and UPS canceled their orders for the aircraft.\\n\\nFive prototypes were used in the flight test programme, which was heavily delayed due to problems with configuration management and wiring issues. The first flight occurred in August 2006, and entry into commercial service, with Singapore Airlines, took place in October 2007.", "Dimensions": "A380-800 - Wing span 79.8m (261ft 10in), length 72,75m (238ft 8in). Height 24,08 m (79ft)", "Engine_Count": "4", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Airbus A380F", "Generation": "", "Height_m": "", "IATA_Code": "38F", "ICAO_Code": "A388", "Length_m": "", "MTOW_kg": "277000", "Manufacturer": "Airbus", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "A380F", "Name": "Airbus A380", "Origin": "Europe (France, Germany, Spain, UK)", "Performance": "A380-800 - Max cruising speed M 0.88. Long range cruising speed M 0.85. Range 14,800km (8,000nm). Service ceiling 43.000ft (13,100m).\\nA380-800F - Range 10,370km (5,600nm).", "Powerplant_Desc": "A380-800 - Four 311kN (70,000lb), initially derated to 302kN (68,000lb), later growing to 374kN (84,000lb) thrust Rolls-Royce Trent 900 or  363kN (81,500lb) thrust Engine Alliance (General Electric-Pratt & Whitney) GP-7200 turbofans.", "Powerplants": "A380-800 - Four 311kN (70,000lb), initially derated to 302kN (68,000lb), later growing to 374kN (84,000lb) thrust Rolls-Royce Trent 900 or  363kN (81,500lb) thrust Engine Alliance (General Electric-Pratt & Whitney) GP-7200 turbofans.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "800", "Range_nm": "8", "Record_Status": "active", "Role": "High capacity, long range, twindeck, widebody airliner", "Seating_Config": "A380-800 - Flightcrew of two. Standard seating for 555 passengers on two decks in a three class arrangement. Qantas plans to fit its aircraft with 523 seats (in three classes). A380 has 49% more floor area but only 35% more seats (in 555 seat configuration) than the 747-400, allowing room for passenger amenities such as bars, gymnasiums and duty free shops. Cargo capacity 38 LD3s or 13 pallets.", "Service_Ceiling_ft": "000", "Source_URL": "https://www.airliners.net/aircraft-data/airbus-a380/29", "Status": "In Service", "Typical_Capacity": "A380-800 - Flightcrew of two. Standard seating for 555 passengers on two decks in a three class arrangement. Qantas plans to fit its aircraft with 523 seats (in three classes). A380 has 49% more floor area but only 35% more seats (in 555 seat configuration) than the 747-400, allowing room for passenger amenities such as bars, gymnasiums and duty free shops. Cargo capacity 38 LD3s or 13 pallets.", "Units_Built": "236 firm orders by August 2011. Airbus has forecast a market for approx 1235 airliners of 400 seats and above through to 2020. First delivery took place in autumn 2007.", "WTC": "", "Weights": "A380-800 - Operating empty 277,000kg (610,700lb), max takeoff 560,000kg (1,234,600lb).\\nA380-800F - Operating empty 252,000kg (555,600lb), max takeoff 590,000kg (1,300,700lb).", "Wingspan_m": "79.8"}'),
(50568, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Medium to long range airliner and freighter", "Bibliography": "Airliners.net", "Category": "4J", "Common_Name": "707 Combi", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The 707''s jet speed, long range, high seating capacity and operating economics revolutionised airliner travel when it was introduced into service in 1958. The 707 also laid the foundations for Boeing''s dominance of the jet airliner market. \\n\\nRecognising the jet engine''s potential for commercial aviation, Boeing (at great financial risk) decided to develop a jet powered transport that could fulfil military tanker transport roles but be easily adapted to become an airliner.  The resulting prototype, known as the 367 Dash 80, flew for the first time on July 16 1954. Impressed, the US Air Force ordered a larger version, with a wider fuselage (12 ft, vs 11 ft for the Dash 80) into production as the KC-135 tanker/transport (more than 800 were built).  At first, Boeing wanted to sell the same size aircraft to the airlines, but the airlines insisted on an even larger airplane, which Douglas promised to build (this became the DC-8).  Boeing finally relented, designing the 707 as a longer aircraft with a slightly wider fuselage (12 ft 4 in).\\n\\nThe first production 707 (a 707-120 for Pan Am) flew on December 20 1957, and entered service later the following year. Developments of the 707-120 include the similar 707-220, the shorter 138 for Qantas, and the stretched 707-320, which flew in July 1959. The 707-120 and 320 were later reengined with JT3D turbofans (in place of the original JT3 and JT4 turbojets) to become the 707-120B, and the 707-320B respectively. The 707-320C was a convertible model, the 707-420 was powered by RollsRoyce Conways, while the proposed CFM-56 powered 707-700 upgrade was flight tested in the late 1970s but never entered production. \\n\\nMost civil 707s in service today have been converted to freighters, while a number are used as corporate transports. \\n\\nMany air forces have bought 707s, new or converted second-hand aircraft, for general transport, aerial refuelling, and electronic warfare. The E-3 Sentry is a dedicated airborne warning and control system (AWACS) platform with a large rotodome above the fuselage. The E-6 Mercury performs the TACAMO (Take Charge and Move Out) role with the US Navy, maintaining communication with the ballistic missile submarines. The E-8 J-Stars (Joint Surveillance Target Attack Radar System) performs the battlefield control role. Other military 707s received the designations C-137, or C-18, but many others have no special military designation.", "Dimensions": "707-120B - Wing span 39.90m (130ft 10in), length 44.07m (144ft 6in), height 12.94m (42ft 5in). Wing area 226.3m2 (2433sq ft). \\n707-320B - Wing span 44.42m (145ft 9in), length 46.61m (152ft 11in), height 12.93m (42ft 5in). Wing area 283m2 (3050sq ft).", "Engine_Count": "4", "Engine_Type": "Turbojet", "First_Flight_Year": "", "Full_Designation": "Boeing 707 Combi", "Generation": "", "Height_m": "", "IATA_Code": "70M", "ICAO_Code": "B703", "Length_m": "44.07", "MTOW_kg": "55589", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "1010", "Mission_Type": "Passenger", "Model": "707 Combi", "Name": "Boeing 707", "Origin": "United States of America", "Performance": "707-120B - Max speed 1010km/h (545kt), max cruising speed 1000km/h (540kt), economical cruising speed 897km/h (484kt). Range with max payload 6820km (3680nm), range with max fuel 8485km (4580nm). \\n707-320B - Max speed 1009km/h (545kt), max cruising speed 974km/h (525kt), long range cruising speed 885km/h (478kt). Range with max passengers 6920km (3735nm), range with max fuel and 147 passengers 9265km (5000nm).", "Powerplant_Desc": "707-120B - Four 75.6kN (17,000lb) Pratt & Whitney JT3D-1 turbofans. \\n707-320B - Four 80kN (18,000lb) JT3D-3s or four 84.4kN (19,000lb) JT3D-7s.", "Powerplants": "707-120B - Four 75.6kN (17,000lb) Pratt & Whitney JT3D-1 turbofans. \\n707-320B - Four 80kN (18,000lb) JT3D-3s or four 84.4kN (19,000lb) JT3D-7s.", "Production_Count": "", "Production_Status": "active", "Range_km": "6820", "Range_nm": "3680", "Record_Status": "active", "Role": "Medium to long range airliner and freighter", "Seating_Config": "Flightcrew of three or four. \\n707-120 max seating for 179, or 110 in two classes (44 first and 66 economy).\\n707-320B - Max seating for 219, or 189 single class at 81cm (32in) pitch, or 147 in two classes. \\nConvertible or freighter versions - 13 A type containers.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/boeing-707/87", "Status": "In Service", "Typical_Capacity": "Flightcrew of three or four. \\n707-120 max seating for 179, or 110 in two classes (44 first and 66 economy).\\n707-320B - Max seating for 219, or 189 single class at 81cm (32in) pitch, or 147 in two classes. \\nConvertible or freighter versions - 13 A type containers.", "Units_Built": "Production of commercial 707s ended in 1978 after 878 had been built. Limited production of military variants continued until 1990. Approximately 130 remain in commercial service.", "WTC": "", "Weights": "707-120B - Operating empty 55,589kg (122,533lb), max takeoff 116,575kg (257,000lb). \\n707-320B - Empty 66,406kg (146,400lb), max takeoff 151,315kg (333,600lb).", "Wingspan_m": "39.90"}'),
(50569, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Short to medium range airliner", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "717", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The 100 seat 717 is the latest development of the popular DC-9/MD-80/MD-90 family and the only Douglas airliner which Boeing (which merged with McDonnell Douglas in 1997) plans to retain in its product line-up. It is designed for high cycle, short range regional airline operations. \\n\\nMcDonnell Douglas first announced the MD-95 at the Paris Airshow in June 1991. At the time MDC anticipated a formal program launch by late 1991 and a first flight in July 1994. As it happened program launch was not until October 1995 when US airline ValuJet (now AirTran Airlines) ordered 50 and optioned 50. \\n\\nIn January 1998 Boeing (following the August 1997 Boeing/McDonnell Douglas merger) relaunched the aircraft as the 717-200 (the second use of the Boeing designation \\"717\\", as this was previously allocated to the military C-135/KC-135 family). First flight took place on September 2 1998, followed by a second development 717 on October 26. Certification was awarded on September 1 1999 while the first delivery, to AirTran, was on September 23 that year. \\n\\nInitially MDC studied powering the MD-95 with Pratt & Whitney JT8D-218s or Rolls-Royce Tays. In February 1994 however MDC announced it had chosen the new BMW Rolls-Royce (now just Rolls-Royce) BR715 over the JT8D-200 and an engine from the proposed \\"Project Blue\\" teaming of General Electric, Snecma, MTU and P&W. \\n\\nOther 717-200 features include a fuselage 1.45m (4ft 9in) longer than the DC-9-30''s, a wing based on the DC-9-34''s, an advanced six LCD screen Honeywell EFIS flightdeck, and a cabin interior similar to that developed for the MD-90. It is offered in standard 717-200BGW (Basic Gross Weight) and extended range 717-200HGW (High Gross Weight) forms. In addition, 80 seat shortened 717-100 (formerly MD-95-20) and 120 seat stretched 717-300 (formerly MD-95-50) models have been studied, as has a business jet variant. \\n\\nCompanies participating in 717 production include Alenia (fuselage), Korean Air (nose), AIDC of Taiwan (empennage), ShinMaywa of Japan (engine pylons and horizontal stabilizers), Israel Aircraft Industries (undercarriage), and Fischer of Austria (interior). Final assembly is at Boeing''s Long Beach plant, in the same building that the DC-9 and MD-80 were built in. \\n\\nInitial orders and operators are:\\nAeBal, Airtran, Bangkok Air, Bavaria International Leasing, Hawaiian Airlines, Impulse Airlines, Midwest Express Airlines, Olympic Aviation, Pembroke Leasing, Qantas Link, Siam Reap Air, Trans World Airlines, and Turkmenistan Airlines.", "Dimensions": "Wing span 28.44m (93ft 3in), length 37.80m (124ft 0in), height 8.87m (29ft 1in). Wing area 93.0m2 (1000.7sq ft).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Boeing 717", "Generation": "", "Height_m": "", "IATA_Code": "717", "ICAO_Code": "B712", "Length_m": "37.80", "MTOW_kg": "31674", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "811", "Mission_Type": "Passenger", "Model": "717", "Name": "Boeing 717", "Origin": "United States of America", "Performance": "717-200BGW - Cruising speed 811km/h (438kt). Range with 106 passengers 2545km (1375nm). \\n717-200HGW - Cruising speed same. Range with 106 passengers 3815km (2060nm).", "Powerplant_Desc": "717-200BGW - Two 82.3kN (18,500lb) Rolls-Royce BR715-A1-30 turbofans.\\n717-200HGW - Same or optionally 89.6kN (20,000lb) or 93.4kN (21,000lb) BR715s.", "Powerplants": "717-200BGW - Two 82.3kN (18,500lb) Rolls-Royce BR715-A1-30 turbofans.\\n717-200HGW - Same or optionally 89.6kN (20,000lb) or 93.4kN (21,000lb) BR715s.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "2545", "Range_nm": "1375", "Record_Status": "active", "Role": "Short to medium range airliner", "Seating_Config": "Flightcrew of two. Typical two class seating for 106 passengers at five abreast in main cabin. Single class seating for 117.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/boeing-717/111", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Typical two class seating for 106 passengers at five abreast in main cabin. Single class seating for 117.", "Units_Built": "As of early 2003, 153 717s had been ordered, of which 111 had been delivered.", "WTC": "M", "Weights": "717-200BGW - Operating empty 31,674kg (69,830lb), max takeoff 49,940kg (110,100lb) or 51,710kg (114,000lb).\\n717-200HGW - Operating empty 32,110kg (70,790lb), max takeoff 54,885kg (121,000lb).", "Wingspan_m": "28.44"}'),
(50570, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "Airliners.net", "Category": "3J", "Common_Name": "727-100 Freighter", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The 727 short to medium range trijet is the world''s second most successful jet airliner built. \\n\\nInitial design studies began in 1956, although for a time it appeared that a new short/medium range airliner would not be built at all due to Boeing''s financial position before sales of the 707 had taken off. Boeing persisted however and serious development of the 727 beginning in June 1959. The program was launched on the strength of orders for 80 from Eastern and United in 1960. \\n\\nThe resulting Boeing Model 727 pioneered the rear trijet configuration, with power from three specially designed Pratt & Whitney JT8D turbofans (although RollsRoyce Speys were originally considered). The trijet design was settled upon as it gave the redundancy of three engines, better climb performance than a twin and improved operating economics over a four engine jet. The 727 also introduced an advanced wing design with the first airliner application of triple slotted Krueger flaps. The 727 retained the 707''s fuselage cross section, but with a redesigned smaller lower fuselage due to the need to carry less baggage on shorter range flights, and it has limited parts commonality with the 707 and 720. The 727 was also the first Boeing airliner to feature an APU (auxiliary power unit). \\n\\nThe prototype 727 first flew on February 9 1963, with certification granted in December that year. The first 727 entered service with Eastern Airlines on February 9 the following year. \\n\\nDevelopment of the initial 727-100 resulted in a small family of sub variants, including higher gross weight options for the basic passenger carrying 727, the 727-100C Convertible and 727-200QC Quick Change, both with a large freight door on the forward left hand side of the fuselage. Many were subsequently converted to pure freighters. The stretched 727-200 is described separately. \\n\\nProduction of the 727-100 ceased in 1973 but one recent notable development was Dee Howard in the USA upgrading a number of 727-100 freighters for express freight operator UPS. The major feature of the upgrade was reengining with RollsRoyce Tays, which improves performance, reduces fuel consumption and more importantly, allows the aircraft to meet Stage 3 noise requirements.", "Dimensions": "727-100 - Wing span 32.92m (108ft 0in), length 40.59m (133ft 2in), height 10.36m (34ft 0in). Wing area 157.9m2 (1700sq ft).", "Engine_Count": "3", "Engine_Type": "Turbojet", "First_Flight_Year": "", "Full_Designation": "Boeing 727-100 Freighter", "Generation": "", "Height_m": "", "IATA_Code": "72X", "ICAO_Code": "B721", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "727-100 Freighter", "Name": "Boeing 727-100", "Origin": "United States of America", "Performance": "Max speed 1017km/h (549kt), max cruising speed 960km/h (518kt), economical cruising speed 917km/h (495kt). Range with max payload 5000km (2700nm).", "Powerplant_Desc": "727-100 - Three 62.3kN (14,000lb) Pratt & Whitney JT8D-7 turbofans.", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "Short to medium range narrowbody airliner", "Seating_Config": "Flightcrew of three (two pilots and flight engineer). Typical two class seating for 94, max seating for 131.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/boeing-727-100/89", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "Of the 582 727-100s built, almost 400 remained in commercial service in late 1998, with 40 more used as corporate jets.", "WTC": "", "Weights": "727-100 - Empty equipped 36,560kg (80,602lb), max takeoff 72,570kg (160,000lb).", "Wingspan_m": ""}'),
(50571, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Short to medium range narrowbody airliner", "Bibliography": "Airliners.net", "Category": "3J", "Common_Name": "727-200 Freighter", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The 727-100 had been in service barely a year when Boeing began serious consideration of a stretched, greater capacity development. \\n\\nThis resulted in the 727-200, which Boeing announced it was developing in August 1965. The 727-200 was essentially a minimum change development of the 100, the only major change being the 6.10m (20ft) fuselage stretch, which increased maximum seating to 189 passengers. The 727-200''s stretch consisted of two 3.05m (10ft) plugs, one forward and one rear of the wing. Otherwise the 727-100 and 200 shared common engines, fuel tank capacity and the same maximum takeoff weight. \\n\\nThe first flight of the 727-200 occurred on July 27 1967, with certification granted in late November that year. The -200 was placed into service by launch customer Northeast Airlines (this airline was later acquired by Delta) the following month, by which time total 727 orders for both models had exceeded 500. \\n\\nThe 727-200 helped broaden the sales appeal of the 727 considerably and snared significant sales. However the 200 was restricted by its relatively short range, due to it having the same fuel capacity as the 727-100, so Boeing developed the increased range Advanced 727-200. First flown in March 1972 changes introduced on the Advanced model included increased fuel capacity, and thus range, the option of more powerful engines, quieter engine nacelles and strengthened structure. The Advanced remained the primary 727-200 production model until production ceased in 1984. \\n\\nThe 727-200 remains popular with passengers and pilots but it does not meet Stage 3 noise requirements. To overcome this a number of hushkit programs are on offer while Valsan converted 23 727s to its Stage 3 compliant Quiet 727 standard (before the company collapsed). This retrofit included installing JT8D-217s on the outer pylons and acoustic treatment of the centre engine. Other 727s have been fitted with winglets for improved performance.", "Dimensions": "Wing span 32.92m (108ft 0in), length 46.69m (153ft 2in), height 10.36m (34ft 0in). Wing area 157.9m2 (1700sq ft).", "Engine_Count": "3", "Engine_Type": "Turbojet", "First_Flight_Year": "", "Full_Designation": "Boeing 727-200 Freighter", "Generation": "", "Height_m": "", "IATA_Code": "72Y", "ICAO_Code": "B722", "Length_m": "46.69", "MTOW_kg": "45360", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "1017", "Mission_Type": "Passenger", "Model": "727-200 Freighter", "Name": "Boeing 727-200", "Origin": "United States of America", "Performance": "Advanced 727-200 - Max speed 1017km/h (549kt), max cruising speed 953km/h (515kt), economical cruising speed 865km/h (467kt). Range with max payload 3965km (2140nm), range with max fuel 4450km (2400nm).", "Powerplant_Desc": "Three 64.5kN (14,500lb) Pratt & Whitney JT8D-9 turbofans, or 67.2kN (15,000lb) JT8D-11s, or 68.9kN (15,500lb) JT8D-15s or 71.1kN (16,000lb) JT8D-17s (Advanced only), or 77.3kN (17,400lb) JT8D-17Rs (Advanced only).", "Powerplants": "Three 64.5kN (14,500lb) Pratt & Whitney JT8D-9 turbofans, or 67.2kN (15,000lb) JT8D-11s, or 68.9kN (15,500lb) JT8D-15s or 71.1kN (16,000lb) JT8D-17s (Advanced only), or 77.3kN (17,400lb) JT8D-17Rs (Advanced only).", "Production_Count": "", "Production_Status": "active", "Range_km": "3965", "Range_nm": "2140", "Record_Status": "active", "Role": "Short to medium range narrowbody airliner", "Seating_Config": "727-200 - Max seating for 189 at six abreast and 76cm (30in) pitch, typical two class seating for 14 premium class and 131 economy class passengers.\\n727-200F - Typical max payload comprises 11 2.23m x 3.17m (7ft 4in x 10ft 5in) pallets.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/boeing-727-200/90", "Status": "In Service", "Typical_Capacity": "727-200 - Max seating for 189 at six abreast and 76cm (30in) pitch, typical two class seating for 14 premium class and 131 economy class passengers.\\n727-200F - Typical max payload comprises 11 2.23m x 3.17m (7ft 4in x 10ft 5in) pallets.", "Units_Built": "1831 727s of all models built when production ceased in 1984, including 1249 200s. Approx 940 727-200s in commercial service at late 1998, with a further 15 as corporate transports.", "WTC": "", "Weights": "Advanced 727-200 - Operating empty 45,360kg (100,000lb), max takeoff 95,030kg (209,500lb).", "Wingspan_m": "32.92"}'),
(50572, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "737-100", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The 737-100 and 200 are the first generation production models of the world''s most successful jet airliner family, Boeing''s 737 twinjet. \\n\\nThe 737 was conceived as a short range small capacity airliner to round out the Boeing jet airliner family beneath the 727, 720 and 707. Announced in February 1965, the 737 was originally envisioned as a 60 to 85 seater, although following consultation with launch customer Lufthansa, a 100 seat design was settled upon. Design features included two underwing mounted turbofans and 60% structural and systems commonality with the 727, including the same fuselage cross section (making it wider than the competing five abreast DC-9 and BAC-111). \\n\\nThe 737-100 made its first flight on April 9 1967 and entered service in February 1968 with Lufthansa, while the last of 30 built was delivered to Malaysia-Singapore Airlines in October 1969. \\n\\nBy this time however the larger capacity 1.93m (6ft 4in) stretched 737-200 was in service after it had made its first flight on August 8 1967. First delivery, to United, was that December.\\n\\nDevelopments of the -200 include the -200C convertible and quick change -200QC, while an unprepared airfield kit was also offered. The definitive Advanced 737-200 appeared in 1971, featuring minor aerodynamic refinements and other improvements. \\n\\nSales of the 737-200 far exceeded that of the shorter -100 and the 737-200 remained in production until 1988, by which time it had been superseded by the improved 737-300, after 1114 had been built. Many have been fitted with Stage 3 engine hushkits, and a number of passenger aircraft have been converted with cargo doors.\\n\\nThe USAF ordered 19 as navigation trainers, and some were later converted to standard transport aircraft as CT-43A. A few other air forces received 737-200s to serve in general transport, surveillance or VIP transport tasks.", "Dimensions": "737-100 - Wing span 28.35m (93ft 0in), length 28.67m (94ft 0in), height 11.29m (37ft 0in). Wing area 91.1m2 (980sq ft).\\n737-200 - Same except for length 30.53m (100ft 2in).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Boeing 737-100", "Generation": "", "Height_m": "", "IATA_Code": "731", "ICAO_Code": "B731", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "737-100", "Name": "Boeing 737-100/200", "Origin": "United States of America", "Performance": "737-100 - Max speed 943km/h (509kt), economical cruising speed 852km/h (460kt). Range with max fuel 2855km (1540nm).\\n737-200 - Max speed 943km/h (509kt), max cruising speed 927km/h (500kt), economical cruising speed 796km/h (430kt). Range with 115 passengers and reserves between 3520km (1900nm) and 4260km (2300nm) depending on weight options and engines.", "Powerplant_Desc": "737-100 - Two 62.3kN (14,000lb) Pratt & Whitney JT8D-7 turbofans. \\n737-200 - Two 64.5kN (14,500lb) JT8D-9As, or two 68.9kN (15,500lb) JT8D-15s, or two 71.2kN (16,000lb) JT8D-17s, or two 77.4kN (17,400lb) JT8D-17Rs with automatic reverse thrust.", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "Short range narrowbody airliner", "Seating_Config": "Flightcrew of two. \\n737-100 - Typical single class seating for 100. \\n737-200 - Typical single class seating for 115, max seating for 130 at 74cm (29in) pitch.\\n737-200C/QC payload 15,545kg (34,270lb), consisting of pallets or containers.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/boeing-737-100200/91", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "1144 737-100s and 200s built, comprising 30 100s and 1114 200s, including 19 T-43A (737-200) navigation trainers for the USAF and 104 737-200Cs. Approximately 1 737-100 and 550 737-200s remained in commercial and corporate service in early 2005.", "WTC": "", "Weights": "737-100 - Empty 25,878kg (57,000lb), max takeoff 49,940kg (110,000lb). \\n737-200 - Operating empty 27,448kg (60,600lb), max takeoff 52,390kg (115,500lb), or optionally 58,740kg (129,500lb).", "Wingspan_m": ""}'),
(50573, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "2J", "Common_Name": "737-200 Freighter", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Boeing 737-200 Freighter", "Generation": "", "Height_m": "", "IATA_Code": "73X", "ICAO_Code": "B732", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "737-200 Freighter", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "", "Weights": "", "Wingspan_m": ""}'),
(50574, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Short to medium range narrowbody airliner", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "737-300 Freighter", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The 737-300 is the first of the three member second generation CFM56 powered 737 family, which also comprises the stretched 737-400 and shortened 737-500. The success of the second generation Boeing 737 family pushed sales of the mark to over 3000, a record for a commercial jetliner. \\n\\nBoeing announced it was developing the 737-300 in March 1981. This new variant started off as a simple stretch over the 737-200 but Boeing decided to adopt the CFM International CFM56 high bypass turbofan (jointly developed by General Electric and SNECMA) to reduce fuel consumption and comply with the then proposed International Civil Aviation Organisation Stage 3 noise limits. \\n\\nDespite the all new engines and the 2.64m (104in) fuselage stretch, the 737-300 retains 80% airframe spares commonality and shares the same ground handling equipment with the 737-200. A number of aerodynamic improvements were incorporated to further improve efficiency including modified leading edge slats and a new dorsal fin extending from the tail. Another feature was the flattened, oval shaped engine nacelles, while the nosewheel leg was extended to increase ground clearance for the new engines. Other internal changes include materials and systems improvements first developed for the 757 and 767 programs, including an early generation EFIS flightdeck (with four colour CRT screens). \\n\\nThe 737-300 flew for the first time on February 24 1984, while first deliveries were from November 1984. Since that time well over 1000 737-300s have been sold and it forms the backbone of many airlines'' short haul fleets. \\n\\nThe stretched 737-400 and shortened 737-500 are described separately.", "Dimensions": "Wing span 28.88m (94ft 9in), length 33.40m (109ft 7in), height 11.13m (36ft 6in). Wing area 105.4m2 (1135sq ft).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Boeing 737-300 Freighter", "Generation": "", "Height_m": "", "IATA_Code": "73Y", "ICAO_Code": "B733", "Length_m": "33.40", "MTOW_kg": "32881", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "908", "Mission_Type": "Passenger", "Model": "737-300 Freighter", "Name": "Boeing 737-300", "Origin": "United States of America", "Performance": "Max cruising speed 908km/h (491kt), long range cruising speed 794km/h (429kt). Range with 128 passengers and standard fuel 3362km (1815nm), range with 128 pax and max fuel 4973km (2685nm). High gross weight version max range 6300km (3400nm) with 140 passengers.", "Powerplant_Desc": "Two 89.0kN (20,000lb) CFM International CFM563B1 turbofans, or optionally two 97.9kN (22,000lb) CFM563B2s.", "Powerplants": "Two 89.0kN (20,000lb) CFM International CFM563B1 turbofans, or optionally two 97.9kN (22,000lb) CFM563B2s.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "3362", "Range_nm": "1815", "Record_Status": "active", "Role": "Short to medium range narrowbody airliner", "Seating_Config": "Flightcrew of two. Typical two class seating for 128 (eight premium class four abreast and 120 economy class six abreast), standard one class seating for 141 at six abreast and 81cm (31in) pitch, max seating for 149 at 76cm (30in) pitch.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/boeing-737-300/92", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Typical two class seating for 128 (eight premium class four abreast and 120 economy class six abreast), standard one class seating for 141 at six abreast and 81cm (31in) pitch, max seating for 149 at 76cm (30in) pitch.", "Units_Built": "Grand total 737 orders stand at over 4236, of which over 1104 are for the 300. Approximately 1070 737-300s were in service at late 1998.", "WTC": "", "Weights": "Operating empty 32,881kg (72,490lb), standard max takeoff 56,740kg (124,500lb), high gross weight option 62,823kg (138,500lb).", "Wingspan_m": "28.88"}'),
(50575, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Short to medium range airliner", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "737-400 Mixed Configuration", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "Boeing announced it was developing a new higher capacity version of the fast selling 737-300 in June 1986. \\n\\nThe new aeroplane, the 737-400, was developed as a 150 seat class 727 replacement. Although Boeing had initially developed the 180 to 200 seat 757 to replace the successful 727, there still existed a considerable market for a near direct size replacement for the popular trijet. By developing the 737-400 as a minimum change stretch of the 737-300, Boeing was also able to offer considerable commonality, and thus cost, benefits to operators already with the 737-300, and to a lesser extent, the 737-200 in their fleets. \\n\\nThe major change of the 737-400 over the smaller 300 is a 3.05m (10ft 0in) fuselage stretch, consisting of a 1.83m (6ft 0in) stretch forward and a 1.22m (4ft 0in) plug rear of the wing. The stretch increases maximum passenger seating to 188. To cope with the increased weights, more powerful CFM56s are fitted. Other changes are minor, such as a tail bumper fitted to protect against over rotation at takeoff, something that could have become a problem due to the increased fuselage length. \\n\\nA higher gross weight longer range version is offered. It features increased fuel capacity, and strengthened undercarriage and structures, but is otherwise identical to the standard 737-400. \\n\\nThe first flight of the 737-400 occurred on February 19 1988 and it entered airline service in October that year with Piedmont. Of the 737-300/-400/-500 family the 400 has proven the most successful member behind the 300, its larger capacity and transcontinental US range meaning it has found a very useful market for Boeing as a 727 replacement. However the 737-400 does face stiff competition from the similar size Airbus A320, which has higher levels of technology, longer range and is faster (but is also heavier).", "Dimensions": "Wing span 28.88m (94ft 9in), length 36.45m (119ft 7in), height 11.13m (36ft 6in). Wing area 105.4m2 (1135sq ft).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Boeing 737-400 Mixed Configuration", "Generation": "", "Height_m": "", "IATA_Code": "73Q", "ICAO_Code": "B734", "Length_m": "36.45", "MTOW_kg": "34564", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "912", "Mission_Type": "Passenger", "Model": "737-400 Mixed Configuration", "Name": "Boeing 737-400", "Origin": "United States of America", "Performance": "Max cruising speed 912km/h (492kt), long range cruising speed 813km/h (439kt). Standard version range with max payload 4005km (2160nm), typical range with 146 passengers 3630km (1960nm). High gross weight option range with 146 passengers 3850km (2080nm).", "Powerplant_Desc": "Two 97.9kN (22,000lb) CFM International CFM563B2 turbofans, or optionally 104.5kN (23,500lb) CFM563C1s.", "Powerplants": "Two 97.9kN (22,000lb) CFM International CFM563B2 turbofans, or optionally 104.5kN (23,500lb) CFM563C1s.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "4005", "Range_nm": "2160", "Record_Status": "active", "Role": "Short to medium range airliner", "Seating_Config": "Flightcrew of two. Typical two class seating for 146 (eight premium, 138 economy), typical all economy for 159 at 81cm (32in) pitch, or max seating for 188.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/boeing-737-400/93", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Typical two class seating for 146 (eight premium, 138 economy), typical all economy for 159 at 81cm (32in) pitch, or max seating for 188.", "Units_Built": "Orders for the 737-400 stood at 473 at late 1998, of which approximately 470 were in airline service.", "WTC": "", "Weights": "Standard version operating empty 34,564kg (76,200lb), max takeoff 62,820kg (138,500lb). High gross weight operating empty 34,827kg (76,780lb), max takeoff 68,040kg (150,000lb).", "Wingspan_m": "28.88"}'),
(50576, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Short to medium range airliner", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "737-500 (winglets)", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The 737-500 is the shortest and smallest member of the second generation 737-300/-400/-500 family, and the last to be developed. \\n\\nWhen the new stretched 737-300 first appeared it was intended to supplement, rather than replace, the 737-200. However the evolution of the 737-300 into a family of models led to the development of a new model comparable in size to the 737-200, but offering better fuel economy and extensive commonality with the 737-300 and -400 models. This was the 737-500, known before its May 1987 formal launch as the 737-1000. \\n\\nLike the preceding 737-300 and 737-400, the 737-500 is powered by CFM International CFM56s turbofans, in this case either 82.3kN (18,500lb) CFM563B1s or 89.0kN (20,000lb) CFM56-3C-1s. All three second generation 737 models share extensive systems and structure commonality, and a common aircrew type rating. These benefits offer real cost savings to an airline with two or more variants of the family in its fleet. \\n\\nThe 737-500 is 31.01m (101ft 9in) in length, comparable to the 737-200''s 30.53m (100ft 2in) length, and as such is a viable direct replacement for the earlier type. Like the 300 and 400, a higher gross weight longer range version is offered, featuring auxiliary fuel tanks and uprated engines. \\n\\nThe 737-500''s first flight occurred on June 30 1989, FAA certification was awarded on February 12 1990, with service entry later that same month. \\n\\nThe 737-500''s main appeal is for operators of large 737-400 and 737-300 fleets, as because the 500 is a shortened development of the 300, it still carries much of the structural weight needed for the higher weight models. This makes it less efficient than if it was designed specifically for its size category, however for operators of large 737-300/400 fleets, the extensive commonality benefits more than compensate for this.", "Dimensions": "Wing span 28.88m (94ft 9in), length 31.01m (101ft 9in), height 11.13m (36ft 6in). Wing area 105.4m2 (1135sq ft).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Boeing 737-500 (winglets)", "Generation": "", "Height_m": "", "IATA_Code": "73E", "ICAO_Code": "B735", "Length_m": "31.01", "MTOW_kg": "31983", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "912", "Mission_Type": "Passenger", "Model": "737-500 (winglets)", "Name": "Boeing 737-500", "Origin": "United States of America", "Performance": "Max cruising speed 912km/h (492kt), economical cruising speed 795km/h (430kt). Standard range with max passengers 2815km (1520nm), higher gross weight option range with max passengers 4444km (2400nm).", "Powerplant_Desc": "Two 82.3kN (18,500lb) CFM International CFM563B1 turbofans, or 89.0kN (20,000lb) CFM56-3C-1s.", "Powerplants": "Two 82.3kN (18,500lb) CFM International CFM563B1 turbofans, or 89.0kN (20,000lb) CFM56-3C-1s.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "2815", "Range_nm": "1520", "Record_Status": "active", "Role": "Short to medium range airliner", "Seating_Config": "Flightcrew of two. Typical two class seating for 108 (eight first and 100 economy), or max single class seating for 132 at 76cm (30in) pitch.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/boeing-737-500/94", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Typical two class seating for 108 (eight first and 100 economy), or max single class seating for 132 at 76cm (30in) pitch.", "Units_Built": "At late 1998 737-500 sales stood at 387, of which 383 had been delivered.", "WTC": "", "Weights": "Operating empty (standard and high gross weight models) 31,983kg (70,510lb), standard max takeoff 52,390kg (115,500lb), high gross weight max takeoff 60,555kg (133,500lb).", "Wingspan_m": "28.88"}'),
(50577, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Short to medium range airliners", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "737-600", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The 737-600 and -700 are the smaller members of Boeing''s successful Next Generation 737-600/700/800/900 family. \\n\\nAmong the many changes, the Next Generation 737s feature more efficient CFM56-7B turbofans. The CFM56-7 combines the core of the CFM56-5 with the CFM56-3''s low pressure compressor and a 1.55m (61in) fan. The 737''s new wing has greater chord, span and wing area, while the tail surfaces are also larger. The 2.4m (8ft) high winglets first developed for the Boeing Business Jet development are now offered as an option on the 737-700 (and -800). \\n\\nThe new engines and wings allow the 737 to cruise at Mach 0.78 to Mach 0.80, while the larger wing allows greater fuel tankage and transcontinental USA range. Other features include a 777 style EFIS flightdeck with six flat panel LCDs which can be programmed to present information as on the 777 or as on the 737-300/400/500 series, allowing a common pilot type rating for the two 737 families. \\n\\nThe improved Next Generation Boeing 737 family (originally covered by the 737X designation) was launched in November 1993. The 737-700 was the first member of the new family to be developed, and is based on the 737-300, while the 737-600 is based on the 737-500. \\n\\nThe 737-700 rolled out on December 7 1996, was granted certification in November 1997 and entered service (with Southwest) the following month. The 737-600 was launched was launched on March 16 1996, first flew on January 22 1998 and entered service (with SAS) in September that year. \\n\\nThe Boeing Business Jet or BBJ (described separately) is based on the fuselage of the 737-700 with the larger 737-800''s wing. \\n\\nThe BBJ''s airframe also forms the basis for the convertible passenger/freighter variant of the 700, the 737-700QC, which has been ordered by the US Navy as the C-40A Clipper (to replace the DC-9 based C-9B). The C-40 first flew on April 17 2000. The naval aircraft can be converted to carry 121 passengers, or 3 pallets of cargo plus 70 passengers, or 8 pallets of cargo only. These aircraft are currently (2002) based at Naval Air Station Fort Worth, Texas (VR-59) and Naval Air Station Jacksonville, Florida (VR-58). \\n\\nThe US Air Force has bought two ex-Fordair BBJs, which are designated C-40B.", "Dimensions": "737-600 - Wing span 34.31m (112ft 7in), length 31.24m (102ft 6in), height 12.57m (41ft 3in). Wing area 125.0m2 (1344sq ft). \\n737-700 - Same except length 33.63m (110ft 4in), height 12.55m 41ft 2in).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Boeing 737-600", "Generation": "", "Height_m": "", "IATA_Code": "736", "ICAO_Code": "B736", "Length_m": "31.24", "MTOW_kg": "37104", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "737-600", "Name": "Boeing 737-600/700", "Origin": "United States of America", "Performance": "Typical cruising speed Mach 0.785. Max certificated altitude 41,000ft. \\n737-600 - Range with 110 pax 2480km (1340nm) or 5648km (3050nm) for HGW version. \\n737-700 - Range with 126 pax 2852km (1540nm) or 6037km (3260nm) for HGW version.", "Powerplant_Desc": "737-600 - Two 86.7kN (19,500lb) CFM56-7B18 turbofans, or 101kN (22,700lb) CFM56-7B22s on high gross weight version. \\n737-700 - Two 91.6kN (20,600lb) CFM56-7B20s or 101kN (22,700lb) CFM56-7B24s on HGW version.", "Powerplants": "737-600 - Two 86.7kN (19,500lb) CFM56-7B18 turbofans, or 101kN (22,700lb) CFM56-7B22s on high gross weight version. \\n737-700 - Two 91.6kN (20,600lb) CFM56-7B20s or 101kN (22,700lb) CFM56-7B24s on HGW version.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "2480", "Range_nm": "1340", "Record_Status": "active", "Role": "Short to medium range airliners", "Seating_Config": "Flightcrew of two. \\n737-600 - 110 passengers in two classes or 132 in a single class. \\n737-700 - 126 in two classes or 149 in a single class.", "Service_Ceiling_ft": "000", "Source_URL": "https://www.airliners.net/aircraft-data/boeing-737-600700/95", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. \\n737-600 - 110 passengers in two classes or 132 in a single class. \\n737-700 - 126 in two classes or 149 in a single class.", "Units_Built": "737-600 - 81 ordered and 47 delivered by October 2002.\\n737-700 - 883 ordered and 465 delivered by October 2002.", "WTC": "M", "Weights": "737-600 - Operating empty 37,104kg (81,800lb), max takeoff 56,245kg (124,000lb), HGW max takeoff 65,090kg (143,500lb). \\n737-700 - Operating empty 38,147kg (84,100lb), max takeoff 60,330kg (133,000lb), HGW MTOW 70,080kg (154,500lb).", "Wingspan_m": "34.31"}'),
