(50581, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "4J", "Common_Name": "747-100 Freighter", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "4", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Boeing 747-100 Freighter", "Generation": "", "Height_m": "", "IATA_Code": "74T", "ICAO_Code": "B741", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "747-100 Freighter", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "", "Weights": "", "Wingspan_m": ""}'),
(50582, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "4J", "Common_Name": "747-200 Freighter", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "4", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Boeing 747-200 Freighter", "Generation": "", "Height_m": "", "IATA_Code": "74X", "ICAO_Code": "B742", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "747-200 Freighter", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "", "Weights": "", "Wingspan_m": ""}'),
(50583, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Long range high capacity widebody airliner", "Bibliography": "Airliners.net", "Category": "4J", "Common_Name": "747-300 / 747-200 SUD Freighter", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "Boeing''s 747-300 model introduced the distinctive stretched upper deck which can seat up to 69 economy class passengers. \\n\\nThe 747-300 was the end result of a number of Boeing studies which looked at increasing the aircraft''s seating capacity. Ideas studied included fuselage plugs fore and aft of the wing increasing seating to around 600, or running the upper deck down the entire length of the fuselage. In the end Boeing launched the more modest 747SUD (Stretched Upper Deck) with greater upper deck seating on June 12 1980. \\n\\nThe 747SUD designation was soon changed to 747EUD (for Extended Upper Deck), and then 747-300. The new model first flew on October 5 1982 and was first delivered to Swissair on March 28 1983. Other customers included UTA, Saudia, SIA, Qantas and Cathay. \\n\\nCompared to the -200, the -300''s upper deck is stretched aft by 7.11m (23ft 4in), increasing economy class seating from 32 to a maximum of 69. The lengthened upper deck introduced two new emergency exit doors and allows an optional flightcrew rest area immediately aft of the flightdeck to be fitted. Access is via a conventional rather than spiral staircase as on the earlier models. \\n\\nOtherwise the 747-300 is essentially little changed from the 747-200 and features the same takeoff weight and engine options. 747-300 variants include the 747-300M Combi and the short range 747-300SR built for Japan Air Lines for domestic Japanese services. \\n\\nThe extended upper deck was also offered as a retrofit to existing 747-100/-200s, although the only airlines to take up this option were KLM and UTA. KLM has since converted two to freighters, resulting in the first 747 freighters with the stretched upper deck. Also, two JAL 747-100s were delivered new with the extended upper deck.", "Dimensions": "Wing span 59.64m (195ft 8in), length 70.66m (231ft 10in), height 19.33m (63ft 5in). Wing area 511m2 (5500sq ft).", "Engine_Count": "4", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Boeing 747-300 / 747-200 SUD Freighter", "Generation": "", "Height_m": "", "IATA_Code": "74U", "ICAO_Code": "B743", "Length_m": "70.66", "MTOW_kg": "174134", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "996", "Mission_Type": "Passenger", "Model": "747-300 / 747-200 SUD Freighter", "Name": "Boeing 747-300", "Origin": "United States of America", "Performance": "Max speed (with CF6-80s) 996km/h (538kt), max cruising speed 939km/h (507kt), economical cruising speed 907km/h (490kt), long range cruising speed 898km/h (485kt). Range with 400 passengers and reserves with JT9Ds 11,675km (6300nm), with CF650s 11,297km (6100nm), with CF6-80s 12,408km (6700nm), with RB211s 11,575km (6250nm).", "Powerplant_Desc": "Four 243.5kN (54,750lb) Pratt & Whitney JT9D7R4G2 turbofans, or 236.3kN (53,110lb) RollsRoyce RB211524D4s, or 233.5kN (52,500lb) General Electric CF650E2s, or 252.2kN (56,700lb) CF6-80C2B1s.", "Powerplants": "Four 243.5kN (54,750lb) Pratt & Whitney JT9D7R4G2 turbofans, or 236.3kN (53,110lb) RollsRoyce RB211524D4s, or 233.5kN (52,500lb) General Electric CF650E2s, or 252.2kN (56,700lb) CF6-80C2B1s.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "675", "Range_nm": "6300", "Record_Status": "active", "Role": "Long range high capacity widebody airliner", "Seating_Config": "747-300 - Flightcrew of three, with two pilots and one flight engineer. Typical two class seating arrangement for 470 (50 business class including 28 on the upper deck and 370 economy class).", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/boeing-747-300/99", "Status": "In Service", "Typical_Capacity": "747-300 - Flightcrew of three, with two pilots and one flight engineer. Typical two class seating arrangement for 470 (50 business class including 28 on the upper deck and 370 economy class).", "Units_Built": "81 delivered 1983-90 with 78 in service in late 1998.", "WTC": "", "Weights": "Operating empty 174,134kg (383,900lb) with JT9Ds, 175,721kg (387,400lb) with CF6-50s, 176,901kg (390,000lb) with CF6-80s or 178,171kg (392,800lb) with RB211s. Max takeoff 351,535kg (775,000lb), or 356,070kg (785,000lb), or 362,875kg (800,000lb), or 371,945kg (820,000lb), or 377,840kg (833,000lb).", "Wingspan_m": "59.64"}'),
(50584, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Long range high capacity widebody airliner", "Bibliography": "Airliners.net", "Category": "4J", "Common_Name": "747-400 Freighter", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The 747-400 is the latest, longest ranging and best selling model of the 747 family. \\n\\nBoeing launched the 747-400 in October 1985 and the first development aircraft first flew on April 29 1988. US certification (with PW-4000s) was awarded in January 1989. \\n\\nThe 747-400 externally resembles the -300, but it is a significantly improved aircraft. Changes include a new, two crew digital flightdeck with six large CRT displays, an increased span wing with winglets (the -400 was the first airliner to introduce winglets), new engines, recontoured wing/fuselage fairing, a new interior, lower basic but increased max takeoff weights, and greater range. \\n\\nApart from the basic passenger 747-400 model, a number of variants have been offered including the winglet-less 747-400 Domestic optimised for Japanese short haul domestic sectors, the 747-400M Combi passenger/freight model, and the 747-400F Freighter (which combines the 747-200F''s fuselage with the -400''s wing).\\n\\nThe latest model is the 747-400ER, which was launched on November 28, 2000 when Qantas placed an order for 6. The -400ER has the same size as the -400, but has more range or payload capability. The MTOW was increased by 15,870kg (35,000lb) to 412,770kg (910,000lb), giving a further range of 805km (435nm) or a 6800kg (15,000lb) greater payload. The -400ER also features a wholly new cabin interior with larger luggage bins, and several flight deck improvements.\\n\\nThe -400ER incorporates the strengthened wing, body, and landing gear of the -400F, plus an auxiliary fuel tank in the forward cargo hold, and an optional second one. Operators who don''t need these can remove them both, gaining additional cargo volume.\\n\\nThe first 747-400ER was rolled out in June 2002, and flew for the first time on July 31, 2002, and this was the 1308th 747 to fly. \\n\\nA cargo version, the 747-400ERF, followed the standard -400ER, and was launched April 30, 2001 on an order by leasing company ILFC for 5. The first -400ERF is the 1315th 747 built. The -ERF has the same MTOW as the -ER, and this will give an extra range of 970km (525nm), or an extra payload of 9980kg (22,000lb) at MTOW compared with the standard -400F.     \\n\\nShortly before delivery of the first -400ER, Boeing had received orders for 15 ER/ERFs from 5 customers.\\n\\nVarious growth 747 models have been studied. The 747-500X and -600X models were dropped in January 1997.  Boeing is currently proposing the 747-400XQLR (Quiet Longer Range) to 747-size customers which will offer more range, more quiet, and more features.", "Dimensions": "Wing span 64.44m (211ft 5in), length 70.67m (231ft 10in), height 19.41m (63ft 8in). Wing area 541.2m2 (5825sq ft).", "Engine_Count": "4", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Boeing 747-400 Freighter", "Generation": "", "Height_m": "", "IATA_Code": "74Y", "ICAO_Code": "B744", "Length_m": "70.67", "MTOW_kg": "180985", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "939", "Mission_Type": "Passenger", "Model": "747-400 Freighter", "Name": "Boeing 747-400", "Origin": "United States of America", "Performance": "747-400 - Max cruising speed 939km/h (507kt), long range cruising speed 907km/h (490kt). Design range with 420 three class pax at 396,895kg (875,000lb) MTOW 13,491km (7284nm) with PW-4000s, 13,444km (7259nm) with GEs, 13,214km (7135nm) with RB-211s.\\n747-400ER - Range at MTOW 14,205km (7670nm).\\n747-400ERF - Range at MTOW 9200km (4970nm).", "Powerplant_Desc": "Four 252.4kN (56,750lb) Pratt & Whitney PW-4056 turbofans or 266.9kN (60,000lb) PW-4060s, or 275.8kN (62,000lb) PW-4062s, 252.4kN (56,750lb) General Electric CF6-80-C2B1Fs or 273.6kN (61,500lb) CF6-80-C2B1F1s or -80-C2B7Fs, or 258.0kN (58,000lb) RollsRoyce RB-211-524G or -524Hs, or 262.4 to 266.9kN (59 to 60,000lb) RB-211-524G/H-Ts.", "Powerplants": "Four 252.4kN (56,750lb) Pratt & Whitney PW-4056 turbofans or 266.9kN (60,000lb) PW-4060s, or 275.8kN (62,000lb) PW-4062s, 252.4kN (56,750lb) General Electric CF6-80-C2B1Fs or 273.6kN (61,500lb) CF6-80-C2B1F1s or -80-C2B7Fs, or 258.0kN (58,000lb) RollsRoyce RB-211-524G or -524Hs, or 262.4 to 266.9kN (59 to 60,000lb) RB-211-524G/H-Ts.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "491", "Range_nm": "7284", "Record_Status": "active", "Role": "Long range high capacity widebody airliner", "Seating_Config": "747-400 - Flightcrew of two. Typical three class seating for 416 (23 first, 78 business and 315 economy class pax). Cargo hold 170.5m3 (6025cuft) or 151m3 (5332cuft). \\n747-400 Domestic - Two class seating for 568 (24 first and 544 economy).\\n747-400 Combi - Typical arrangement for six or seven pallets and 266 three class passengers. \\n747-400ER - Same as -400, but cargo hold 158.6m3 (5599cuft) or 137m3 (4837cuft).\\n747-400F - 30 pallets on the main deck and 32 LD1 containers in the lower hold.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/boeing-747-400/100", "Status": "In Service", "Typical_Capacity": "747-400 - Flightcrew of two. Typical three class seating for 416 (23 first, 78 business and 315 economy class pax). Cargo hold 170.5m3 (6025cuft) or 151m3 (5332cuft). \\n747-400 Domestic - Two class seating for 568 (24 first and 544 economy).\\n747-400 Combi - Typical arrangement for six or seven pallets and 266 three class passengers. \\n747-400ER - Same as -400, but cargo hold 158.6m3 (5599cuft) or 137m3 (4837cuft).\\n747-400F - 30 pallets on the main deck and 32 LD1 containers in the lower hold.", "Units_Built": "Orders for the 747-400 as of August 2002 stood at 632 (of which 17 ER/ERF), of which 585 had been delivered. Total 747 sales stood at 1356.", "WTC": "", "Weights": "747-400 - Standard operating empty with PW-4056s 180,985kg (399,000lb), with CF6-80-C2B1Fs 180,755kg (398,500lb), with RB-211s 181,755kg (400,700lb); operating weights at optional MTOW with PW-4056s 181,485kg (400,100lb), with CF6-80-C2B1Fs 181,255kg (399,600lb), with RB-211s 182,255kg (401,800lb). Max takeoff 362,875kg (800,000lb), or optionally 377,845kg (833,000lb), or 385,555kg (850,000lb), or 396,895kg (875,000lb).\\n747-400ER/ERF - MTOW 412,770kg (910,000lb).", "Wingspan_m": "64.44"}'),
