(50587, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Long range high capacity widebody airliner", "Bibliography": "Airliners.net", "Category": "4J", "Common_Name": "747SP", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "Boeing developed the 747SP in the mid 1970s as a longer range, shortened 747, trading passenger seating for extra range. The 747SP is the only 747 model to feature a changed fuselage length compared with the 747-100.\\n\\nThe 747SP first flew on July 4 1975, certification was awarded on February 4 1976 and first delivery (to Pan American) was in March 1976. \\n\\nThe 747SP''s fuselage is shortened by 14.35m (47ft 1in) compared to other 747 models, while the vertical tail was increased in height to compensate for the reduced moment arm with the shorter fuselage. Structurally the 747SP was lightened in some areas because of the significant reduction in gross weights. Overall though the 747SP retained 90% commonality of components with the 747-100 and 200. While shortening the 747''s fuselage increased the fuel fraction and thus range, it also meant that seating capacity was reduced.  \\n\\nThe SP suffix in 747SP stands for Special Performance, and points to the ultra long range abilities of this 747 variant that preceded the later 747-400 by 15 years. The 747SP''s range is best illustrated by the spate of long range distance records it set in the mid 1970s. The most prominent of those was the delivery flight of a South African Airways SP, which over March 23/24 1976 flew nonstop with 50 passengers from Paine Field in Washington State to Cape Town, South Africa, a distance of 16,560km (8940nm). This world nonstop record for a commercial aircraft stood until 1989 when a Qantas 747-400 flew 17,945km (9688mn) nonstop from London to Sydney. \\n\\nSales of the 747SP were modest despite the increased range, as the SP had poorer operating economics per seat compared to the 747-200. However the 747SP did pioneer a number of long range nonstop services that are now commonly flown by the 747-400. \\n\\nNotable SP customers included South African Airways (who found the SP''s extended range a great asset in bypassing African nations that denied it landing rights while South Africa''s apartheid policies were in place), Qantas and PanAm, the latter pioneering nonstop trans Pacific Los Angeles/Sydney services.\\n\\nIn early 2005 less than twenty SPs remain in airline or corporate service.", "Dimensions": "Wing span 59.64m (195ft 8in), length 56.31m (184ft 9in), height 19.94m (65ft 5in). Wing area 511m2 (5500sq ft).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Boeing 747SP", "Generation": "", "Height_m": "", "IATA_Code": "74L", "ICAO_Code": "B74S", "Length_m": "56.31", "MTOW_kg": "147420", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "1000", "Mission_Type": "Passenger", "Model": "747SP", "Name": "Boeing 747SP", "Origin": "United States of America", "Performance": "Max speed 1000km/h (540kt). Range with 331 passengers and baggage 10,840km (5855nm), range with 276 passengers 12,325km (6650nm), ferry range with max fuel and 13,610kg (30,000lb) payload 15,400km (8315nm).", "Powerplant_Desc": "Four 218.4kN (48,750lb) Pratt & Whitney JT9D-7AW turbofans, or 222.8kN (50,100lb) Rolls-Royce RB211-524Bs or 229.5kN (51,600lb) RB211-524Cs, or 206.8kN (46,500lb) General Electric CF6-45A2s or CF6-50E2-Fs.", "Powerplants": "Four 218.4kN (48,750lb) Pratt & Whitney JT9D-7AW turbofans, or 222.8kN (50,100lb) Rolls-Royce RB211-524Bs or 229.5kN (51,600lb) RB211-524Cs, or 206.8kN (46,500lb) General Electric CF6-45A2s or CF6-50E2-Fs.", "Production_Count": "45", "Production_Status": "discontinued", "Range_km": "840", "Range_nm": "5855", "Record_Status": "active", "Role": "Long range high capacity widebody airliner", "Seating_Config": "Flightcrew of three comprising two pilots and one flight engineer. Max high density single class seating for 440, typical two class seating for 28 first class and 288 economy class passengers", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/boeing-747sp/98", "Status": "In Service", "Typical_Capacity": "Flightcrew of three comprising two pilots and one flight engineer. Max high density single class seating for 440, typical two class seating for 28 first class and 288 economy class passengers", "Units_Built": "Just 45 747SPs were built, of which approximately 18 remain in service by early 2005.", "WTC": "", "Weights": "Operating empty 147,420kg (325,000lb), max takeoff 317,515kg (700,000lb).", "Wingspan_m": "59.64"}'),
(50588, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "4J", "Common_Name": "747SR Freighter", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Boeing 747SR Freighter", "Generation": "", "Height_m": "", "IATA_Code": "74V", "ICAO_Code": "B74R", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "747SR Freighter", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "", "Weights": "", "Wingspan_m": ""}'),
(50589, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Medium range narrowbody airliner", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "757-200 (winglets)", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "After a slow sales start, the medium range single aisle 757 has become yet another sales success story for Boeing. \\n\\nBoeing considered a number of proposals for a successor to the 727 tri-jet during the 1970s, with many of these designs featuring the nose and T-tail of the earlier jet. It was not until later in that decade however that Boeing settled on a more conventional design featuring the same cross section as the 727 (not to mention the 737, 707 and 720) but with the fuselage considerably longer in length, an all new wing, nose and flightdeck and fuel efficient high bypass turbofan engines. \\n\\nBoeing launched development of the 757 in March 1979 following orders from British Airways and Eastern. Developed in tandem with the larger widebody 767 the two types share a number of systems and technologies, including a common early generation EFIS flightdeck. \\n\\nFirst flight was on February 19 1982 and the 757 entered service in January the following year. Subsequent versions to appear are the 757-200PF Package Freighter, a pure freighter, and the 757-200M Combi (only one has been built). The standard passenger aircraft is designated the 757-200, there being no -100. The stretched 757-300 is described separately. \\n\\nInitial sales of the 757 were fairly slow, however orders picked up significantly in the mid to late 1980s as traffic on routes previously served by smaller 727s and 737s grew to require the 757''s extra capacity. Today 757 sales comfortably exceed those of the 767, a position that was reversed until the late 1980s.", "Dimensions": "Wing span 38.05m (124ft 10in), length 47.32m (155ft 3in), height 13.56m (44ft 6in). Wing area 185.3m2 (1994sq ft).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Boeing 757-200 (winglets)", "Generation": "", "Height_m": "", "IATA_Code": "75W", "ICAO_Code": "B752", "Length_m": "47.32", "MTOW_kg": "57840", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "914", "Mission_Type": "Passenger", "Model": "757-200 (winglets)", "Name": "Boeing 757-200", "Origin": "United States of America", "Performance": "Max cruising speed 914km/h (493kt), economical cruising speed 850km/h (460kt). Range with P&W engines and 186 passengers 5053km (2728nm), with RR engines 4758km (2569nm). Range at optional max takeoff weight with P&W engines 7277km (3929nm), with RR engines 6888km (3719nm). 757-200PF - Speeds same. Range with 22,680kg payload and P&W engines 7195km (3885nm), with RR engines 6857km (3700nm).", "Powerplant_Desc": "Two 166.4kN (37,400lb) RollsRoyce RB211-535C turbofans, or 178.8kN (40,200lb) RB211-535E4s, or 193.5kN (43,500lb) RB211-535E4-Bs, or 162.8kN (36,600lb) Pratt & Whitney PW2037s, or two 178.4kN (40,100lb) PW2040s, or 189.5kN (42,600lb) PW2043s.", "Powerplants": "Two 166.4kN (37,400lb) RollsRoyce RB211-535C turbofans, or 178.8kN (40,200lb) RB211-535E4s, or 193.5kN (43,500lb) RB211-535E4-Bs, or 162.8kN (36,600lb) Pratt & Whitney PW2037s, or two 178.4kN (40,100lb) PW2040s, or 189.5kN (42,600lb) PW2043s.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "5053", "Range_nm": "2728", "Record_Status": "active", "Role": "Medium range narrowbody airliner", "Seating_Config": "Flightcrew of two. 757-200 - Typical passenger arrangements vary from 178 two class (16 first & 162 economy), or 202 (12 first & 190 economy) or 208 (12 first and 196 economy) or 214 to 239 in all economy class. 757-200PF - Maximum of 15 standard 2.24 x 2.74m (88 x 108in) freight pallets on main deck.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/boeing-757-200/101", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. 757-200 - Typical passenger arrangements vary from 178 two class (16 first & 162 economy), or 202 (12 first & 190 economy) or 208 (12 first and 196 economy) or 214 to 239 in all economy class. 757-200PF - Maximum of 15 standard 2.24 x 2.74m (88 x 108in) freight pallets on main deck.", "Units_Built": "987 757-200s had been ordered by late 2002, of which over 983 had been delivered.", "WTC": "", "Weights": "Operating empty with P&W engines 57,840kg (127,520lb), with RB211s 57,975kg (127,810lb). Basic max takeoff 99,790kg (220,000lb), medium range MTOW 108,860kg (240,000lb), extended range MTOW 115,665kg (255,000lb) or 115,895kg (255,550lb).", "Wingspan_m": "38.05"}'),
(50590, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Medium range narrowbody airliner", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "757-300 (winglets)", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The stretched, 240 seat Boeing 757-300 is the first significant development of the basic 757-200 and is aimed primarily at the European vacation charter market. \\n\\nAlthough design work on the original 757 began in the late 1970s and its entry into service was in 1983, it wasn''t until over a decade later in the mid 1990s that Boeing began to study a stretched development of its popular narrowbody twin. This new 757 stretch was covered by the 757-300X designation until its launch at the Farnborough Airshow in England in September 1996. \\n\\nThe most obvious change over the 757-200 is the 300''s 54.43m (178ft 7in) long fuselage, which is 7.11m (23ft 4in) longer than the standard aircraft (and only fractionally shorter than the 767-300). This fuselage stretch allows a 20% increase in seating to 225 to 279 passengers, depending on the interior configuration. Lower hold freight capacity is also increased by 40% over the 757-200 by virtue of the longer fuselage. \\n\\nAnother feature of the 757-300 is its new interior which is based on that developed for the Next Generation 737 models. Features include a new sculptured ceiling, larger overhead bins, indirect overhead lighting and vacuum toilets. \\n\\nThe 757-300 shares the 200''s cockpit, wing, tail and powerplant options, although the 300 will feature strengthened structure and landing gear to cope with the increased weights, new wheels, tyres and brakes and a tailskid. \\n\\nThe 757-300 first flew on August 2 1998, with certification in January 1999, and entry into service (with launch customer Condor - the charter arm of German flag carrier Lufthansa) in March 1999. The -300''s 27 month development program from final configuration to planned first delivery is the fastest for any Boeing airliner (the 777-300 took 31 months for example). Other early customers are Icelandair, Arkia, Northwest, American Trans Air, Continental, and JMC Air.", "Dimensions": "Wing span 38.05m (124ft 10in), length 54.47m (178ft 7in), height 13.56m (44ft 6in). Wing area 185.3m2 (1994sq ft).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Boeing 757-300 (winglets)", "Generation": "", "Height_m": "", "IATA_Code": "75T", "ICAO_Code": "B753", "Length_m": "54.47", "MTOW_kg": "64590", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "757-300 (winglets)", "Name": "Boeing 757-300", "Origin": "United States of America", "Performance": "Cruising speed Mach 0.80. Range with 240 passengers 6055km (3270nm) with RB-211s, 6455km (3485nm) with PW-2043s.", "Powerplant_Desc": "Two 191.7kN (43,100lb) RollsRoyce RB-211-535E4-B turbofans, or 195.1kN (43,850lb) Pratt & Whitney PW-2043s.", "Powerplants": "Two 191.7kN (43,100lb) RollsRoyce RB-211-535E4-B turbofans, or 195.1kN (43,850lb) Pratt & Whitney PW-2043s.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "6055", "Range_nm": "3270", "Record_Status": "active", "Role": "Medium range narrowbody airliner", "Seating_Config": "Flightcrew of two. Typical two class arrangement seats 240 passengers, comprising 12 premium class at 91cm (36in) pitch and 228 economy class at 81cm (32in) pitch. Max seating for 289 passengers in a high density configuration 71-74cm (28-29in) pitch.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/boeing-757-300/102", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Typical two class arrangement seats 240 passengers, comprising 12 premium class at 91cm (36in) pitch and 228 economy class at 81cm (32in) pitch. Max seating for 289 passengers in a high density configuration 71-74cm (28-29in) pitch.", "Units_Built": "63 ordered by May 2002, of which 30 had been delivered.", "WTC": "", "Weights": "Operating empty with RB-211s 64,590kg (142,400lb), with PW-2043s 64,460kg (142,110lb), max takeoff 122,470kg (270,000lb).", "Wingspan_m": "38.05"}'),
(50591, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Medium to long range widebody airliner", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "767-200 Freighter", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The narrowest widebody in service, the 767 started life as an advanced technology mid to large size airliner in the late 1970s. \\n\\nLaunched in July 1978, the 767 was developed in tandem with the narrowbody 757 with which it shares a common two crew EFIS flightdeck (with six colour CRT displays) and many systems. The 767 also features a unique width fuselage typically seating seven abreast in economy, and a new wing design with greater sweepback (compared to the 757) which was designed with high altitude cruise in mind. \\n\\nThe 767 program also features a high degree of international participation, with Japanese companies in particular having a large share of construction. \\n\\nInitially Boeing intended to offer two versions, the longer 767-200 and short fuselage 767100 (which was not launched as it was too close in capacity to the 757). The 767 first flew on September 26 1981, and entered service (with United) on September 26 1982 (certification with P&W engines was awarded on July 30 1982). \\n\\nThe longer range 767-200ER (Extended Range) version features higher weights and an additional wing centre section fuel tank. It first flew on March 6 1984, and service entry, with Ethiopian Airlines, was two months later. The 200ER accounts for 111 of the total 239 767-200s ordered. \\n\\nThe last airliner 767-200/-200ER was delivered in 1994 until a November 1998 order from Continental. These had all been delivered by 2002, but military orders for 767 tankers will keep the -200 in production.", "Dimensions": "Wing span 47.57m (156ft 1in), length 48.51m (159ft 2in), height 15.85m (52ft 0in). Wing area 283.3m2 (3050sq ft).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Boeing 767-200 Freighter", "Generation": "", "Height_m": "", "IATA_Code": "76X", "ICAO_Code": "B762", "Length_m": "48.51", "MTOW_kg": "74752", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "914", "Mission_Type": "Passenger", "Model": "767-200 Freighter", "Name": "Boeing 767-200", "Origin": "United States of America", "Performance": "767-200 - Max cruising speed 914km/h (493kt), economical cruising speed 854km/h (461kt). Range of basic aircraft with JT9Ds 5855km (3160nm), medium range version with CF6s 7135km (3850nm). 767-200ER - Speeds same. Range with PW4056s 12,269km (6625nm), with CF6s 12,352km (6670nm).", "Powerplant_Desc": "767-200 - Two 213.5kN (48,000lb) Pratt & Whitney JT9D7R4D turbofans, or 222.4kN (50,000lb) PW4050s, or 233.5kN (52,500lb) General Electric CF680C2B2s. 767-200ER - Two PW4050s (as above), or 231kN (52,000lb) PW4052s, or 252.4kN (56,750lb) PW4056s, or 257.7kN (57,900lb) CF680C2B4Fs.", "Powerplants": "767-200 - Two 213.5kN (48,000lb) Pratt & Whitney JT9D7R4D turbofans, or 222.4kN (50,000lb) PW4050s, or 233.5kN (52,500lb) General Electric CF680C2B2s. 767-200ER - Two PW4050s (as above), or 231kN (52,000lb) PW4052s, or 252.4kN (56,750lb) PW4056s, or 257.7kN (57,900lb) CF680C2B4Fs.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "5855", "Range_nm": "3160", "Record_Status": "active", "Role": "Medium to long range widebody airliner", "Seating_Config": "Flightcrew of two, or optionally three. Typical two class seating for 18 premium and 198 economy class pax. Max seating for 290 at eight abreast and 76cm (30in) pitch. Underfloor cargo holds can accommodate up to 22 LD2 containers.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/boeing-767-200/103", "Status": "In Service", "Typical_Capacity": "Flightcrew of two, or optionally three. Typical two class seating for 18 premium and 198 economy class pax. Max seating for 290 at eight abreast and 76cm (30in) pitch. Underfloor cargo holds can accommodate up to 22 LD2 containers.", "Units_Built": "Total 767 sales in late 2002 stood at 934. 245 767-200/200ER orders were placed by this time, of which 240 had been delivered.", "WTC": "", "Weights": "767-200 - Empty with JT9Ds 74,752kg (164,800lb), with CF6s 74,344kg (163,900lb). Operating empty with JT9Ds 80,920kg (178,400lb), with CF6s 80,510kg (177,500lb). Max takeoff 136,078kg (300,000lb), medium range max takeoff 142,881kg (315,000lb). 767-200ER - Empty with PW4056s 76,566kg (168,800lb), with CF680C2B4s 76,476kg (168,600lb), operating empty with PW4056s 84,415kg (186,100lb), with CF680C2B4Fs 84,370kg (186,000lb). Max takeoff with PW4056s or CF680C2B4Fs 175,540kg (387,000lb).", "Wingspan_m": "47.57"}'),
(50592, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Medium to long range widebody airliner", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "767-300 Freighter", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "Boeing announced that it was developing a stretched development of the 767-200 in February 1982. \\n\\nThe resulting 767-300 features a 6.42m (21ft 1in) stretch consisting of fuselage plugs forward (3.07m/10ft 1in) and behind (3.35m/11ft) the wing centre section. The flightdeck and systems were carried directly over from the 767-200, the only other changes were minor, and related to the increased weights of the new version. Initially the max takeoff weight was the same as the later 767-200ER. \\n\\nThe 767-300 flew for the first time on January 30 1986, and was awarded certification and entered service in September that year. The higher weight Extended Range ER version flew on December 19 1986, while RollsRoyce RB-211-524G engines became available from 1989. The range of the 767-300ER has proven to be very popular with a number of airlines using them for long range low density flights. \\n\\nIn 1993 Boeing launched the 767-300F General Market Freighter. Changes include strengthened undercarriage and wing structure, a cargo handling system, no cabin windows and a main deck freight door. Capacity is 24 containers. The further stretched 767-400 is described separately.", "Dimensions": "Wing span 47.57m (156ft 1in), length 54.94m (180ft 3in), height 15.85m (52ft 0in). Wing area 283.3m2 (3050sq ft).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Boeing 767-300 Freighter", "Generation": "", "Height_m": "", "IATA_Code": "76Y", "ICAO_Code": "B763", "Length_m": "54.94", "MTOW_kg": "79560", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "900", "Mission_Type": "Passenger", "Model": "767-300 Freighter", "Name": "Boeing 767-300", "Origin": "United States of America", "Performance": "Max cruising speed 900km/h (486kt), economical cruising speed 850km/h (460kt). Higher gross weight version range with design payload and PW-4050s 7835km (4230nm), with CF6-80C2B2s 7890km (4260nm). \\n767-300ER - Range with design payload with PW-4060s 10,880km (5875nm), with CF6-80C2B4Fs 10,195km (5505nm).", "Powerplant_Desc": "Two 213.5kN (48,000lb) Pratt & Whitney JT9D-7R4 turbofans or 222.4kN (50,000lb) JT9D-7R4Es, or 222.4kN (50,000lb) PW-4050, or 233.5kN (52,000lb) PW-4052s, or 213.5kN (48,000lb) General Electric CF6-80As or 213.5kN (48,000lb) CF6-80A2s, or 231.3kN (52,500lb) CF6-80C2B2s, or 257.5kN (57,900lb) CF6-80C2B4Fs, or 269.9kN (60,000lb) RollsRoyce RB-211-524Gs. \\n767-300ER - Same options or 252.4kN (56,750lb) PW-4056s or 266.9kN (60,000lb) CF6-80C2B6s, or two PW-4060 rated at 60,000 lbs MTO", "Powerplants": "Two 213.5kN (48,000lb) Pratt & Whitney JT9D-7R4 turbofans or 222.4kN (50,000lb) JT9D-7R4Es, or 222.4kN (50,000lb) PW-4050, or 233.5kN (52,000lb) PW-4052s, or 213.5kN (48,000lb) General Electric CF6-80As or 213.5kN (48,000lb) CF6-80A2s, or 231.3kN (52,500lb) CF6-80C2B2s, or 257.5kN (57,900lb) CF6-80C2B4Fs, or 269.9kN (60,000lb) RollsRoyce RB-211-524Gs. \\n767-300ER - Same options or 252.4kN (56,750lb) PW-4056s or 266.9kN (60,000lb) CF6-80C2B6s, or two PW-4060 rated at 60,000 lbs MTO", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "7835", "Range_nm": "4230", "Record_Status": "active", "Role": "Medium to long range widebody airliner", "Seating_Config": "Flightcrew of two. Typical three class layout for 210, two class 269 (24 premium & 245 economy seven abreast) max seating for 350 at eight abreast. Underfloor capacity for 20 LD2s.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/boeing-767-300/104", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Typical three class layout for 210, two class 269 (24 premium & 245 economy seven abreast) max seating for 350 at eight abreast. Underfloor capacity for 20 LD2s.", "Units_Built": "652 767-300s (including ERs) had been ordered by late 2002, of which 607 had been delivered.", "WTC": "", "Weights": "767-300 - Empty with PW-4050s 79,560kg (175,400lb), with CF6-80C2B2s 79,379kg (175,000lb). Operating empty with PW-4050s 87,135kg (192,100lb), with CF6-80C2B2s 86,955kg (191,700lb). Higher gross weight version max takeoff with PW-4050s or CF6-80C2B2s 159,210kg (351,000lb). \\n767-300ER - Empty with PW-4060s 81,374kg (179,400lb), with CF6-80C2B4s 80,603kg (177,700lb). Operating empty with PW-4060s 90,535kg (199,600lb), with CF6-80C2B4s 90,175kg (198,800lb). Max takeoff with PW-4060s 181,890kg (401,000lb), with CF6-80C2B4Fs 175,540kg (387,000lb).", "Wingspan_m": "47.57"}'),
(50593, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Long range widebody airliner", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "767-400", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "Boeing''s 767-400ER is a stretched development of the popular 767-300ER, designed to replace early A300, A310 and 767 twins used on transcontinental services and DC-10-30s and L-1011 trijets used for intercontinental work. It competes with the A330-200. \\n\\nDesign work on the then 767-400ERX began in late 1996 when Boeing signed a technical assistance agreement covering the program with the then independent Douglas Aircraft Company division of McDonnell Douglas. At the time Boeing suffered from a shortage of engineering talent with a number of other key programs underway while Douglas had surplus engineering capacity following the cancellation of the MD-XX (Boeing and McDonnell Douglas subsequently merged in August 1997). The program was formally launched as the 767-400ER in January 1997 when Delta Airlines ordered 21. \\n\\nThe most significant change with the 767-300 is the 6.4m (21ft) fuselage stretch, which increases typical three class seating capacity from 218 to 245. Because of the increased fuselage length the -400 features all new, 46cm (18in) taller landing gear to restore rotation angles for acceptable takeoff and landing speeds and distances which would otherwise have been adversely affected by the fuselage stretch. The wheels, tyres and brakes are common with the 777. \\n\\nCompared to the 767-300, the 767-400ER''s wing features 2.34m (7ft 8in) long raked wingtips which improve aerodynamic efficiency. Winglets were originally considered but the wingtip extensions proved more efficient. The wing is also made from increased gauge aluminium with thicker spars. \\n\\nInside, the 767-400ER features a 777 style advanced flightdeck with six colour multifunction displays, which can present information in the same format as earlier 767s, allowing a common type certificate, or as for the 777 and Next Generation 737s. The all new passenger interior is similar to that in the 777. \\n\\nOther features include common engines with the 767-300, a new APU, new tailskid and increased weights. \\n\\nThe first flight was made 9 October 1999. Four aircraft took part in the development program. \\n\\nDelta Airlines was the launch customer, and, as of December 2001, the aircraft was also ordered by Continental Airlines and Kenya Airways.", "Dimensions": "Wing span 51.92m (170ft 4in), length 61.37m (201ft 4in), height 16.87m (55ft 4in)", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Boeing 767-400", "Generation": "", "Height_m": "", "IATA_Code": "764", "ICAO_Code": "B764", "Length_m": "61.37", "MTOW_kg": "103145", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "767-400", "Name": "Boeing 767-400", "Origin": "United States of America", "Performance": "Design cruising speed 0.80 Mach. Design range at max takeoff weight with max passengers 10,343km (5580nm) with PW4062s, 10,418km (5625nm) with CF6-80C2B8Fs.", "Powerplant_Desc": "Two 281.6kN (63,300lb) Pratt & Whitney PW4062 turbofans, or two 276.2kN (62,100lb) General Electric CF6-80C2B7F1s or 282.5kN (63,500lb) CF6-80C2B8Fs.", "Powerplants": "Two 281.6kN (63,300lb) Pratt & Whitney PW4062 turbofans, or two 276.2kN (62,100lb) General Electric CF6-80C2B7F1s or 282.5kN (63,500lb) CF6-80C2B8Fs.", "Production_Count": "", "Production_Status": "active", "Range_km": "343", "Range_nm": "5580", "Record_Status": "active", "Role": "Long range widebody airliner", "Seating_Config": "Flightcrew of two. Typical three class arrangement for 245 passengers, comprising 20 first class at 152cm (60in) pitch, 50 business at 97cm (38in) and 175 economy at 81cm (32in).", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/boeing-767-400/105", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Typical three class arrangement for 245 passengers, comprising 20 first class at 152cm (60in) pitch, 50 business at 97cm (38in) and 175 economy at 81cm (32in).", "Units_Built": "Orders for the 767-400 as of December 2001 stood at 40 with 24 aircraft delivered. In current production.", "WTC": "H", "Weights": "Operating empty with PW4062s 103,145kg (227,400lb), 103,100kg (227,300lb) with CF6-80C2B8Fs, max takeoff 204,120kg (450,000lb).", "Wingspan_m": "51.92"}'),
(50594, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Long and ultra long range widebody airliners", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "777-200", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "Boeing''s advanced widebody 777 twin incorporates more advanced technologies than any other previous Boeing airliner, and has been progressively developed into increasingly longer range developments. \\n\\nThe 777 was originally conceived as a stretched 767, but Boeing instead adopted an all new design. Notable 777 design features include a unique fuselage cross section, Boeing''s first application of fly-by-wire, an advanced technology glass flightdeck with five liquid crystal displays, comparatively large scale use of composites (10% by weight), and advanced and extremely powerful engines. The 777 was also offered with optional folding wings where the outer 6m/21ft of each would fold upwards for operations at space restricted airports. \\n\\nThe basic 777-200 as launched in October 1990 was offered in two versions, the basic 777-200 (initially A-Market) and the increased weight longer range 777-200IGW (Increased Gross Weight, initially B-Market). The IGW has since been redesignated 777-200ER. \\n\\nThe 777-200 first flew on June 12 1994, with FAA and JAA certification awarded on April 19 1995. The FAA awarded full 180 minutes ETOPS clearance for PW4074 -200s on May 30 that year. First customer delivery was to United Airlines in May 1995. The first 777-200IGW/ER was delivered to British Airways in February 1997. \\n\\nThe 777-100X was a proposed shortened ultra long range (16,000km/8635nm) model, dropped in favour of the 777-200LR (originally 777-200X) design study. Boeing claims the 777-200LR will be the longest ranging airliner, capable of flying 16,417km (8865nm) - 18 hours flying time. It will achieve this with awesomely powerful 489kN (110,000lb) thrust GE90-110B1 turbofans, a significantly increased max takeoff weight and optional auxiliary fuel tanks in the rear cargo hold. Other changes include 2m (6.5ft) raked wingtips, new main landing gear, structural strengthening and optional overhead crew and flight attendant rest stations above the cabin. The 777-200LR was launched in 2000, but is now delayed until 2006. \\n\\nThe stretched 777-300 is described separately.", "Dimensions": "777-200 - Wing span 60.93m (199ft 11in), or folded 47.32m (155ft 3in), length 63.73m (209ft 1in), height 18.51m (60ft 9in). Wing area 427.8m2 (4605sq ft).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Boeing 777-200", "Generation": "", "Height_m": "", "IATA_Code": "772", "ICAO_Code": "B77L", "Length_m": "63.73", "MTOW_kg": "139025", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "905", "Mission_Type": "Passenger", "Model": "777-200", "Name": "Boeing 777-200", "Origin": "United States of America", "Performance": "Typical cruising speed 905km/h (490kt). \\n777-200 - Range 229 tonne MTOW 7000km (3780nm), 233 tonne MTOW 7778km (4200nm), 247 tonne MTOW range 9537km (5150nm). \\n777-200ER - 263 tonne MTOW range 11,037km (5960nm), 286 tonne MTOW range 14,316km (7730nm).\\n777-200LR - Max range 16,417km (8865nm)", "Powerplant_Desc": "777-200 - Two 329kN (74,000lb) Pratt & Whitney PW4074 turbofans, or 334kN (75,000lb) General Electric GE90-75Bs, or 334kN (75,000lb) Rolls-Royce Trent 875s. \\n247 tonne MTOW version - Two 345kN (77,000lb) PW4077s, or 338kN (76,000lb) GE90-76Bs or 345kN (77,000lb) Trent 877s. \\n777-200ER - Two 374kN (84,000lb) PW4084s, or 378kN (85,000lb) GE90-85Bs, or 373kN (84,000lb) Trent 884s; or 400kN (90,000lb) class PW4090s, GE90-90B1s, or Trent 890s; or 409kN (92,000lb) GE90-92Bs.\\n777-200LR - Two 489kN (110,000lb) GE90-110B1s.", "Powerplants": "777-200 - Two 329kN (74,000lb) Pratt & Whitney PW4074 turbofans, or 334kN (75,000lb) General Electric GE90-75Bs, or 334kN (75,000lb) Rolls-Royce Trent 875s. \\n247 tonne MTOW version - Two 345kN (77,000lb) PW4077s, or 338kN (76,000lb) GE90-76Bs or 345kN (77,000lb) Trent 877s. \\n777-200ER - Two 374kN (84,000lb) PW4084s, or 378kN (85,000lb) GE90-85Bs, or 373kN (84,000lb) Trent 884s; or 400kN (90,000lb) class PW4090s, GE90-90B1s, or Trent 890s; or 409kN (92,000lb) GE90-92Bs.\\n777-200LR - Two 489kN (110,000lb) GE90-110B1s.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "7000", "Range_nm": "3780", "Record_Status": "active", "Role": "Long and ultra long range widebody airliners", "Seating_Config": "Flightcrew of two. Passenger seating for 305 in three classes or up to 440. Underfloor capacity for up to 32 LD3 containers.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/boeing-777-200/106", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Passenger seating for 305 in three classes or up to 440. Underfloor capacity for up to 32 LD3 containers.", "Units_Built": "Total 777-200 orders received as of early 2003 452, with 379 delivered.", "WTC": "H", "Weights": "777-200 - Empty 139,025kg (306,500lb) or 139,160kg (306,800lb), max takeoff optionally 229,520kg (506,000lb), or 233,600kg (515,000lb), or 247,210kg (535,000lb). \\n777-200ER - Empty 142,430kg (314,000lb) with 374kN/84,000lb engines, 143,015kg (315,300lb) with 400kN/90,000lb engines, max takeoff optionally 263,085kg (580,000lb) or 286,897kg (632,500lb).\\n777-200LR - Max takeoff 341,105kg (752,000lb).", "Wingspan_m": "60.93"}'),
(50595, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Long range high capacity widebody airliner", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "777-300", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "Boeing''s 777-300 is powered by the world''s most powerful turbofan engines.\\n\\nThe stretched 777-300 is designed as a replacement for early generation 747s (747-100s and 200s). Compared to the older 747s the stretched 777 has comparable passenger capacity and range, but burns one third less fuel and features 40% lower maintenance costs. \\n\\nCompared with the baseline 777-200 the 300 features a 10.13m (33ft 3in) stretch, comprising plugs fore and aft of the wings. The longer fuselage allows seating for up to 550 passengers in a single class high density configuration. To cope with the stretch and the up to 13 tonne (28,600lb) increased max takeoff weight the 300 features a strengthened undercarriage, airframe and inboard wing. Other changes compared with the 777-200 include a tailskid and ground manoeuvring cameras mounted on the horizontal tail and underneath the forward fuselage. Otherwise changes have been kept to a minimum to maximise commonality. \\n\\nBoeing publicly announced it was developing the 777-300 at the Paris Airshow in mid June 1995 where it revealed it had secured 31 firm orders from All Nippon, Cathay Pacific, Korean Airlines and Thai Airways. Later that month Boeing''s board authorised production of the new aircraft. \\n\\nThe 777-300 rolled out on September 8 1997, followed by first flight on October 16 that year. The type made history on May 4 1998 when it was awarded type certification simultaneously from the US FAA and European JAA and was granted 180min ETOPS approval. Service entry with Cathay Pacific was later in that month. \\n\\nLike the 777-200, a 777-300ER long range version has been developed. Changes made to the 777-300ER are more powerful General Electric GE90-115B engines (currently the world''s most powerful jet engine), raked wingtips, strengthened body, wings, empennage, nose gear, engine struts and nacelles, new main landing gear, and provision for extra fuel tanks. The range, carrying 365 passengers, is increased up to 13,427km (7,250nm).\\n\\nRoll-out of the first 777-300ER was made on November 14 2002, followed by the first flight on February 24 2003. First delivery, to Air France, is scheduled for March 2004.", "Dimensions": "Wing span 60.93m (199ft 11in), or folded 47.32m (155ft 3in), length 73.86m (242ft 4in), height 18.51m (60ft 9in). Wing area 427.8m2 (4605sq ft).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Boeing 777-300", "Generation": "", "Height_m": "", "IATA_Code": "773", "ICAO_Code": "B773", "Length_m": "73.86", "MTOW_kg": "160120", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "893", "Mission_Type": "Passenger", "Model": "777-300", "Name": "Boeing 777-300", "Origin": "United States of America", "Performance": "777-300 - Typical cruising speed 893km/h (482kt). Range with 386 three class passengers 10,595km (5720nm).\\n777-300ER - Range with 365 passengers 13,427km (7,250nm).", "Powerplant_Desc": "777-300 - Either two 400kN (90,000lb) Pratt & Whitney PW-4090 turbofans, or 436kN (98,000lb) PW-4098s, or 409kN (92,000lb) Rolls-Royce Trent 892s, or 409kN (92,000lb) General Electric GE90-92Bs.\\n777-300ER - 512 kN (115,300lb) General Electric GE90-115B", "Powerplants": "777-300 - Either two 400kN (90,000lb) Pratt & Whitney PW-4090 turbofans, or 436kN (98,000lb) PW-4098s, or 409kN (92,000lb) Rolls-Royce Trent 892s, or 409kN (92,000lb) General Electric GE90-92Bs.\\n777-300ER - 512 kN (115,300lb) General Electric GE90-115B", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "595", "Range_nm": "5720", "Record_Status": "active", "Role": "Long range high capacity widebody airliner", "Seating_Config": "Flightcrew of two. Typical passenger accommodation for 386 (30 first, 84 business and 254 economy) to 394 in three class arrangements, 400 to 479 in two class arrangements or up to 550 in an all economy high density configuration. Underfloor capacity for 20 standard LD3 containers or eight 2.55 x 3.17m (96 x 125in) pallets.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/boeing-777-300/107", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Typical passenger accommodation for 386 (30 first, 84 business and 254 economy) to 394 in three class arrangements, 400 to 479 in two class arrangements or up to 550 in an all economy high density configuration. Underfloor capacity for 20 standard LD3 containers or eight 2.55 x 3.17m (96 x 125in) pallets.", "Units_Built": "Total 777-300 orders as of January 2003 stood at 121 (of which 56 300ER) with 44 delivered.", "WTC": "H", "Weights": "Operating empty 160,120kg (353,600lb), basic max takeoff 263,080kg (580,000lb), high gross weight MTOW 299,380kg (660,000lb).", "Wingspan_m": "60.93"}'),
