(50599, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "2J", "Common_Name": "787-3", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Boeing 787-3", "Generation": "", "Height_m": "", "IATA_Code": "783", "ICAO_Code": "B783", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "787-3", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "", "Weights": "", "Wingspan_m": ""}'),
(50600, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Long range widebody airliner", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "787-8", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The Boeing 7E7 was announced on 29th January 2003 following the cancellation of the Sonic Cruiser. The aircraft was renamed the Boeing 787 in 2005.\\n\\nThis important design marked a major shift in technology for Boeing, which aimed for maximum fuel efficiency in a number of ways. Chief among these was a radical change of construction material, with much of the aircraft being built of carbon fibre reinforced plastic (CFRP). Additionally, the fuselage was produced as ''barrels'' rather than sheets of material, reducing the number of fastenings required. This further increased the weight savings. Many of the aircraft''s systems are now electrically operated, replacing the heavier hydraulic systems of earlier Boeing designs with lighter technology.\\n\\nThe engines are new designs with increased fuel efficiency. Both the General Electric GEnx and Rolls-Royce Trent 1000 designs are available. Boeing decided to use bleedless designs, another major change for aircraft of this class. Interestingly, Airbus decided not to use bleedless technology on its competing Airbus A350 design and it remains to be seen which approach offers the greatest benefits over the other. The rear engine nacelle has a distinctive rippled look which reduces noise as the engine exhaust and external air mix.\\n\\nFor passengers, there have been a number of technology improvements. Most noticeably, the windows are amongst the largest in a civil airliner and are lower on the fuselage than is usual, so that passengers have a better view downwards. The lighting system use LED technology allowing each customer great flexibility on the lighting schemes it can use. The pressurisation system features a lower cabin altitude than normal and allows increased humidity, both factors which will contribute to passenger comfort during a long flight.\\n\\nWith all these technology advances and a distributed manufacturing program that was very new to Boeing, it is not suprising that the program encountered a number of delays. However, the first aircraft was delivered to a customer, All Nippon Airways, in September 2011.", "Dimensions": "787-8 - Wing span 60.00m (197ft 0in), length 56.70m (186ft 0in), height 16.9m (55ft 6in). Wing area 325m2 (3501sq ft).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Boeing 787-8", "Generation": "", "Height_m": "", "IATA_Code": "788", "ICAO_Code": "B788", "Length_m": "56.70", "MTOW_kg": "110000", "Manufacturer": "Boeing", "Max_Pax": "", "Max_Speed_kmh": "913", "Mission_Type": "Passenger", "Model": "787-8", "Name": "Boeing 787-8 Dreamliner", "Origin": "United States of America", "Performance": "Typical cruising speed 913km/h (490kt).\\nMaximum speed 954km/h (515kt).\\nMaximum range 15,200km (8200nm).", "Powerplant_Desc": "787-8 - Two General Electric GEnx, or Rolls-Royce Trent 1000s.", "Powerplants": "787-8 - Two General Electric GEnx, or Rolls-Royce Trent 1000s.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "200", "Range_nm": "8200", "Record_Status": "active", "Role": "Long range widebody airliner", "Seating_Config": "Flightcrew of two. Passenger seating is typically between 210 and 250 depending on customer layout.\\nUnderfloor cargo capacity for up to 28 LD3 containers.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/boeing-787-8-dreamliner/407", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Passenger seating is typically between 210 and 250 depending on customer layout.\\nUnderfloor cargo capacity for up to 28 LD3 containers.", "Units_Built": "By Summer of 2011 there were over 700 orders for the 787-8 and 787-9 models. Deliveries to customers began in September 2011, with a 787-8 being received by All Nippon Airways.", "WTC": "H", "Weights": "787-8 - Empty 110,000kg (242,000lb), max takeoff 228,000kg (502,500lb).", "Wingspan_m": "60.00"}'),
