(50606, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Extra-Large cargo aircraft", "Bibliography": "Airliners.net", "Category": "4T", "Common_Name": "An-22", "Country_Origin": "Ukraine", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The massive An-22 Antei (Antheus) is the largest turboprop powered aircraft yet built - it has a maximum takeoff weight similar to that of the Airbus A340-300 - and was designed in response to a largely military Soviet requirement for a strategic heavylift freighter. \\n\\nThe An-22 (NATO reporting name `Cock'') made its first flight on February 27 1965 - at that time it was comfortably the largest aircraft in the world. Production of the An-22 for the Soviet air force and Aeroflot continued through the 1960s until 1974. \\n\\nThe An-22 set 14 payload to height records in 1967, the pinnacle of which was the carriage of 100 tonnes (220,500lb) of metal blocks to an altitude of 25,748ft (7848m). It also established the record for a maximum payload lifted to a height of 2000m (6562ft), carrying a payload of 104,444kg (221,443lb). A number of class speed records were also set in 1972, including a speed of 608.5km/h (328kt) around a 1000km (540nm) circuit with a 50,000kg (110,250lb) payload. Further speed with payload records were established in 1974 and 1975. \\n\\nAs well as operations into the underdeveloped regions of Russia''s northeast, Siberia and Far East, Aeroflot An-22s were commonly used for military transport, their `civilian'' status allowing much freer access to landing and overflight rights. \\n\\nNotable features of the An-22 include the NK12 turboprops - which also power the Tupolev Tu-95/Tu-142 Bear family of bombers and maritime patrol aircraft and are the most powerful turboprop engines in service - comprehensive navigation and precision drop avionics, and massive undercarriage and tailplane.", "Dimensions": "Wing span 64.49m (211ft 4in), length 57.92m (190ft 0in), height 12.53m (41ft 1in). Wing area 345m2 (3713.0sq ft).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Antonov An-22", "Generation": "", "Height_m": "", "IATA_Code": "A22", "ICAO_Code": "AN22", "Length_m": "", "MTOW_kg": "600000", "Manufacturer": "Antonov", "Max_Pax": "", "Max_Speed_kmh": "850", "Mission_Type": "Passenger", "Model": "An-22", "Name": "Antonov An-22 Antei", "Origin": "Ukraine", "Performance": "Max level speed 740km/h (400kt). Range with max fuel and 45 tonne (99,200lb) payload 10,950km (5905nm), range with max payload 5000km (2692nm).", "Powerplant_Desc": "Four 11,185kW (15,000shp) Kuznetsov (now Kuibyshev) NK12MA turboprops driving eight blade counter rotating propellers.", "Powerplants": "6x Progress-D-18T", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "Large capacity turboprop freighter", "Seating_Config": "Flightcrew of up to six, comprising two pilots, navigator, flight engineer and a communications specialist. Up to 29 passengers can be accommodated on the upper deck behind the cockpit. The unpressurised main cabin can house a range of oversize payloads such as main battle tanks. Total An-22 payload is 80,000kg (176,350lb).", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/antonov-an-22-antei/36", "Status": "In Service", "Typical_Capacity": "Maximum load: 551150lbs (250000kg)", "Units_Built": "Approximately 70 have been built, of which approximately 50 have been operated in Aeroflot colours. A few dozen remain in commercial and military service.", "WTC": "", "Weights": "Typical empty equipped 114,000kg (251,325lb), max takeoff 250,000kg (551,160lb).", "Wingspan_m": "88.4"}'),
