(50610, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "2T", "Common_Name": "/ Antonov An-32", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Antonow / Antonov An-32", "Generation": "", "Height_m": "", "IATA_Code": "A32", "ICAO_Code": "AN32", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Antonow", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "/ Antonov An-32", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "", "Weights": "", "Wingspan_m": ""}'),
(50611, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Regional airliner and utility transport", "Bibliography": "Airliners.net", "Category": "2T", "Common_Name": "An-38", "Country_Origin": "Ukraine", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The An-38 is an all-new development of the earlier An-28, series production of which had been transferred to PZL-Mielec in Poland. During a sales tour of India in 1989 a requirement emerged for a larger 25-30 seat version of the An-28. Late 1990 this was approved by the Soviet Ministry of Transport. At the 1991 Paris Air Show a model was shown and details were made public for the first time. The aircraft is intended to replace An-24s, Let L-410s and Yak-40s. \\n\\nAs the An-28 was produced in Poland, and had to be paid in foreign currency after the break-up of the Soviet Union, payment in local currency was an added advantage for the development of the An-38.\\n\\nThe An-38 retains the basic wing and twin fin tail structure of the An-28, but has a stretched fuselage with three additional seat rows. New high efficiency Honeywell TPE331 or Omsk TVD-20 engines power the An-28. Many other improvements have been made such as improved sound and vibration insulation, reduced external noise, improved cockpit and passenger cabin comfort, payload, fuel efficiency and flight speed. The An-38 is equipped with a rear cargo door and a cargo-handling overhead-track hoist. The seats and the baggage compartment can be folded by the crew to provide a clear space for use as a cargo aircraft.\\n\\nThe fixed tricycle gear with low pressure tires enables operation from unpaved runways. The An-38 has weather radar and an integrated navigation system and can be operated by night and in adverse weather. It can be equipped with Western or CIS avionics.\\n\\nApart from passenger and cargo configuration, the multirole An-38 can also be equipped for forest patrol, aerial photography, survey, fishery patrol, ambulance, VIP transport and military airlift. \\n\\nThe first flight was made on June 23 1994 by the version with TPE331 engines, the An-38-100. The TVD-20 version, the An-38-200, followed on December 11 2001. Certification of the An-38-100 in compliance with AP-25 rules was granted April 22 1997. The An-38-200 was certificated on November 28 2002.\\n\\nThe An-38-110 is a -100 with a reduced avionics fit, the An-38-120 is a -100 with an enhanced avionics fit.\\n\\nIn December 1995 Antonov and NAPO (Novosibirsk Aircraft Production Association) established a joint venture company, Siberian Antonov Aircraft, to produce, market and provide after-sale support of the An-38. Series production of the An-38-100 aircraft is by NAPO.\\n\\nTwo prototypes (one at Antonov and one at NAPO) and a static test airframe were built. Vostok Airlines became the launch customer for the production aircraft and the first three were received by mid-1995. The An-38 also entered service with e.g. Layang Layang Aerospace in Malaysia, Alrosa-Avia in Russia, and Vietnam Air Services.", "Dimensions": "Wing span 22.06m (72ft 5in), length 15.67m (51ft 5in), height 5.05m (16ft 7in).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Antonov An-38", "Generation": "", "Height_m": "", "IATA_Code": "A38", "ICAO_Code": "AN38", "Length_m": "15.67", "MTOW_kg": "5300", "Manufacturer": "Antonov", "Max_Pax": "", "Max_Speed_kmh": "405", "Mission_Type": "Passenger", "Model": "An-38", "Name": "Antonov An-38", "Origin": "Ukraine", "Performance": "An-38-100 - Max cruising speed 405km/h (219kt), nominal cruising speed 380km/h (205kt). Range at 3050m (10,000ft) with maximum payload 700km (380nm), with 1300kg (2865lb) payload 1750km (945nm).\\nAn-38-200 - Range at 3050m (10,000ft) with maximum payload 780km (420nm), with 1300kg (2865lb) payload 1780km (960nm).", "Powerplant_Desc": "An-38-100 - Two 1118kW (1500shp) Honeywell TPE331-14GR-801E turboprops driving Hartzell five blade propellers.\\nAn-38-200 - Two 1030kW (1380shp) Omsk TVD-20 turboprops driving Aerosila propellers.", "Powerplants": "An-38-100 - Two 1118kW (1500shp) Honeywell TPE331-14GR-801E turboprops driving Hartzell five blade propellers.\\nAn-38-200 - Two 1030kW (1380shp) Omsk TVD-20 turboprops driving Aerosila propellers.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "700", "Range_nm": "380", "Record_Status": "active", "Role": "Regional airliner and utility transport", "Seating_Config": "Flightcrew of two. Standard passenger seating for 26 at three abreast, optionally 27 seats at 75cm (29in) pitch.", "Service_Ceiling_ft": "000", "Source_URL": "https://www.airliners.net/aircraft-data/antonov-an-38/404", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Standard passenger seating for 26 at three abreast, optionally 27 seats at 75cm (29in) pitch.", "Units_Built": "11 (mid 2004).", "WTC": "", "Weights": "An-38-100 - Empty 5300kg (11,684lb), max takeoff 9500kg (20,945lb). \\nAn-38-200 - Max takeoff 9930kg (21,891lb).", "Wingspan_m": "22.06"}'),
(50612, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Turboprop regional airliner", "Bibliography": "Airliners.net", "Category": "2T", "Common_Name": "/ Antonov An-140", "Country_Origin": "Ukraine", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "Antonov''s An-140 is an all new 50 seat twin turboprop regional airliner developed to replace the ageing An-24.\\n\\nAntonov announced development of the An-140 in 1993. The first An-140 prototype rolled out from the Kiev factory on June 6 1997 and flew for the first time on September 17 that year. The second flying prototype was completed in late 1998, while the first production standard An-140 flew on October 11 1999.\\n\\nThe An-140 is of conventional design and construction, with US and European certification planned in addition to Russian/CIS certification. The basic version is powered by Motor-Sich AI-30s which are licence built Klimov TV3-117VMA-SBM1s, while Pratt & Whitney Canada PW127As will be optional. The flightdeck features conventional instruments, the main cabin seats 52 in a four abreast configuration. The rear passenger door features integral stairs, while a forward starboard side freight door allows cargo to be carried. The rear of the cabin also features a galley, coat stowage and a toilet.\\n\\nProduction of the initial basic An-140 was superseded in 2003 by the An-140-100 which features a 1.00m (3ft 3in) increase in wing span, a higher MTOW and a 300km (160nm) longer range. Other future versions include the An-140A for Aeroflot which will be powered by PW127As, the An-140T freighter which would have a large freight door on the rear port side, the convertible An-140TK, the An-140VIP executive version, and the An-142 with a rear loading freight ramp. Military versions are also planned.    \\n\\nSeries production of the An-140 is being undertaken at Kharkov by KhGAPP in Ukraine and at Samara in Russia by Aviacor. The first few aircraft were for Odessa Airlines, Aeromost (originally named Aeromist), Motor-Sich and Illich Avia. \\n\\nIn 1996 Antonov signed an agreement with HESA in Iran for licence assembly of an An-140 model called the IRAN-140 Faraz at a new plant in Esfahan. Initial IRAN-140s will be assembled from supplied kits, with gradually increasing Iranian local content. the first Faraz flew in February 2001. Iran Asseman and Iran Air are expected to be customers.", "Dimensions": "An-140 - Wing span 24.51m (80ft 5in), length 22.61m (74ft 2in), height 8.23m (26ft 11in).\\nAn-140-100 - Wing span 25.51m (83ft 8in).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Antonow / Antonov An-140", "Generation": "", "Height_m": "", "IATA_Code": "A40", "ICAO_Code": "A140", "Length_m": "22.61", "MTOW_kg": "19150", "Manufacturer": "Antonow", "Max_Pax": "", "Max_Speed_kmh": "575", "Mission_Type": "Passenger", "Model": "/ Antonov An-140", "Name": "Antonov An-140", "Origin": "Ukraine", "Performance": "An-140 with AI-30s - Max cruising speed 575km/h (310kt), economical cruising speed 520km/h (280kt). Range with 52 passengers 2100km (1133nm), range with a 6000kg (13,227lb) payload at 520km/h (280kt) 900km (486nm).\\nAn-140 with PW127s - Range with 52 passengers 2500km (1349nm).", "Powerplant_Desc": "An-140 - Two 1839kW (2466shp) Motor-Sich AI-30 Series 1 turboprops (licence built Klimov TV3-117s) driving six blade propellers, or two 1864kW (2500shp) Pratt & Whitney Canada PW127A Turboprops.", "Powerplants": "An-140 - Two 1839kW (2466shp) Motor-Sich AI-30 Series 1 turboprops (licence built Klimov TV3-117s) driving six blade propellers, or two 1864kW (2500shp) Pratt & Whitney Canada PW127A Turboprops.", "Production_Count": "", "Production_Status": "active", "Range_km": "2100", "Range_nm": "1133", "Record_Status": "active", "Role": "Turboprop regional airliner", "Seating_Config": "An-140 - Flightcrew of two. Typical passenger seating for 52 at four abreast and 75cm (30in) pitch or 48 at 81cm (32in) pitch. Forward starboard freight door allows 1900 to 3650kg (4188 to 8046lb) of palletised freight and 36 or 20 passengers to be carried in a combi configuration.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/antonov-an-140/405", "Status": "In Service", "Typical_Capacity": "An-140 - Flightcrew of two. Typical passenger seating for 52 at four abreast and 75cm (30in) pitch or 48 at 81cm (32in) pitch. Forward starboard freight door allows 1900 to 3650kg (4188 to 8046lb) of palletised freight and 36 or 20 passengers to be carried in a combi configuration.", "Units_Built": "Two prototypes and eight production aircraft by the end of 2004.", "WTC": "", "Weights": "An-140 - Max takeoff 19,150kg (42,218lb).\\nAn-140-100 - Empty 12,810kg (28,240lb), max takeoff 21,500kg (47,400lb).", "Wingspan_m": "24.51"}'),
(50613, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "4J", "Common_Name": "/ Antonov An-124", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Antonow / Antonov An-124", "Generation": "", "Height_m": "", "IATA_Code": "A4F", "ICAO_Code": "A124", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Antonow", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "/ Antonov An-124", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "", "Weights": "", "Wingspan_m": ""}'),
(50614, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "Airliners.net", "Category": "", "Common_Name": "An-225 Mriya", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "Antonov An-225 \\"Mriya\\" is the world''s largest aircraft. When it was built, it surpassed any airliner built before by 50%.  It was designed for the transportation of the Russian Space Shuttle \\"Buran\\" by the Antonov Design Bureau (HQ in Kiev, Ukraine), which already had built good and large cargo aircraft such as the Antonov An-124 \\"Ruslan\\". The basic configuration of the An-225  is the same as the An-124, except the An-225 is longer, has no rear ramp/door assembly, and incorporates a 32-wheel landing gear system (two nose and fourteen main wheel bogies, seven per side, each with two wheels).\\n\\nAn-225 \\"Mriya\\" (\\"Mriya\\" is Ukrainian word for \\"dream) is also capable to transport other oversized objects/cargo. It is not a military aircraft, but it could find many military uses, because of the ability to transport cargo that no other aircraft is capable to.\\n\\nThe plane had the first flight in early 1988 and entered service in 1989. It''s first flight took 75 minutes. After the cancellation of the Buran space program, the only An-225 built was stored in spring 1994, and it''s engines were used for An-124s. In 2001 the aircraft was made airworthy again, and made it''s new first flight on May 7. There were rumors that the European Space Agency had plans to launch the unmanned British HoTOL (Horizontal Take-Off and Landing) from the An-225, though these rumors appear to be unfounded. Although, some possibilities for deployment have already been found. Plenty of customers are to be found in the USA. According to Bruce Bird, Director of the Charter Division of Air Foyle, parts of rocket launchers like the Delta and Atlas could be transported in the An-225. Lockheed''s planned Venture Star could be transported on its back. Additionally the Mrija could serve as a launch platform for the X-34B. Furthermore big sections of aircraft could be transported in it. The complete assembled fuselage of a Boeing 737 can be fitted in the hold. \\n\\nA second An-225 was partly built, but was stored before it was finished.  It is possible that more aircraft of the type will be built, depending on market demand.", "Dimensions": "Wingspan 290 ft (88.4m), lenght -- 84,00m, height -- 18,10.", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Antonov An-225 Mriya", "Generation": "", "Height_m": "", "IATA_Code": "A25", "ICAO_Code": "A225", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Antonov", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "An-225 Mriya", "Name": "Antonov An-225 Mriya", "Origin": "Ukraine", "Performance": "Max. speed - 528mph (850km/h), range with max payload - 2425nm (4500km), range with no cargo - 8310nm (15400km).", "Powerplant_Desc": "6x Progress-D-18T", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "Extra-Large cargo aircraft", "Seating_Config": "Maximum load: 551150lbs (250000kg)", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/antonov-an-225-mriya/389", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "Only one was built since 1989, but a second frame was partially constructed and remains in storage.", "WTC": "", "Weights": "Max. take off weight -- 600000kg", "Wingspan_m": ""}'),
