(50617, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Medium range widebody airliner", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "A300-600F", "Country_Origin": "France, Germany, Spain and UK", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The A300-600 development of the earlier A300B4 incorporated a number of significant improvements and refinements, foremost being a two crew flightdeck and increased range. \\n\\nApart from the two crew EFIS cockpit, with digital avionics based on that developed for the A310, changes included the A310''s tail empennage which increased freight and passenger payloads, small winglets (an option from 1989, standard from 1991), simplified systems, greater use of composites, Fowler flaps and increased camber on the wings, new brakes and APU, and improved payload/range through an extensive drag reducing airframe clean up and new engines. First flight for the A300-600 was on July 8 1983, the first airline delivery was in March 1984. \\n\\nThe A300-600 was further developed into the longer range A300-600R, its extended range courtesy of a fuel trim tank in the tailplane and higher maximum takeoff weights. First flight was on December 9 1987, first delivery was April 20 1988 (to American Airlines). \\n\\nConvertible freight/passenger versions of all variants of the A300 have been offered, as has the all freight A300F4-600. The first new build pure freighter A300, one of 36 ordered for Federal Express, flew in December 1993. UPS is another major A300-600F customer, following its September 1998 order for 30. Airbus also offers conversion packages of existing passenger A300s into freighters with a left side forward freight door and strengthened floor.", "Dimensions": "Wing span 44.84m (147ft 1in), length 54.08m (177ft 5in), height 16.62m (54ft 6.5in). Wing area 260.0m2 (2798.7sq ft).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Airbus A300-600F", "Generation": "", "Height_m": "", "IATA_Code": "ABY", "ICAO_Code": "A306", "Length_m": "54.08", "MTOW_kg": "90115", "Manufacturer": "Airbus", "Max_Pax": "", "Max_Speed_kmh": "897", "Mission_Type": "Passenger", "Model": "A300-600F", "Name": "Airbus A300-600", "Origin": "France, Germany, Spain and UK", "Performance": "A300-600R - Max cruising speed 897km/h (484kt), long range cruising speed 875km/h (472kt). Range at typical airline operating weight with 267 passengers with 370km (200nm) reserves and standard fuel 7505km (4050nm) with CF6s, or 7540km (4070nm) with PW-4000s.\\nA300-600 - Range at same parameters 6670km (3600nm).\\nA300-600F - Range with max payload, and reserves 4908km (2650nm).", "Powerplant_Desc": "Two 262.4kN (59,000lb) General Electric CF6-80C2A1s, or two 273.6kN (61,500lb) CF6-80C2A5s, or two 249kN (56,000lb) Pratt & Whitney PW-4156s or two 258kN (58,000lb) PW-4158 turbofans.", "Powerplants": "Two 262.4kN (59,000lb) General Electric CF6-80C2A1s, or two 273.6kN (61,500lb) CF6-80C2A5s, or two 249kN (56,000lb) Pratt & Whitney PW-4156s or two 258kN (58,000lb) PW-4158 turbofans.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "370", "Range_nm": "200", "Record_Status": "active", "Role": "Medium range widebody airliner", "Seating_Config": "Flightcrew of two. Typical two class arrangement for 26 premium class passengers at six abreast and 240 economy class passengers at eight abreast. The A300-600 and 600R can carry 22 LD3 containers in forward and aft belly cargo holds. \\nA300-600F total payload 55,017kg (121,290lb).", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/airbus-a300-600/18", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Typical two class arrangement for 26 premium class passengers at six abreast and 240 economy class passengers at eight abreast. The A300-600 and 600R can carry 22 LD3 containers in forward and aft belly cargo holds. \\nA300-600F total payload 55,017kg (121,290lb).", "Units_Built": "A total of 334 A300-600s of all variants had been ordered by late 2002, of which 266 had been delivered.", "WTC": "", "Weights": "A300-600 - Operating empty with CF6s 90,115kg (198,665lb), with PW-4000s 90,065kg (198,565lb). Max takeoff 165,900kg (365,745lb). \\nA300-600R - Operating empty 91,040kg (200,700lb) with CF6s, or 90,965kg (200,550lb) with PW4000s, max takeoff 170,500kg (375,855lb), or optionally 171,700kg (378,535lb). \\nA300-600F - (CF6 powered) Operating empty 78,335kg (172,700lb), max takeoff 170,500kg (375,900lb).", "Wingspan_m": "44.84"}'),
(50618, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "A300-600ST Beluga", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The A300-600 development of the earlier A300B4 incorporated a number of significant improvements and refinements, foremost being a two crew flightdeck and increased range. \\n\\nApart from the two crew EFIS cockpit, with digital avionics based on that developed for the A310, changes included the A310''s tail empennage which increased freight and passenger payloads, small winglets (an option from 1989, standard from 1991), simplified systems, greater use of composites, Fowler flaps and increased camber on the wings, new brakes and APU, and improved payload/range through an extensive drag reducing airframe clean up and new engines. First flight for the A300-600 was on July 8 1983, the first airline delivery was in March 1984. \\n\\nThe A300-600 was further developed into the longer range A300-600R, its extended range courtesy of a fuel trim tank in the tailplane and higher maximum takeoff weights. First flight was on December 9 1987, first delivery was April 20 1988 (to American Airlines). \\n\\nConvertible freight/passenger versions of all variants of the A300 have been offered, as has the all freight A300F4-600. The first new build pure freighter A300, one of 36 ordered for Federal Express, flew in December 1993. UPS is another major A300-600F customer, following its September 1998 order for 30. Airbus also offers conversion packages of existing passenger A300s into freighters with a left side forward freight door and strengthened floor.", "Dimensions": "Wing span 44.84m (147ft 1in), length 54.08m (177ft 5in), height 16.62m (54ft 6.5in). Wing area 260.0m2 (2798.7sq ft).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Airbus 