(50648, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "Airliners.net", "Category": "", "Common_Name": "BD-100 Challenger 300", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "Bombardier''s all new Challenger 300 is a transcontinental range eight-seat corporate jet which will sit in the company''s model line-up between the Learjet 60 and Challenger 604. It is developed for a non-stop 5471km (3100nm) mission with a load of eight passengers and NBAA IFR reserves.\\n\\nBombardier revealed it was developing the Continental (as it was known then) at the 1998 National Business Aircraft Association''s annual convention in Las Vegas in October 1998. The program was officially launched at the Paris Air Show on June 13, 1999. It would compete for what Bombardier sees as a market for 1230 super mid size corporate jets by 2012. The Continental was renamed Challenger 300 on September 9, 2002. \\n\\nThe new jet will compete with the Hawker Horizon and Galaxy, among others. Bombardier claims the Continental will offer 39% more cabin space and 20% more range \\"than the leading mid size business jet\\". It is also claimed to have a larger cabin than the intercontinental range Falcon 50 and high speed Citation X. \\n\\nFeatures of the Challenger 300 are a cockpit equipped with Collins Pro Line 21 four-tube EFIS, EICAS, TCASII, and EGPWS avionics, a standard eight place double club interior with galley and toilet, stand-up headroom, a flat floor, an auxiliary power unit and thrust reversers, all metal construction and a large area wing for good field performance. \\n\\nThe Challenger 300 has a primarily light-alloy structure, with composites used for some non-structural items. The fuselage is of a semi-monocoque construction with frames and stringers. The wing has two spars. \\n\\nThe first Continental risk sharing partner is AlliedSignal, which will supply its new FADEC equipped AS-907 turbofan to power the new jet, as well as the engine nacelles and thrust reversers. The AS-907 itself is developed with a number of partner companies, with AIDC of Taiwan selected to provide the fan.\\n\\nWing/fuselage mating of the first aircraft was achieved on November 19, 2000. The first flight was made on August 14, 2001, and certification is due in the third quarter of 2002. The aircraft will start corporate service in 2003.  \\n\\nThe Challenger 300 made its official debut at Orlando Executive Airport on September 8, 2002 at the NBAA Convention. At that time, four aircraft were flying in the test program.", "Dimensions": "Wing span 19.46m (63ft 10in), length 20.93m (68ft 8in), height 6.20m (20ft 4in). Wing area 48.5m2 (522.0sq ft). Internal dimensions include a length of 8.72m (28ft 7in), height 1.85m (6ft 1in) and max width 2.19m (7ft 2in).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Bombardier BD-100 Challenger 300", "Generation": "", "Height_m": "", "IATA_Code": "", "ICAO_Code": "CL30", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Bombardier", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "BD-100 Challenger 300", "Name": "Bombardier BD-100 Challenger 300", "Origin": "Canada", "Performance": "High speed cruising speed 870km/h (470kt) or Mach 0.82, normal cruising speed 850km/h (460kt) or Mach 0.80. Balanced field length 1510m (4950ft), landing distance 792m (2600ft). Max operating altitude 45,000ft, initial cruise altitude 41,000ft. Max range with 8 passengers and NBAA IFR reserves at Mach 0.80 5740km (3100nm).", "Powerplant_Desc": "Two 28.9kN (6501lb) Honeywell AS-907 turbofans.", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "Super mid size corporate jet", "Seating_Config": "Flightcrew of two. Typical cabin arrangement for eight, with a two seat lounge opposite two facing seats, with club seating for four behind them, or double club seating. Features a forward wardrobe, refreshment centre and toilet. A high-density interior for 15 pax is also available.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/bombardier-bd-100-challenger-300/129", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "As of June 2001, 115 had been ordered.", "WTC": "", "Weights": "Basic operating 10,140kg (22,350lb), max takeoff 17,010kg (37,500lb). Max payload 1360kg (3000lb).", "Wingspan_m": ""}'),
(50649, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "2J", "Common_Name": "750 Citation X", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Cessna 750 Citation X", "Generation": "", "Height_m": "", "IATA_Code": "CN7", "ICAO_Code": "C750", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Cessna", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "750 Citation X", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "", "Weights": "", "Wingspan_m": ""}'),
(50650, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "CRJ 100", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "Bombardier''s Canadair Regional Jet pioneered the new 50 seat jet class, and has since become a runaway sales success. \\n\\nThe Canadair Regional Jet - or CRJ - is designed to offer the high speed advantages of much larger jets, with similar standards of service while at the same time offering operating economics, particularly over longer stage lengths, close to that of comparable size turboprops. \\n\\nThe concept of a stretched airliner derivative of the Challenger is not new, Canadair (now part of Bombardier Aerospace) originally studied a 24 seat stretched development of the CL-600 up to 1981. Design studies for a stretched airliner based on the 601 however were first undertaken in 1987, leading Canadair to launch the Regional Jet program on March 31 1989. The first of three development aircraft took to the skies for the first time on May 10 1991. Transport Canada certification was awarded on July 31 1992, allowing the first customer delivery to Lufthansa that October. \\n\\nMajor changes over the Challenger apart from the stretched fuselage include a new advanced wing optimised for airline operations, higher design weights, EFIS flightdeck with Collins Pro-Line 4 avionics suite, new undercarriage, additional fuel capacity and slightly more powerful CF-34 engines. \\n\\nThe original CRJ-100 series - the 100, 100ER and 100LR - was augmented by the 200 series (with more efficient engines) in 1995. The Series 200 is available in standard 200, long range 200LR with optional greater fuel capacity, and the extended range Series 200LR (all three are offered in B form with CF34-3B1s for improved hot and high performance). Corporate shuttle configurations are also available as the Corporate Jetliner and the SE (Special Edition). \\n\\nThe stretched, 70 seat CRJ-700 is described separately.", "Dimensions": "Wing span 21.21m (69ft 7in), length 26.77m (87ft 10in), height 6.22m (20ft 5in). Wing area 54.5m2 (587.1sq ft).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Canadair CRJ 100", "Generation": "", "Height_m": "", "IATA_Code": "CR1", "ICAO_Code": "CRJ1", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Canadair", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "CRJ 100", "Name": "Canadair CL-600 Regional Jet CRJ-100 & 200", "Origin": "Canada", "Performance": "100 - High speed cruise 851km/h (459kt), typical cruising speed 786km/h (424kt). Range with max payload at long range cruising speed with reserves 1815km (980nm). \\n200LR - Speeds same. Range with max payload at long range cruising speed and reserves over 3713km (2005nm).", "Powerplant_Desc": "100 - Two 41.0kN (9220lb) General Electric CF-34-3A1 turbofans. \\n200 - Two 41.0kN (9220lb) CF-34-3B1s.", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "Regional jet airliner", "Seating_Config": "Flightcrew of two. Typical one class seating for 50 at four abreast and 79cm (31in) pitch. Max seating for 52. Corporate Jetliner corporate shuttle configurations seat from 18 to 30.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/canadair-cl-600-regional-jet-crj-100-200/125", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "Total CRJ Series 100/200 orders at late 1998 over 430, of which more than 260 had been delivered. Bombardier plans to increase the CRJ production rate from six per month in late 1998 to 7.5 per month by the northern fall of 1999.", "WTC": "M", "Weights": "100 - Empty 13,236kg (29,180lb), operating empty 13,653kg (30,100lb), max takeoff 21,523kg (47,450lb).\\n200LR - Empty 13,740kg (30,292lb), operating empty 13,740kg (30,292lb), max takeoff 24,040kg (53,000lb).", "Wingspan_m": ""}'),
(50651, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "2J", "Common_Name": "CRJ 200", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Canadair CRJ 200", "Generation": "", "Height_m": "", "IATA_Code": "CR2", "ICAO_Code": "CRJ2", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Canadair", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "CRJ 200", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "M", "Weights": "", "Wingspan_m": ""}'),
(50652, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "CRJ 700", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "Bombardier''s 70 seat Canadair CRJ-700 is the first significant development of its fast selling 50 seat Canadair Regional Jet series. \\n\\nDefinition and development work on the Series 700 commenced in 1995 when Bombardier began consultation with a 15 member airline advisory panel on what the airlines wanted in a 70 seat class regional jet. Prior to its January 1997 formal launch the Series 700 was dubbed the CRJ-X. \\n\\nConstruction of the first prototype Series 700 began in late 1998 and first flight took place in May 1999. The CRJ-700 entered service in February 2001 with French airline Brit Air. \\n\\nCompared with the 50 seat CRJ Series 100/200, the Series 700 is stretched by 4.72m (15ft 6in) with plugs forward and aft of the wing, while the cabin is 6.02m (19ft 9in) longer, aided by moving the rear pressure bulkhead 1.29m (4ft 3in) aft. The cabin windows are raised by 12cm (5in), the cabin floor is lowered slightly and the ceiling raised to provide 1.90m (6ft 3in) headroom, and an underfloor baggage compartment under the forward fuselage is added. Other changes include relocating the APU to the rear fuselage and redesigned overhead stowage bins. \\n\\nThe wing too comes in for attention, with span increased by a 1.83m (6ft 0in) wing root plug, while the leading edge is extended and high lift devices added. The main undercarriage units are lengthened and fitted with new wheels, tyres and brakes. \\n\\nPower is from two FADEC equipped General Electric CF-34-8C1 turbofans (which were selected in February 1995), while the flightdeck is based on that in the earlier CRJs and features six CRT displays presenting information from the Collins Pro Line 4 EFIS avionics suite. \\n\\nLike other Bombardier aircraft, the CRJ Series 700 is the product of a joint manufacturing effort. Canadair manufactures the wing and flightdeck and is responsible for final assembly, Mitsubishi builds the aft fuselage, Shorts is responsible for the fuselage and engine nacelles Avcorp the tail, and Westland the tailcone.", "Dimensions": "Wing span 23.01m (75ft 6in), length 32.41m (106ft 4in), height 7.29m (23ft 11in).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Canadair CRJ 700", "Generation": "", "Height_m": "", "IATA_Code": "CR7", "ICAO_Code": "CRJ7", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Canadair", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "CRJ 700", "Name": "Canadair CL-600 Regional Jet CRJ-700", "Origin": "Canada", "Performance": "High speed cruise 860km/h (464kt), normal cruising speed 818km/h (442kt). Max certificated altitude 41,000ft. Range with 70 passengers and reserves 3152km (1702nm). \\nER variant range with 70 passengers and reserves 3763km (2032nm).", "Powerplant_Desc": "Two 56.4kN (12,670lb) or 61.3kN (13,790lb) with automatic power reserve General Electric CF-34-8C1 turbofans.", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "70 seat regional jet airliner", "Seating_Config": "Flightcrew of two. Typical main cabin seating for 70 passengers at 79cm (31in) pitch and four abreast. Optionally can seat 72 or 78 passengers.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/canadair-cl-600-regional-jet-crj-700/126", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "By early 2011, total CRJ-700 deliveries stood at 310 with 11 on order.", "WTC": "M", "Weights": "Operating empty 19,595kg (43,200lb), standard max takeoff 32,885kg (72,500lb), \\nER max takeoff 34,020kg (75,000lb).", "Wingspan_m": ""}'),
