(50654, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "2J", "Common_Name": "CRJ 1000", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Canadair CRJ 1000", "Generation": "", "Height_m": "", "IATA_Code": "CRK", "ICAO_Code": "CRJX", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Canadair", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "CRJ 1000", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "M", "Weights": "", "Wingspan_m": ""}'),
(50655, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "STOL turboprop regional airliner and utility transport", "Bibliography": "Airliners.net", "Category": "2T", "Common_Name": "212 Aviocar", "Country_Origin": "Spain", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "Initially conceived as a light STOL transport for the Spanish air force, the CASA C212 has found a handy market niche and is highly regarded for its utility in underdeveloped regions. \\n\\nDesigned to replace the Spanish air force''s mixed transport fleet of Douglas C47 Dakotas, CASA Azors and Junkers Ju 52s still in service in the 1960s, the C212 was also developed with the intention of offering a civil variant. Design work began in the late 1960s, the first prototype made the type''s first flight on March 26 1971. Preproduction examples followed, then the type entered air force service in 1974. The first commercial version was delivered in July 1975. \\n\\nThe basic civil version was designated the C212C, the military version the C2125. Production of these models ceased in 1978, CASA switching to the Series 200 with more powerful engines and higher operating weights. The first Series 200, a converted C212C prototype, flew for the first time in its new configuration on April 30 1978. A third development of the Aviocar is the Series 300 which first flew in 1984 and was certificated in late 1987. Improvements to this model are newer engines and winglets. \\n\\nThe latest development is the C212-400, which was launched at the 1997 Paris Airshow (after its first flight on April 4 that year). It features TPE331-12JR engines which maintain their power output to a higher altitude for improved hot and high performance and an EFIS flightdeck.", "Dimensions": "C212C & Series 200 - Wing span 19.00m (62ft 4in), length 15.20m (49ft 11in), height 6.30m (20ft 8in). Wing area 40.0m2 (430.6sq ft). Series 300 - Wing span 20.28m (66ft 7in), length 16.15m (53ft 0in), height 6.60m (21ft 8in). Wing area 41.0m2 (441.3sq ft).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "CASA 212 Aviocar", "Generation": "", "Height_m": "", "IATA_Code": "CS2", "ICAO_Code": "C212", "Length_m": "15.20", "MTOW_kg": "3700", "Manufacturer": "CASA", "Max_Pax": "", "Max_Speed_kmh": "370", "Mission_Type": "Passenger", "Model": "212 Aviocar", "Name": "CASA C212 Aviocar", "Origin": "Spain", "Performance": "C212C - Max speed 370km/h (199kt), max cruising speed 359km/h (194kt), economical cruising speed 315km/h (170kt). Range with max fuel and 1045kg (2303lb) payload 1760km (950nm), range with max payload 480km (258nm). Series 300 - Max operating speed 370km/h (200kt), max cruising speed 354km/h (191kt), economical cruising speed 300km/h (162kt). Range with 25 passengers and reserves at max cruising speed 440km (237nm), with 1700kg (3770lb) payload 1435km (775nm).", "Powerplant_Desc": "C212C - Two 580kW (775shp) Garrett AiResearch (now AlliedSignal) TPE3315251C turboprop engines driving four blade propellers. Series 300 - Two 670kW (900shp) TPE33110R513Cs.", "Powerplants": "C212C - Two 580kW (775shp) Garrett AiResearch (now AlliedSignal) TPE3315251C turboprop engines driving four blade propellers. Series 300 - Two 670kW (900shp) TPE33110R513Cs.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "1760", "Range_nm": "950", "Record_Status": "active", "Role": "STOL turboprop regional airliner and utility transport", "Seating_Config": "Flightcrew of two. Max passenger seating for 26, typical layout for 22 passengers at three abreast. Freighter version can accommodate three LD3 containers or two LD2s or two LD727/DC-8s. Max payload 2700kg (5950lb).", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/casa-c212-aviocar/136", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Max passenger seating for 26, typical layout for 22 passengers at three abreast. Freighter version can accommodate three LD3 containers or two LD2s or two LD727/DC-8s. Max payload 2700kg (5950lb).", "Units_Built": "Over 435 Aviocars of all models built, including 170 for commercial operators and 265 for military customers. IPTN in Indonesia has built over 90 NC212s under licence.", "WTC": "", "Weights": "C212C - Empty 3700kg (8157lb), max takeoff 6300kg (13,890lb). Series 300 - Empty 3780kg (8333lb), operating empty 4560kg (10,053lb), max takeoff 7700kg (16,975lb).", "Wingspan_m": "19.00"}'),
(50656, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "Airliners.net", "Category": "2T", "Common_Name": "CN-235", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The CN235 regional airline and military tactical transport was developed and manufactured jointly by CASA from Spain and IPTN from Indonesia (the latter initially as Nurtanio, and as of October 1985 as Nusantara). A new company Airtech was formed to manage the program, but Airtech was not an aircraft manufacturer and never owned or operated any factories.\\n\\nEach country built one prototype, and these rolled out simultaneously on 10 September 1983. The Spanish prototype flew first, on 11 November 1983, with the Indonesian-built aircraft following on 30 December 1983. Certification by both Spanish and Indonesian authorities and first deliveries (from the Indonesian line) occurred in December 1986. Entry into commercial service was in March 1988. \\n\\nFinal assembly lines for the CN235 are in Spain and Indonesia, but all other construction is not duplicated. CASA is responsible for the centre and forward fuselage, wing centre section and inboard flaps, and engine nacelles. IPTN builds outer wings and flaps, ailerons, the rear fuselage and the tail unit. \\n\\nThe initial production CN235-10 was soon replaced by the CASA-built CN235-100 and IPTN''s CN235-110, incorporating CT7-9C engines in place of CT7-7As, and new composite engine nacelles. Further improvements led to the CASA CN235-200 and similar IPTN CN235-220 with increased operating weights, better field performance and greater range, with structural improvements and improved leading edge flaps and rudder. The CN235-220 was certificated in March 1992. CASA and IPTN now develop their own CN235 variants independently. \\n\\nOther variants on the CN235 theme are the CN235 QC quick change capable of carrying passengers or freight or both; IPTN''s CN235 MPA maritime patrol aircraft and CASA''s CN235MP Persuader (which while primarily aimed at military customers, have customs and boarder patrol applications); and the widely ordered CN235 M multirole military freighter. CASA later developed the stretched C-295, primarily for military use. \\n\\nThe CN235 has succeeded in achieving only a small number of commercial orders, mostly from Indonesian and Spanish operators. In contrast the CN235''s spacious interior and rear loading ramp has helped it win a significant number of military orders.", "Dimensions": "Wing span 25.81m (84ft 8in), length 21.40m (70ft 3in), height 8.18m (26ft 10in). Wing area 59.1m2 (636.17sq ft).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Airtech CN-235", "Generation": "", "Height_m": "", "IATA_Code": "CS5", "ICAO_Code": "CN35", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Airtech", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "CN-235", "Name": "CASA/IPTN CN235", "Origin": "Spain and Indonesia", "Performance": "CN235-100 - Max speed 509km/h (275kt), max cruising speed 454km/h (245kt). Initial rate of climb at sea level 1780ft/min. Range with max payload and reserves at 18,000ft 796km (430nm).", "Powerplant_Desc": "Two 1395kW (1870shp) General Electric CT7-9C turboprops, driving four blade constant speed Hamilton Standard propellers.", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "Utility transport and 45 seat regional airliner", "Seating_Config": "Flightcrew of two. Passenger accommodation in airliner version for 45 four abreast. Quick change convertibles can carry mixtures of passengers and LD2 or LD3 containers. Cargo version can carry four LD3s or five LD2s or palletised freight.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/casaiptn-cn235/137", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "Out of total orders for 230 CN235s, 47 have been for civil customers. Over 30 are currently in airline service.", "WTC": "", "Weights": "CN235-100 - Operating empty 9800kg (21,605lb), max takeoff 15,100kg (33,290lb).", "Wingspan_m": ""}'),
