(50663, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "2T", "Common_Name": "Do 328", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "2", "Engine_Type": "Turboprop", "First_Flight_Year": "", "Full_Designation": "Dornier Do 328", "Generation": "", "Height_m": "", "IATA_Code": "D38", "ICAO_Code": "D328", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Dornier", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "Do 328", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "M", "Weights": "", "Wingspan_m": ""}'),
(50664, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Short range airliner and utility transport", "Bibliography": "Airliners.net", "Category": "2P", "Common_Name": "DC-3", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "No greater accolade for the DC-3 exists than the fact that over six decades after its first flight more than 400 remain in commercial service worldwide. Durability, longevity and profitability are but three of this outstanding aircraft''s virtues. <p>Development of the DC-3 traces back to the earlier oneoff Douglas Commercial 1 (DC1) and subsequent DC2 which made their first flights in 1933 and 1934 respectively. In 1934 American Airlines requested that Douglas develop a larger more capable version of the DC2 for transcontinental US sleeper flights. The resulting DC-3 (or DST - Douglas Sleeper Transport as it then was) flew for the first time on December 17 1935. <p>An almost instant sales success, the DC-3 became the mainstay of the US domestic airline network in the years prior to World War 2. Aside from passenger comfort and appeal, the DC-3 offered that most important of virtues, profitability, with the result that over 400 had been sold to airlines prior to late 1941. <p>The entry of the United States into WW2 in December 1941 had a profound effect on the fortunes of the already successful DC-3. The US Army Air Force''s requirements for transport aircraft were admirably met by the inproduction DC-3, with the result that as the C47 Skytrain it became the standard USAAF transport during the war. More than 10,000 were built for service with US and allied air arms. <p>After the war many of these aircraft became surplus to requirements and were sold off at bargain prices. The result was that demilitarised C47s became the standard postwar aircraft of almost all the world''s airlines and the backbone of the world airline industry well into the 1950s. Its availability and reliability meant it proved extremely popular. Even today hundreds remain in service. <p>A postwar update of the DC-3, the Super DC-3, involving a stretched airframe and more powerful engines, was commercially unsuccessful. This aircraft first flew in June 1949. A small number were built for the US Navy as the R4D8 and for a US domestic airline, and a few remain in service. <p>", "Dimensions": "Wing span 28.96m (95ft 0in), length 19.66m (64ft 6in), height 5.16m (16ft 12in). Wing area 91.7m2 (987sq ft).", "Engine_Count": "2", "Engine_Type": "Piston", "First_Flight_Year": "", "Full_Designation": "Douglas DC-3", "Generation": "", "Height_m": "", "IATA_Code": "DC3", "ICAO_Code": "DC3", "Length_m": "19.66", "MTOW_kg": "8030", "Manufacturer": "Douglas", "Max_Pax": "", "Max_Speed_kmh": "346", "Mission_Type": "Passenger", "Model": "DC-3", "Name": "Douglas DC-3", "Origin": "United States of America", "Performance": "Max speed 346km/h (187kt), economical cruising speed 266km/h (143kt). Initial rate of climb 1130ft/min. Range with max fuel 2420km (1307nm), range with max payload 563km (305nm).", "Powerplant_Desc": "Two 895kW (1200hp) Pratt & Whitney R1830S1C3G Twin Wasp 14 cylinder twin row radial piston engines driving three blade variable pitch propellers, or two 895kW (1200hp) Wright SGR1820 Cyclone nine cylinder radials.", "Powerplants": "Two 895kW (1200hp) Pratt & Whitney R1830S1C3G Twin Wasp 14 cylinder twin row radial piston engines driving three blade variable pitch propellers, or two 895kW (1200hp) Wright SGR1820 Cyclone nine cylinder radials.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "2420", "Range_nm": "1307", "Record_Status": "active", "Role": "Short range airliner and utility transport", "Seating_Config": "Flightcrew of two. Seating for between 28 and 32 passengers at four abreast or 21 three abreast.", "Service_Ceiling_ft": "1130", "Source_URL": "https://www.airliners.net/aircraft-data/douglas-dc-3/188", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Seating for between 28 and 32 passengers at four abreast or 21 three abreast.", "Units_Built": "10,655 built in the USA, including 430 for commercial operators prior to US entry to WW2. 2000 or so built in Russia under licence. More than 400 remain in commercial service in 1998.", "WTC": "", "Weights": "Typical operating empty 8030kg (17,720lb), max takeoff 12,700kg (28,000lb).", "Wingspan_m": "28.96"}'),
