(50666, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "2T", "Common_Name": "Havilland Canada-Bombardier DHC-8-400 Dash 8Q", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "2", "Engine_Type": "Turboprop", "First_Flight_Year": "", "Full_Designation": "De Havilland Canada-Bombardier DHC-8-400 Dash 8Q", "Generation": "", "Height_m": "", "IATA_Code": "DH4", "ICAO_Code": "DH8D", "Length_m": "", "MTOW_kg": "", "Manufacturer": "De", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "Havilland Canada-Bombardier DHC-8-400 Dash 8Q", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "M", "Weights": "", "Wingspan_m": ""}'),
(50667, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "Airliners.net", "Category": "4P", "Common_Name": "DC6A/B", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "While the DC-3''s and DC-4''s civilian careers were interrupted by WW2, the opposite applies to the DC-6, which started off in response to a military airlift requirement, and went on to become Douglas'' most successful four engined piston airliner. \\n\\nDuring the latter stages of WW2 Douglas began work on a developed DC-4 for postwar commercial use. However the improved DC-4 (which would feature a 2.11m/6ft 11in fuselage stretch and P&W R-2800 Double Wasp engines) soon attracted the attention of the US Army Air Force, which devised a requirement which the new transport was developed against. A prototype was built, designated XC-112, but it did not fly until February 15 1946, by which time the war was over and the military requirement no longer stood.\\n\\nInstead Douglas continued development of the type as a long range airliner, resulting in the DC-6. The XC-112 served as the prototype for the DC-6 program. US airlines had already shown strong interest in the new transport, with launch orders for the DC-6 placed in September 1944. The first production DC-6 first flew in June 1946 and service entry, with United Air Lines, occurred on April 27 1947. However early service was not smooth with the fleet grounded for four months from November that year after two internal fuselage fires in flight, one being fatal, caused by fuel venting entering the cabin heater ram air intake. \\n\\nThe availability of the more powerful R-2800 engines with water/methanol injection prompted Douglas to develop the further stretched DC-6A Liftmaster freighter (first flight September 29 1949) and the equivalent passenger DC-6B (first flight February 2 1951). The DC-6C, the last DC-6 model to be developed, was a convertible passenger/freight version of the DC-6A.\\n\\nMeanwhile renewed military interest in the DC-6 was sparked by the Korean War, with the result that large numbers of USAF C-118s and USN R6D-1s were built. Many of these were later sold to civilian operators.", "Dimensions": "DC-6 - Wing span 35.81m (117ft 6in), length 30.66m (100ft 7in), height 8.66m (28ft 5in). Wing area 135.9m2 (1463sq ft).\\nDC-6B - Same except length 32.18m (105ft 7in).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Douglas DC6A/B", "Generation": "", "Height_m": "", "IATA_Code": "DC6", "ICAO_Code": "DC6", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Douglas", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "DC6A/B", "Name": "Douglas DC-6", "Origin": "United States of America", "Performance": "DC-6 - Cruising speed 501km/h (270kt). Initial rate of climb 1070ft/min. Max range 7376km (3983nm). \\nDC-6B - Cruising speed 507km/h (274kt). Service ceiling 25,000ft. Range with max payload 4835km (2610nm), range with max fuel 7595km (4100nm).", "Powerplant_Desc": "DC-6 - Four 1340kW (1800hp) Pratt & Whitney Double Wasp R-2800-CA15 18 cylinder twin row radial piston engines (with a maximum output rating of 1790kW (2400hp) with water injection) driving three blade constant speed Hamilton Standard propellers. \\nDC-6B - Four 1685kW (2500hp) R-2800-CB17s.", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "Piston engined airliner and freighter", "Seating_Config": "DC-6 - Flightcrew of three or four. Passenger accommodation typically for between 48 to 56, but most aircraft now usually equipped to carry freight. \\nDC-6B - Typical passenger seating for 54, with max seating for 102, but now usually configured for freight.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/douglas-dc-6/190", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "Total DC-6 production of 665, comprising 174 DC-6s, 73 DC-6As, 288 DC-6Bs, 105 C-118s and 25 R6Ds. Approximately 100 remained in service in 2003.", "WTC": "", "Weights": "DC-6 - Empty 23,840kg (52,567lb), max takeoff 44,129kg (97,200lb). \\nDC-6B - Empty 25,110kg (55,357lb), max takeoff 48,534kg (107,000lb).", "Wingspan_m": ""}'),
