(50676, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Large transcontinental range corporate jet", "Bibliography": "Airliners.net", "Category": "3J", "Common_Name": "Falcon 900/900B/900C/900DX/900EX/EASY", "Country_Origin": "France", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The Falcon 900 intercontinental range trijet is a substantially revised development of the Falcon 50. \\n\\nDassault announced it was developing a new intercontinental range large size business jet based on the Falcon 50 on May 27 1983 at the Paris Airshow. The prototype, \\"Spirit of Lafayette\\", flew for the first time on September 21 1984. A second prototype flew on August 30 1985, and this aircraft demonstrated the type''s long range potential by flying nonstop from Paris to Little Rock, Arkansas in the USA for a demonstration tour. French certification was awarded on March 14 1986, FAA certification followed on March 21, and first customer deliveries occurred in December that year. \\n\\nWhile of similar overall configuration to the Falcon 50, the Falcon 900 intoduced an all new wider and longer fuselage which can seat three passengers abreast. The main commonality with the Falcon 50 is the wing, which despite being designed for a considerably lighter aircraft, was adapted almost directly unchanged. In designing the Falcon 900 Dassault made use of computer aided modelling, while the aircraft''s structure incorporates a degree of composite materials. \\n\\nTwo Falcon 900s entered service with the Japanese Maritime Safety Agency for the long-range maritime surveillance role as the Falcon 900MSA, equipped with search radar, special communications equipment, observation windows, a control station, and a drop hatch.\\n\\nFrom 1991 the standard production model was the Falcon 900B, which differs from the earlier 900 in having more powerful engines, increased range, the ability to operate from unprepared strips and Category II visibility approach clearance. Earlier production 900s can be retrofitted to 900B standard. \\n\\nThe Falcon 900EX is a longer range development launched in October 1994. It features TFE731-60 engines, a Honeywell Primus 2000 EFIS avionics suite, optional Flight Dynamics head-up displays, increased fuel capacity and greater range. Its first flight was on June 1 1995 and first delivery was in May 1996. \\n\\nThe latest Falcon 900 model is the 900C. Revealed in 1998, the C is a development of the B but incorporates the advanced Honeywell Primus avionics of the 900EX, but without autothrottles. The 900C replaced the 900B in the Falcon product line with first deliveries in early 2000.\\n\\nFrom 2003 the 900EX will introduce Dassault''s EASy avionics operating system with four colour displays, cursor control devices and multifunction keyboards.", "Dimensions": "Wing span 19.33m (63ft 5in), length 20.21m (66ft 4in), height 7.55m (24ft 9in). Wing area 49.0m2 (527.43sq ft).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Dassault Falcon 900/900B/900C/900DX/900EX/EASY", "Generation": "", "Height_m": "", "IATA_Code": "DF9", "ICAO_Code": "F900", "Length_m": "20.21", "MTOW_kg": "10255", "Manufacturer": "Dassault", "Max_Pax": "", "Max_Speed_kmh": "927", "Mission_Type": "Passenger", "Model": "Falcon 900/900B/900C/900DX/900EX/EASY", "Name": "Dassault Falcon 900", "Origin": "France", "Performance": "900B - Max cruising speed 927km/h (500kt), economical cruising speed Mach 0.75. Max certificated altitude 51,000ft. Range with 15 passenger and reserves 7116km (3840nm), with eight passengers and reserves at Mach 0.80 7150km (3860nm). \\n900EX - Range with eight passengers at Mach 0.80 8020km (4330nm), at long range cruising speed 8335km (4500nm).", "Powerplant_Desc": "900B - Three 21.1kN (4750lb) AlliedSignal TFE731-5BRs. \\n900EX - Three 22.3kN (5000lb) TFE731-60s.", "Powerplants": "900B - Three 21.1kN (4750lb) AlliedSignal TFE731-5BRs. \\n900EX - Three 22.3kN (5000lb) TFE731-60s.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "7116", "Range_nm": "3840", "Record_Status": "active", "Role": "Large transcontinental range corporate jet", "Seating_Config": "Flightcrew of two. Main passenger cabin seating for between eight and 15 passengers, or up to 18 in a high density configuration.", "Service_Ceiling_ft": "000", "Source_URL": "https://www.airliners.net/aircraft-data/dassault-falcon-900/175", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Main passenger cabin seating for between eight and 15 passengers, or up to 18 in a high density configuration.", "Units_Built": "Over 260 Falcon 900s (including 7 900Cs, 74 900EXs, and 2 900MSAs) delivered by mid 2000.", "WTC": "", "Weights": "900B - Empty equipped 10,255kg (22,611lb), max takeoff 20,640kg (45,500lb). \\n900EX - Empty equipped 10,830kg (23,875lb), max takeoff 21,909kg (48,300lb).", "Wingspan_m": "19.33"}'),
(50677, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Piston engined airliner and freighter", "Bibliography": "Airliners.net", "Category": "4P", "Common_Name": "DC-4", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The history of the DC-4 dates back to when United Airlines devised a requirement for a four engine long range airliner. <p>United looked to Douglas to fulfil the requirement, who devised the highly ambitious DC-4E (where the E stood for experimental). This four engined behemoth was flight tested in 1939. It was roughly three times the size of the DC-3 (its wingspan was 42.17m/138ft 3in, and length 29.76m/97ft 7in), had triple tail surfaces, tricycle undercarriage, was pressurised and potentially could fly nonstop from Chicago to San Francisco. <p>However all the ground breaking new technology on the DC-4E meant that it was costly, complex and had higher than anticipated operating costs, so Douglas thoroughly revised the design, resulting in the smaller and simpler definitive DC-4. <p>The new DC-4 was developed under the darkening clouds of WW2, and upon the USA''s entry into war all DC-4s then on the production line were requisitioned for the US military. The result was that the first DC-4 flew for the first time on February 14 1942 in military markings (as the C-54 Skymaster). The DC-4 was found to admirably suit the USAAF''s requirement for a long range cargo transport, and 1162 were built through the war years. <p>As was the case with the DC-3, the end of war meant that much of that number were surplus and sold to the world''s airlines. Further to this Douglas built an additional 78 DC-4s to new orders. Over the years the survivors have been passed down to charter and freight airlines, and today small numbers survive in service as freighters. <p>Notable developments of the DC-4 include Aviation Trader''s much modified Carvair freighter (described separately) while Canadair built a number with RollsRoyce Merlin engines and pressurised fuselages. The DC-4 also formed the basis for the larger DC-6 and DC-7 which are described separately (the DC-4 was the first airliner to introduce a circular section, constant diameter fuselage which made stretching the basic aircraft relatively simple). <p>", "Dimensions": "Wing span 35.81m (117ft 6in), length 28.60m (93ft 10in), height 8.38m (27ft 6in). Wing area 135.6m2 (1460sq ft).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Douglas DC-4", "Generation": "", "Height_m": "", "IATA_Code": "DC4", "ICAO_Code": "DC4", "Length_m": "28.60", "MTOW_kg": "19460", "Manufacturer": "Douglas", "Max_Pax": "", "Max_Speed_kmh": "451", "Mission_Type": "Passenger", "Model": "DC-4", "Name": "Douglas DC-4", "Origin": "United States of America", "Performance": "Max speed 451km/h (244kt), cruising speed 365km/h (197kt). Service ceiling 22,300ft. Range with a 5200kg (11,440lb) payload 4023km (2172nm).", "Powerplant_Desc": "Four 1080kW (1450shp) Pratt & Whitney R20002SDBG Twin Wasp 14 cylinder twin row radial piston engines driving three blade constant speed propellers.", "Powerplants": "Four 1080kW (1450shp) Pratt & Whitney R20002SDBG Twin Wasp 14 cylinder twin row radial piston engines driving three blade constant speed propellers.", "Production_Count": "", "Production_Status": "active", "Range_km": "4023", "Range_nm": "2172", "Record_Status": "active", "Role": "Piston engined airliner and freighter", "Seating_Config": "Flightcrew of three, standard passenger seating for 44, max seating for 86. Most surviving aircraft configured as freighters.", "Service_Ceiling_ft": "300", "Source_URL": "https://www.airliners.net/aircraft-data/douglas-dc-4/189", "Status": "In Service", "Typical_Capacity": "Flightcrew of three, standard passenger seating for 44, max seating for 86. Most surviving aircraft configured as freighters.", "Units_Built": "Total DC-4 production comprised one DC-4E, 78 commercial DC-4s, 1162 military C54 Skymasters and 42 Canadair developed Merlin powered derivatives. Almost 80 remain in commercial service, most as freighters.", "WTC": "", "Weights": "Empty 19,460kg (43,300lb), max takeoff 33,112kg (73,000lb).", "Wingspan_m": "35.81"}'),
(50678, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "2J", "Common_Name": "Falcon 10/100", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Dassault Falcon 10/100", "Generation": "", "Height_m": "", "IATA_Code": "DF1", "ICAO_Code": "FA10", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Dassault", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "Falcon 10/100", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "", "Weights": "", "Wingspan_m": ""}'),
