(50688, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "14 seat commuter airliner", "Bibliography": "", "Category": "4P", "Common_Name": "Havilland DH.114 Heron", "Country_Origin": "United Kingdom", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "De Havilland DH.114 Heron", "Generation": "", "Height_m": "", "IATA_Code": "DHH", "ICAO_Code": "HERN", "Length_m": "14.80", "MTOW_kg": "3848", "Manufacturer": "De", "Max_Pax": "", "Max_Speed_kmh": "307", "Mission_Type": "Passenger", "Model": "Havilland DH.114 Heron", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "Series 2 - Four 185kW (250hp) de Havilland (later Bristol Siddeley) Gipsy Queen 30 Mk 2 six cylinder inline piston engines driving two blade de Havilland constant speed propellers. Series 2E/A1 - Four 215kW (290hp) Lycoming IO540B1A5 flat six piston engines driving three blade constant speed props.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "2873", "Range_nm": "1550", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "1075", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Typical main cabin seating for 14 at two abreast with a central aisle. Alternative seating for 15 or 17. Executive versions with seating for eight.", "Units_Built": "", "WTC": "", "Weights": "", "Wingspan_m": "21.80"}'),
(50689, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "1T", "Common_Name": "Havilland Canada DHC-3 Turbo Otter", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "De Havilland Canada DHC-3 Turbo Otter", "Generation": "", "Height_m": "", "IATA_Code": "DHL", "ICAO_Code": "DH3T", "Length_m": "", "MTOW_kg": "", "Manufacturer": "De", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "Havilland Canada DHC-3 Turbo Otter", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "", "Weights": "", "Wingspan_m": ""}'),
(50690, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "Airliners.net", "Category": "1P", "Common_Name": "Havilland Canada DHC-2 Beaver", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "De Havilland Canada''s first purpose designed bush aircraft, the Beaver was that company''s most successful program sales wise (both military or civil), with almost 1700 built in a production run lasting two decades. <p>Beaver development work began in 1946 and the Ontario Department of Lands and Forests had considerable input into the final design and configuration of this rugged and versatile utility. A prototype flew on August 16 1947, with seating for five or six, although the production Beaver grew slightly to seat an extra two passengers by the time civil certification was awarded in March 1948. <p>The only major development of the Beaver (aside from a one off powered by a 410kW/550hp Alvis Leonides 502/4 radial engine) was the Turbo Beaver. First flown in December 1963 it featured a Pratt & Whitney PT6A6 turboprop, which offered lower empty and higher takeoff weights, and even better STOL performance. The Turbo Beaver''s cabin was also longer, allowing maximum accommodation for 11, including the pilot. Externally, the Turbo Beaver had a much longer and reprofiled nose, and squared off vertical tail. DHC also offered conversion kits enabling piston powered Beavers to be upgraded to Turbo standard. Other conversions have been performed. <p>", "Dimensions": "Mk I - Wing span 14.63m (48ft 0in), length 9.25m (30ft 4in), height 2.75m (9ft 0in). Wing area 23.1m2 (250sq ft). Mk I - seaplane - Same except for length 9.98m (32ft 9in), height 3.18m (10ft 5in). Mk III - Same as Mk I except for length 10.74m (35ft 3in).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "De Havilland Canada DHC-2 Beaver", "Generation": "", "Height_m": "", "IATA_Code": "DHP", "ICAO_Code": "DHC2", "Length_m": "", "MTOW_kg": "", "Manufacturer": "De", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "Havilland Canada DHC-2 Beaver", "Name": "De Havilland Canada DHC2 Beaver", "Origin": "Canada", "Performance": "Mk I - Max speed 225km/h (121kt), max cruising speed 217km/h (117kt), normal cruising speed 201km/h (109kt). Initial rate of climb 1020ft/min. Service ceiling 18,000ft. Max range with reserves 1252km (676nm). Mk III - Max speed 274km/h (148kt), max cruising speed 253km/h (137kt), long range cruising speed 225km/h (122kt). Initial rate of climb 1185ft/min. Service ceiling 20,000ft. Max range with reserves 1090km (588nm).", "Powerplant_Desc": "Mk I - One 335kW (450hp) Pratt & Whitney R985 Wasp Junior nine cylinder radial piston engine driving a two blade variable pitch Hamilton Standard propeller. Mk III - One 430kW (578eshp) Pratt & Whitney Canada PT6A6 or PT6A20 turboprop driving a three blade constant speed Hartzell propeller.", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "STOL utility transport", "Seating_Config": "Standard seating for eight including the pilot. The `AgBeaver'' is fitted with a 0.99m3 (35cu ft) chemical hopper.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/de-havilland-canada-dhc2-beaver/178", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "1692 Beavers built between 1948 and 1968, including approximately 60 Turbo Beavers. 974 were delivered to the US military and many others delivered to foreign military air arms. Several hundred remain in service with civilian operators.", "WTC": "", "Weights": "Mk I - Empty 1293kg (2850lb), max takeoff 2313kg (5100lb). Mk I seaplane - Operating empty 1506kg (3316lb), max takeoff 2309kg (5090lb). Mk III - Empty 1175kg (2590lb), max takeoff 2436kg (5370lb).", "Wingspan_m": ""}'),
(50691, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "1T", "Common_Name": "Havilland Canada DHC-2 Turbo-Beaver", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "De Havilland Canada DHC-2 Turbo-Beaver", "Generation": "", "Height_m": "", "IATA_Code": "DHR", "ICAO_Code": "DH2T", "Length_m": "", "MTOW_kg": "", "Manufacturer": "De", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "Havilland Canada DHC-2 Turbo-Beaver", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "", "Weights": "", "Wingspan_m": ""}'),
(50692, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "STOL utility transport", "Bibliography": "Airliners.net", "Category": "1P", "Common_Name": "Havilland Canada DHC-3 Otter", "Country_Origin": "Canada", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "Another in de Havilland Canada''s successful line of rugged and useful STOL utility transports, the Otter was conceived to be capable of performing the same roles as the earlier and highly successful Beaver, but was bigger. \\n\\nUsing the same overall configuration of the earlier and highly successful DHC-2 Beaver, the Otter is much larger overall. The Otter began life as the King Beaver, but compared to the Beaver is longer, has greater span wings and is much heavier. Seating in the main cabin is for 10 or 11, whereas the Beaver could seat six. Power is supplied by a 450kW (600hp) Pratt & Whitney R1340 Wasp radial. Like the Beaver the Otter can be fitted with skis and floats. The amphibious floatplane Otter features a unique four unit retractable undercarriage, with the wheels retracting into the floats. \\n\\nDe Havilland Canada began design work on the DHC-3 Otter in January 1951, the company''s design efforts culminating in the type''s first flight on December 12 1951. Canadian certification was awarded in November 1952. \\n\\nDe Havilland Canada demonstrated the Otter to the US Army, and subsequently that service went on to become the largest DHC-3 operator (as the U-1). Other military users included Australia, Canada and India. \\n\\nSmall numbers of Otters were converted to turbine power by Cox Air Services of Alberta, Canada. Changes included a Pratt & Whitney Canada PT6A turboprop, a lower empty weight of 1692kg (3703lb) and a higher maximum speed of 267km/h (144kt). It was called the Cox Turbo Single Otter. A number of other after market PT6 conversions have also been offered. \\n\\nThe Otter found a significant niche as a bush aircraft and today it remains highly sought after.", "Dimensions": "Wing span 17.69m (58ft 0in), length 12.80m (41ft 10in), height 3.83m (12ft 7in), floatplane height 4.57m (15ft 0in). Wing area 34.8m2 (375sq ft).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "De Havilland Canada DHC-3 Otter", "Generation": "", "Height_m": "", "IATA_Code": "DHS", "ICAO_Code": "DHC3", "Length_m": "12.80", "MTOW_kg": "2010", "Manufacturer": "De", "Max_Pax": "", "Max_Speed_kmh": "257", "Mission_Type": "Passenger", "Model": "Havilland Canada DHC-3 Otter", "Name": "De Havilland Canada DHC-3 Otter", "Origin": "Canada", "Performance": "Max speed 257km/h (140kt), economical cruising speed at sea level 195km/h (105kt). Initial rate of climb 850ft/min. Service ceiling 18,800ft. Max range with reserves 1520km (820nm), range with a 950kg (2100lb) payload and reserves 1410km (760nm).", "Powerplant_Desc": "One 447kW (600hp) Pratt & Whitney R1340S1H1G or R1340S3H1G nine cylinder radial piston engine driving a three blade Hamilton Standard constant speed propeller.", "Powerplants": "One 447kW (600hp) Pratt & Whitney R1340S1H1G or R1340S3H1G nine cylinder radial piston engine driving a three blade Hamilton Standard constant speed propeller.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "1520", "Range_nm": "820", "Record_Status": "active", "Role": "STOL utility transport", "Seating_Config": "Flightcrew of one or two. Normal main cabin seating for nine passengers, max seating for 10. As an aerial ambulance can carry six stretchers and four passengers or three stretchers and seven passengers.", "Service_Ceiling_ft": "850", "Source_URL": "https://www.airliners.net/aircraft-data/de-havilland-canada-dhc-3-otter/179", "Status": "In Service", "Typical_Capacity": "Flightcrew of one or two. Normal main cabin seating for nine passengers, max seating for 10. As an aerial ambulance can carry six stretchers and four passengers or three stretchers and seven passengers.", "Units_Built": "A total of 460 Otters built including for military air arms in 11 nations.", "WTC": "", "Weights": "Landplane - Basic operating 2010kg (4431lb), max takeoff 3629kg (8000lb). Floatplane - Basic operating 2219kg (4892lb), max takeoff 3614kg (7967lb).", "Wingspan_m": "17.69"}'),
(50693, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "STOL turboprop regional airliner and utility transport", "Bibliography": "Airliners.net", "Category": "2T", "Common_Name": "Havilland Canada DHC-6 Twin Otter", "Country_Origin": "Canada", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "Still Canada''s most successful commercial aircraft program with more than 800 built, the Twin Otter remains popular for its rugged construction and useful STOL performance. \\n\\nDevelopment of the Twin Otter dates back to January 1964 when De Havilland Canada started design work on a new STOL twin turboprop commuter airliner (seating between 13 and 18) and utility transport. The new aircraft was designated the DHC-6 and prototype construction began in November that year, resulting in the type''s first flight on May 20 1965. After receiving certification in mid 1966, the first Twin Otter entered service with long time De Havilland Canada supporter the Ontario Department of Lands in Canada. \\n\\nThe first production aircraft were Series 100s. Design features included double slotted trailing edge flaps and ailerons that can act in unison to boost STOL performance. Compared with the later Series 200s and 300s, the 100s are distinguishable by their shorter, blunter noses. \\n\\nThe main addition to the Series 200, which was introduced in April 1968, was the extended nose, which, together with a reconfigured storage compartment in the rear cabin, greatly increased baggage stowage area. \\n\\nThe Series 300 was introduced from the 231st production aircraft in 1969. It too featured the lengthened nose, but also introduced more powerful engines, thus allowing a 450kg (1000lb) increase in takeoff weight and a 20 seat interior. Production ceased in late 1988. In addition, six 300S enhanced STOL performance DHC-6-300s were built in the mid 1970s. \\n\\nAll models have been fitted with skis and floats.", "Dimensions": "100 - Wing span 19.81m (65ft 0in), length 15.09m (49ft 6in), height 5.94m (19ft 6in). Wing area 39.0m2 (420sq ft). \\n300 - Same except for length 15.77m (51ft 9in), or 15.09m (49ft 6in) for floatplane variants.", "Engine_Count": "2", "Engine_Type": "Turboprop", "First_Flight_Year": "", "Full_Designation": "De Havilland Canada DHC-6 Twin Otter", "Generation": "", "Height_m": "", "IATA_Code": "DHT", "ICAO_Code": "DHC6", "Length_m": "15.09", "MTOW_kg": "2653", "Manufacturer": "De", "Max_Pax": "", "Max_Speed_kmh": "297", "Mission_Type": "Passenger", "Model": "Havilland Canada DHC-6 Twin Otter", "Name": "De Havilland Canada DHC-6 Twin Otter", "Origin": "Canada", "Performance": "100 - Max cruising speed 297km/h (160kt). Range with max fuel 1427km (771nm), range with 975kg (2150lb) payload 1344km (727nm). \\n300 - Max cruising speed 338km/h (182kt). Initial rate of climb 1600ft/min. Range with 1135kg (2500lb) payload 1297km (700nm), range with a 860kg (1900lb) payload and wing tanks 1705km (920nm).", "Powerplant_Desc": "100 - Two 431kW (578shp) Pratt & Whitney Canada (formerly United Aircraft of Canada) PT6A-20 turboprops driving three blade propellers. \\n300 - Two 460kW (620shp) P&WC PT6A-27s.", "Powerplants": "100 - Two 431kW (578shp) Pratt & Whitney Canada (formerly United Aircraft of Canada) PT6A-20 turboprops driving three blade propellers. \\n300 - Two 460kW (620shp) P&WC PT6A-27s.", "Production_Count": "", "Production_Status": "active", "Range_km": "1427", "Range_nm": "771", "Record_Status": "active", "Role": "STOL turboprop regional airliner and utility transport", "Seating_Config": "Flightcrew of two. Standard regional airliner interior seats 20 at three abreast and 76cm (30in) pitch. Can be configured as an executive transport, freighter, aerial ambulance and survey aircraft.", "Service_Ceiling_ft": "1600", "Source_URL": "https://www.airliners.net/aircraft-data/de-havilland-canada-dhc-6-twin-otter/181", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Standard regional airliner interior seats 20 at three abreast and 76cm (30in) pitch. Can be configured as an executive transport, freighter, aerial ambulance and survey aircraft.", "Units_Built": "Production completed in 1988, and comprised 115 Series 100s, 115 Series 200s and 614 Series 300s.", "WTC": "L", "Weights": "100 - Basic operating empty 2653kg (5850lb), max takeoff 4763kg (10,500lb). \\n300 - Operating empty 3363kg (7415lb), max takeoff 5670kg (12,500lb).", "Wingspan_m": "19.81"}'),
