(50698, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "Airliners.net", "Category": "2T", "Common_Name": "EMB 120 Brasilia", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The Brasilia has proved to be a popular, relatively high speed yet comparatively inexpensive to operate and purchase regional airliner. \\n\\nEmbraer first began design work on a new regional turboprop airliner in the late 1970s when the company studied stretching its EMB121 Xingu corporate turboprop to a 25 seat regional airliner. While this was the first aircraft to bear the EMB120 designation (it was named the Araguia), the production EMB120 is an all new aircraft. Design studies of the definitive EMB120 began in September 1979, first flight of a PW115 powered prototype took place on July 27 1983, and entry into service was in October 1985. \\n\\nVersions of the EMB120 include: the initial production EMB120; the Reduced Takeoff weight EMB120RT; the Extended Range EMB120ER; the EMB120 Cargo freighter; mixed passenger/freight EMB120 Combi; and EMB120 Convertible. Hot and high versions of these models have PW118A engines, which retain their power ratings to a higher altitude. \\n\\nThe current production model is the EMB120ER Advanced, which incorporates a range of external and interior improvements. The fuselage of the EMB120 also forms the basis for the ERJ145 50 seat regional jet.", "Dimensions": "EMB120 - Wing span 19.78m (64ft 11in), length 20.00m (65ft 8in), height 6.35m (20ft 10in). Wing area 39.4m2 (424.42sq ft). EMB120ER - Same except for length 20.07m (65ft 10in).", "Engine_Count": "2", "Engine_Type": "Turboprop", "First_Flight_Year": "", "Full_Designation": "Embraer EMB 120 Brasilia", "Generation": "", "Height_m": "", "IATA_Code": "EM2", "ICAO_Code": "E120", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Embraer", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "EMB 120 Brasilia", "Name": "Embraer EMB120 Brasilia", "Origin": "Brazil", "Performance": "EMB120 - Max cruising speed 555km/h (300kt) with PW118s, or 574km/h (310kt) with PW118As, long range cruising speed 482km/h (260kt). Initial rate of climb 2120ft/min. Service ceiling 30,000ft with PW118s, or 32,000ft with PW118As. Range with max passengers and reserves 1020km (550nm) with PW118s, or 926km (500nm) with PW118As. EMB120ER - Max cruising speed 555km/h (300kt) with PW118s, or 580km/h (313kt) with PW118As, long range cruising speed 500km/h (270kt). Initial rate of climb 2500ft/min. Service ceiling 29,000ft with PW118s, or 32,000ft with PW118As. Range with max pax and reserves 1556km (840nm) with PW118s, or 1500km (810nm) with PW118As.", "Powerplant_Desc": "Two 1340kW (1800shp) Pratt & Whitney Canada PW118 or PW118A turboprops driving four blade Hamilton Standard propellers.", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "30 seat turboprop regional airliner", "Seating_Config": "Flightcrew of two. Standard main cabin seating for 30 at three abreast and 79cm (31in) pitch. Optional passenger seating for 24 or 26 with greater baggage/cargo space. Alternative interior arrangements for executive and cargo roles.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/embraer-emb120-brasilia/196", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "Approximately 350 ordered by late 1998, including a small number of military orders, of which approximately 330 had been delivered.", "WTC": "M", "Weights": "EMB120 - Empty equipped 7100kg (15,655lb), max takeoff 11,500kg (25,353lb). EMB120ER - Empty equipped 7140kg (15,741lb), max takeoff 11,990kg (26,433lb).", "Wingspan_m": ""}'),
(50699, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "Airliners.net", "Category": "2T", "Common_Name": "EMB 110 Bandeirante", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The Embraer EMB-110 Bandeirante, or `Bandit'', remains Embraer''s most successful commercial aircraft program. \\n\\nDesign of the EMB-110 was undertaken in response to a Brazilian Ministry of Aeronautics specification for a general purpose light transport suitable for military and civilian duties. The new design was developed with the assistance of well known French designer Max Holste, and the first of three YC-95 prototypes flew for the first time on October 26 1968. \\n\\nEmbraer (or Empresa Brasilera de Aeronautica SA) was established the following year, and development and production of the C95 became one of the company''s first responsibilities. The first production standard EMB-110 Bandeirante (Portuguese for Pioneer) flew on August 9 1972, and the first entered airline service in April 1973. \\n\\nBandeirante models include the 12 seat transport EMB-110, the aerial photography EMB-110B and maritime patrol EMB-111 for the Brazilian air force; the initial airline version, the 15 seat EMB-110C; the seven seat EMB110E executive transport; 18 seat enlarged EMB-110P; convertible passenger/freight EMB110P1 with larger rear door; the EMB-110PA which replaced the 110P as the standard passenger aircraft from 1983 and introduced dihedral to the tailplane among other minor improvements; the EMB-110P1K and EMB-110K SAR military equivalents to the P1A; the EMB-110P2 commuter with seating for up to 21; the EMB-110P2A which replaced the P2 and introduced the same changes as the P1A; and the EMB-110P1A/41 and EMBP2A/41 versions of the P1A and P2A recertificated to US FAA SFAR41 standards with higher weights. \\n\\nProduction of the Bandeirante ceased in May 1990, the final aircraft being delivered to the Brazilian Air Force. Today the Bandeirante''s virtues of reliability and good operating economics means that it remains popular with its operators.", "Dimensions": "Wing span 15.33m (50ft 3in), length 15.10m (50ft 4in), height 4.92m (16ft 2in). Wing area 29.1m2 (313sq ft).", "Engine_Count": "2", "Engine_Type": "Turboprop", "First_Flight_Year": "", "Full_Designation": "Embraer EMB 110 Bandeirante", "Generation": "", "Height_m": "", "IATA_Code": "EMB", "ICAO_Code": "E110", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Embraer", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "EMB 110 Bandeirante", "Name": "Embraer EMB-110 Bandeirante", "Origin": "Brazil", "Performance": "EMB-110P - Max speed 460km/h (248kt), max cruising speed 417km/h (225kt), economical cruising speed 326km/h (176kt). Initial rate of climb 1788ft/min. Service ceiling 22,500ft. Range at long range cruising speed with reserves 2000km (1080nm). EMB110P2A/41 - Max cruising speed 413km/h (222kt), economical cruising speed 341km/h (184kt). Range with max fuel 1964km (1060nm).", "Powerplant_Desc": "Two 560kW (750shp) Pratt & Whitney Canada PT6A-34 turboprops driving three blade constant speed, reversable Hartzell propellers.", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "15-18 seat turboprop regional airliner", "Seating_Config": "Flightcrew of two. Typical passenger seating for 18 at three abreast, max seating for 21 at 74cm (29in) pitch.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/embraer-emb-110-bandeirante/195", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "500 Bandeirantes built, the last of which were delivered to the Brazilian military in 1990. Over 200 remain in airline service.", "WTC": "L", "Weights": "EMB110P - Empty equipped 3515kg (7751lb), max takeoff 5700kg (12,500lb). EMB110P2A/41 - Operating empty 3590kg (7915lb), max takeoff 5900kg (13,010lb).", "Wingspan_m": ""}'),
(50700, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "2J", "Common_Name": "EMB-500 Phenom 100", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Embraer EMB-500 Phenom 100", "Generation": "", "Height_m": "", "IATA_Code": "EP1", "ICAO_Code": "E50P", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Embraer", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "EMB-500 Phenom 100", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "", "Weights": "", "Wingspan_m": ""}'),
