(50702, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "2J", "Common_Name": "ERJ 140", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Embraer ERJ 140", "Generation": "", "Height_m": "", "IATA_Code": "ERD", "ICAO_Code": "E135", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Embraer", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "ERJ 140", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "", "Weights": "", "Wingspan_m": ""}'),
(50703, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "ERJ 145", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "Despite a chequered early development history, the 50 seat ERJ-145 has become a runaway sales success. \\n\\nEmbraer began working on 50 seat regional jet concepts in the late 1980s. The original EMB-145 (the marketing designation later became ERJ-145) was launched in mid 1989 and would have been a stretched and jet engined EMB-120 Brasilia. Features of this design included a straight wing with winglets and the two turbofans mounted forward of the wing as on most low wing turboprops. This design would have seated 45 to 50 passengers and featured 75% commonality with the Brasilia. In that configuration cruising speed would have been 740km/h (400kt) and range with a 4500kg (9920lb) payload 2500km (1350nm). \\n\\nBut by 1990 Embraer was studying a modified design with less commonality to the Brasilia as wind tunnel testing revealed that the original configuration would not reach its design performance objectives. Changes to this interim design included a mildly swept wing with winglets (wing sweep of 22.3°) and conventional below wing mounted engines. Wind tunnel testing proved that this configuration met design objectives however it had a major drawback in that it would have needed an unusually high undercarriage.\\n\\nThus in late 1991 Embraer froze the ERJ-145 design with rear fuselage mounted engines and T-tail, and no winglets. Other features include Rolls-Royce (Allison) AE-3007A turbofans and a Honeywell Primus 1000 EFIS avionics suite with five colour CRT screens in the flightdeck. The Brasilia''s three abreast fuselage cross section was retained. \\n\\nThe ERJ-145''s first flight took place on August 11 1995 with first deliveries from December 1996 to Continental Express. Continental''s initial order for 25 was a major fillup for the program and opened the floodgates for a number of major sales. \\n\\nEmbraer has developed several versions of the ERJ-145, the initial ERJ-145ER, the higher max takeoff weight longer range ERJ-145LR introduced in 1998 and most recently the ERJ-145XR (Extra Long Range). The 145XR first flew on June 29 2001 and entered service in October 2002. It features uprated yet more fuel efficient 36kN (8110lb) engines, winglets, 24,100kg (53,131lb) max takeoff weight, a max cruising speed of Mach 0.8 (852km/h/460kt) and increased fuel capacity for a 3705km (2000nm) range. The ERJ-145EP and -EU are -ERs with different max takeoff weights, and the ERJ-145LU and -MP are -LRs with different max takeoff weights.\\n\\nOther EMB-145 developments are the AEW&C (Airborne Early Warning and Control) EMB-145SA with an Erieye radar on top of the fuselage (serving with the Brazilian Air Force as R-99A), the EMB-145AEW which is the export variant of the EMB-145SA (for Greece and Mexico), the EMB-145RS, a remote sensing variant (serving with the Brazilian Air Force as the R-99B and with the Mexican Air Force) and the maritime patrol and ASW EMB-145MP/ASW which will serve with the Brazilian Air Force as P-99. The standard EMB-145ER serves as the C-99A in the Brazilian Air Force.\\n\\nSince mid 2004, the ERJ-145 is also assembled in China by Harbin Embraer.\\n\\nThe shorter fuselage ERJ-135 and ERJ-140 and the corporate transport EMB-135BJ Legacy are described separately.", "Dimensions": "Wing span 20.04m (65ft 9in), length 29.87m (98ft 0in), height 6.75m (22ft 2in). Wing area 51.2m2 (550.9sq ft).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Embraer ERJ 145", "Generation": "", "Height_m": "", "IATA_Code": "ER4", "ICAO_Code": "E145", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Embraer", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "ERJ 145", "Name": "Embraer ERJ-145", "Origin": "Brazil", "Performance": "High speed cruising speed 833km/h (450kt). Service ceiling 37,000ft. \\nERJ-145ER - Range with 50 passengers at long range cruising speed 2445km (1320nm).\\nERJ-145LR - Range with 50 passengers at long range cruising speed 2870km (1550nm).", "Powerplant_Desc": "ERJ-145ER - Two 31.3kN (7040lb) Rolls-Royce AE-3007A turbofans.\\nERJ-145LR - Two 33.0kN (7426lb) AE-3007A1s.", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "50 seat regional jet airliner", "Seating_Config": "Flightcrew of two. Standard passenger accommodation for 50 at three abreast and 79cm (31in) pitch. Alternative seating for 48 or 49 with wardrobe fitted.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/embraer-erj-145/198", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "By early 2005 648 EMB-145s had been delivered and 67 more were on order.", "WTC": "M", "Weights": "ERJ-145ER - Operating empty 11,667kg (25,722lb), max takeoff 20,600kg (45,415lb).\\nERJ-145LR - Operating empty 12,007kg (26,470lb), max takeoff 22,000kg (48,500lb).", "Wingspan_m": ""}'),
(50704, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "F28 Fellowship 4000", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The F28 Fellowship jet was developed to complement Fokker''s highly successful F-27 Friendship turboprop. \\n\\nFokker began development of the F28 in 1960 after perceiving a market for a higher performance (ie jet engined) and greater capacity airliner in comparison with the F-27. First details of the F28 were made public in April 1962, and production of the first development aircraft began in 1964. The first of three prototypes flew for the first time on May 9 1967, with certification and first customer delivery both occurring on February 24 1969. \\n\\nThe F28 was developed into a range of models. Initial production was of the Mk 1000, which could typically seat between 55 and 65, and was powered by 43.8kN (9850lb) Spey Mk 55515 turbofans. The Mk 2000 was essentially similar but featured a 2.21m (7ft 3in) fuselage stretch, increasing maximum seating to 79. \\n\\nThe Mks 5000 and 6000 were based on the 1000 and 2000 respectively, but introduced a longer span wing (by 1.49m/4ft 11in) and wing leading edge slats. Neither version attracted serious sales interest, and no 5000s and just two 6000s were built. Another version that did not come to fruition was the Mk 6600, which would have been stretched by a further 2.21m (7ft 3in), allowing for seating for 100 in a high density layout. It was aimed at Japanese airlines. \\n\\nThe final production models were the 3000 and 4000, again based on the 1000 and 2000 respectively. Both introduced a number of improvements, while the addition of two extra above wing emergency exits on the 4000 increased maximum seating to 85. Freight door equipped convertible versions of each model were offered, and are identified by a C suffix.", "Dimensions": "3000 - Wing span 25.07m (82ft 3in), length 27.40m (89ft 11in), height 8.47m (27ft 10in). Wing area 79.0m2 (850sq ft). 4000 - Same except for length 29.61m (97ft 2in).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Fokker F28 Fellowship 4000", "Generation": "", "Height_m": "", "IATA_Code": "F24", "ICAO_Code": "F28", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Fokker", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "F28 Fellowship 4000", "Name": "Fokker F-28 Fellowship", "Origin": "Netherlands", "Performance": "3000 - Max cruising speed 843km/h (455kt), economical cruising speed 678km/h (366kt). Range at high speed cruise with 65 passengers 2743km (1480nm), at long range cruise with 65 passengers 3170km (1710nm). 4000 - Speeds same. Range at high speed cruise with 85 passengers 1900km (1025nm), at long range cruising speed with 85 passengers 2085km (1125nm).", "Powerplant_Desc": "Mk 3000 & 4000 - Two 44.0kN (9900lb) RollsRoyce RB1832 Spey Mk 55515P turbofans.", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "Regional jet airliner", "Seating_Config": "Flightcrew of two. Max seating for 85 at five abreast and 74cm (29in) pitch in Mk 4000, or 65 in Mk 3000. Mk 3000 offered with a 15 seat executive interior.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/fokker-f-28-fellowship/219", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "Total F28 sales of 241, including some military customers. As at late 1998 approx 160 remained in commercial service. Further 10 used as corporate jets.", "WTC": "", "Weights": "3000 - Operating empty 16,965kg (37,400lb), max takeoff 33,110kg (73,000lb). 4000 - Operating empty 17,645kg (38,900lb), max takeoff 33,110kg (73,000lb).", "Wingspan_m": ""}'),
(50705, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Regional airliners", "Bibliography": "Airliners.net", "Category": "2T", "Common_Name": "FH-227", "Country_Origin": "Netherlands", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "Probably the closest to being the fabled DC-3 replacement, the Fokker F-27 Friendship, including the Fairchild built F-27 and FH-227, was built in greater numbers than any other western turboprop airliner. \\n\\nThe Fokker F-27 began life as a 1950 design study known as the P275, a 32 seater powered by two RollsRoyce Dart turboprops. With the aid of Dutch government funding the P275 evolved into the F-27, which first flew on November 24 1955. This original prototype was powered by Dart 507s and would have seated 28, by the time the second prototype had flown (in January 1957) the fuselage length grew to allow seating for 32. \\n\\nBy this stage Fokker had signed an agreement that would see Fairchild build Friendships in the USA. The first aircraft to enter service was in fact a Fairchild built F-27, in September 1958. \\n\\nFairchild F-27s differed from the initial Fokker F-27 Mk 100s in having basic seating for 40, a lengthened nose capable of housing a weather radar, and additional fuel capacity. \\n\\nDevelopments included the Mk 200/F-27A with more powerful engines, Mk 300/F-27B and primarily military Mk 400 Combi versions, the Mk 500 with a 1.50m (4ft 11in) fuselage stretch taking seating to 52, and Mk 600 quick change freight/pax aircraft. \\n\\nFairchild independently developed the stretched FH-227, which appeared almost two years earlier than the Mk 500. The FH-227 featured a 1.83m (6ft 0in) stretch over standard length F-27/F-27s, taking standard seating to 52.", "Dimensions": "Mk 500 - Wing span 29.00m (95ft 2in), length 23.06m (82ft 3in), height 8.71m (28ft 7in). Wing area 70.0m2 (753.5sq ft). FH-227 - Same except length 25.50m (83ft 8in), height 8.41m (27ft 7in).", "Engine_Count": "2", "Engine_Type": "Turboprop", "First_Flight_Year": "", "Full_Designation": "Fairchild-Hiller FH-227", "Generation": "", "Height_m": "", "IATA_Code": "FK7", "ICAO_Code": "F27", "Length_m": "23.06", "MTOW_kg": "12243", "Manufacturer": "Fairchild-Hiller", "Max_Pax": "", "Max_Speed_kmh": "480", "Mission_Type": "Passenger", "Model": "FH-227", "Name": "Fokker F-27 & Fairchild F-27 & FH-227", "Origin": "Netherlands", "Performance": "Mk 500 - Normal cruising speed 480km/h (260kt). Service ceiling 29,500ft. Range with 52 passengers and reserves 1315km (710nm). FH-227 - Max cruising speed 473km/h (255kt), economical cruising speed 435km/h (236kt). Range with max payload 1055km (570nm), range with max fuel 2660km (1440nm).", "Powerplant_Desc": "Mk 200/500/600 - Two 1730kW (2320ehp) RollsRoyce Dart Mk 5367R turboprops driving four blade Dowty Rotol propellers. FH-227E - Two 1715kW (2300shp) Dart 5327Ls.", "Powerplants": "Mk 200/500/600 - Two 1730kW (2320ehp) RollsRoyce Dart Mk 5367R turboprops driving four blade Dowty Rotol propellers. FH-227E - Two 1715kW (2300shp) Dart 5327Ls.", "Production_Count": "", "Production_Status": "active", "Range_km": "1315", "Range_nm": "710", "Record_Status": "active", "Role": "Regional airliners", "Seating_Config": "Flightcrew of two. Seating for 44 at four abreast and 76cm (30in) pitch in original fuselage length versions (Mks 100, 200, 300, 400, 600 & F-27). Standard seating for 52 and max seating for 60 at 72cm (28.5in) pitch in Mk 500. FH-227 seats 52 at 79cm (31in) pitch, or a maximum of 56.", "Service_Ceiling_ft": "500", "Source_URL": "https://www.airliners.net/aircraft-data/fokker-f-27-fairchild-f-27-fh-227/217", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Seating for 44 at four abreast and 76cm (30in) pitch in original fuselage length versions (Mks 100, 200, 300, 400, 600 & F-27). Standard seating for 52 and max seating for 60 at 72cm (28.5in) pitch in Mk 500. FH-227 seats 52 at 79cm (31in) pitch, or a maximum of 56.", "Units_Built": "581 F-27s, 128 F-27s and 78 FH-227s built. Fokker production comprised 85 Mk 100s, 138 Mk 200s, 13 Mk 300s, 218 Mk 400 & 600s, 112 Mk 500s and six F-27MPA Maritimes. 290 Fokker built and 25 Fairchild aircraft in service in late 1998. Additionally, approx 25 used as corporate transports", "WTC": "", "Weights": "Mk 500 - Empty 12,243kg (26,992lb), operating empty 12,684kg (27,964lb), max takeoff 20,410kg (44,996lb). FH-227 - Operating empty 10,398kg (22,923lb), max takeoff 20,639kg (45,500lb).", "Wingspan_m": "29.00"}'),
(50706, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Turboprop regional airliner", "Bibliography": "Airliners.net", "Category": "2T", "Common_Name": "50 Freighter", "Country_Origin": "Netherlands", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The Fokker 50 was the successor to Fokker''s highly successful and long running F-27 Friendship. \\n\\nFokker announced it was developing the 50 seat Fokker 50, together with the 100 seat jet powered Fokker 100, in November 1983. The Fokker 50 is based on the fuselage of the F-27-500 Friendship, but incorporates a number of key design changes. Foremost of the improvements was the new generation Pratt & Whitney Canada PW125 turboprops driving advanced six blade props, giving a 12% higher cruising speed and greater fuel economy, and thus range. Other improvements include new avionics and an EFIS glass cockpit, limited use of composites, small `Foklet'' winglets, and more, squared, main cabin windows. \\n\\nTwo prototypes were built based on F-27 airframes (despite the fact that over 80% of Fokker 50 parts are new or modified), the first flying on December 28 1985. The first production aircraft flew on February 13 1987, certification was granted in May 1987, and first customer delivery, to Lufthansa Cityline, was during August that year. \\n\\nThe basic Fokker 50 production model is the Series 100. With three, instead of four doors, the Series 100 is designated the Series 120. The hot and high optimised Series 300 has more powerful PW127B turboprops, and was announced in 1990. It has higher cruising speeds and better field performance, particularly at altitude. \\n\\nThe only significant development of the Fokker 50 to see the light of day was the Fokker 60 Utility, a stretched utility transport version ordered by the Royal Netherlands Air Force. Fokker built four for the Netherlands air force and looked at offering a passenger variant. The Fokker 60 was stretched by 1.62m (5ft 4in). \\n\\nFokker collapsed due to financial problems on March 15 1996 and the last Fokker 50 was delivered to Ethiopian Airlines in May 1997.", "Dimensions": "Wing span 29.00m (95ft 2in), length 25.25m (82ft 10in), height 8.32m (27ft 4in). Wing area 70.0m2 (753.5sq ft).", "Engine_Count": "2", "Engine_Type": "Turboprop", "First_Flight_Year": "", "Full_Designation": "Fokker 50 Freighter", "Generation": "", "Height_m": "", "IATA_Code": "F5F", "ICAO_Code": "F50", "Length_m": "25.25", "MTOW_kg": "12520", "Manufacturer": "Fokker", "Max_Pax": "", "Max_Speed_kmh": "532", "Mission_Type": "Passenger", "Model": "50 Freighter", "Name": "Fokker 50", "Origin": "Netherlands", "Performance": "Series 100 - Max cruising speed 532km/h (287kt), economical cruising speed 454km/h (245kt). Max operating altitude 25,000ft. Range with 50 passengers and reserves 2055km (1110nm), or 2822km (1524nm) for optional high gross weight version. Series 300 - Typical cruising speed 526km/h (284kt). Range with 50 passengers and reserves at high speed cruise 2033km (1097nm), or 3017km (1628nm) for high gross weight option at long range cruise.", "Powerplant_Desc": "Series 100 - Two 1864kW (2500shp) Pratt & Whitney Canada PW125B turboprops driving six blade Dowty propellers. Series 300 - Two 2050kW (2750shp) PW127Bs.", "Powerplants": "Series 100 - Two 1864kW (2500shp) Pratt & Whitney Canada PW125B turboprops driving six blade Dowty propellers. Series 300 - Two 2050kW (2750shp) PW127Bs.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "2055", "Range_nm": "1110", "Record_Status": "active", "Role": "Turboprop regional airliner", "Seating_Config": "Flightcrew of two. Standard seating for 50 at four abreast and 81cm (32in) pitch. Max high density seating for 58. Available with convertible passenger/freight configurations.", "Service_Ceiling_ft": "000", "Source_URL": "https://www.airliners.net/aircraft-data/fokker-50/218", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Standard seating for 50 at four abreast and 81cm (32in) pitch. Max high density seating for 58. Available with convertible passenger/freight configurations.", "Units_Built": "205 Fokker 50s built. Last machine delivered in May 1997.", "WTC": "", "Weights": "Series 100 & 300 - Operating empty 12,520kg (27,602lb), max takeoff 19,950kg (43,980lb), or optionally 20,820kg (45,900lb).", "Wingspan_m": "29.00"}'),
(50707, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Single engine corporate turboprop", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "70", "Country_Origin": "France", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The versatile Queen Air is Beech''s largest and heaviest piston twin apart from the WW2 era radial powered Beech 18. \\n\\nThe prototype Model 65 Queen Air made its first flight on August 28 1958, with deliveries of production aircraft in late 1960 marking the beginning of a production run that would last almost two decades. This first model combined the wings, undercarriage, Lycoming engines and tail surfaces of the Model E50 Twin Bonanza with a new and substantially larger fuselage. A Queen Air 65 established a new class altitude record of 34,882ft in 1960. \\n\\nMany variants subsequently followed, including the 3630kg (8000lb) max takeoff weight Model 80 with more powerful 285kW (380hp) engines and swept fin and rudder. This model evolved into the A80, the first to be offered as a commuter airliner. Introduced in 1964, the A80 had a redesigned nose and interior, increased wing span and a 227kg (500lb) greater takeoff weight. The pressurised 88 had round windows and the longer wingspan of the A80 and a 3992kg (8800lb) MTOW. \\n\\nThe Model B80 was the last major production model and appeared in 1966. It featured the longer span wing and the 88''s MTOW. The model A65 was essentially a Model 65 with the swept fin and rudder of the Model 80, and entered production in 1967. The Model 70 entered production in 1969, it featured the longer span wings, 3720kg (8200lb) MTOW and 255kW (340hp) engines. Production of the Queen Air ceased in 1977.", "Dimensions": "Wing span 15.32m (50ft 3in), length 10.82m (35ft 6in), height 4.33m (14ft 3in). Wing area 27.3m2 (294sq ft).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Fokker 70", "Generation": "", "Height_m": "", "IATA_Code": "F70", "ICAO_Code": "F70", "Length_m": "10.64", "MTOW_kg": "1860", "Manufacturer": "Fokker", "Max_Pax": "", "Max_Speed_kmh": "555", "Mission_Type": "Passenger", "Model": "70", "Name": "Beech 65/70/80/88 Queen Air", "Origin": "United States of America", "Performance": "65 - Max speed 385km/h (208kt), max cruising speed 344km/h (186kt), long range cruising speed 267km/h (144kt). Range with reserves and standard fuel 1682km (908nm), with optional fuel 2670km (1442nm). B80 - Max speed 400km/h (215kt), max cruising speed 362km/h (195kt), typical cruising speed 335km/h (181kt). Range with reserves 1950km (1053nm).", "Powerplant_Desc": "65 - Two 255kW (340hp) IGSO480A1E6 Lycoming fuel injected supercharged flat six piston engines driving three blade constant speed propellers. B80 - Two 285kW (380hp) Lycoming IGSO540A1D piston engines.", "Powerplants": "One 520kW (700shp) flat rated Pratt & Whitney Canada PT6A-64 turboprop driving a four blade constant speed Hartzell propeller.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "1666", "Range_nm": "900", "Record_Status": "active", "Role": "Utility, light executive transport and commuter airliner", "Seating_Config": "One or two pilots and up to nine passengers in commuter configuration, or six passengers in executive transport role.", "Service_Ceiling_ft": "2380", "Source_URL": "https://www.airliners.net/aircraft-data/beech-65708088-queen-air/65", "Status": "In Service", "Typical_Capacity": "Pilot and one passenger (or copilot) on flightdeck. Main cabin seating for up to five, or typical accommodation for four in a club arrangement. The TBM-700 is also offered as a freighter.", "Units_Built": "1001 Queen Airs of all models built (404 Model 65s & A65s, 42 Model 70s, 510 Model 80s and 45 Model 88s), including U8F Seminoles for the US Army.", "WTC": "M", "Weights": "65 - Empty 2324kg (5123lb), max takeoff 3719kg (8200lb). B80 - Empty 2394kg (5277lb), max takeoff 3992kg (8800lb).", "Wingspan_m": "12.68"}'),
(50708, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "32 seat regional jet airliner", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "328JET", "Country_Origin": "Germany", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The 30 seat Dornier 328 is a modern regional turboprop airliner that offers high cruising speeds and advanced systems. \\n\\nDevelopment of the 328 traces back to Dornier''s mid 1980s market research that indicated there existed a substantial market for regional airliners in the 30 seat class through to 2005. Firm 328 development work began in December 1988, culminating in the first development aircraft''s first flight on December 6 1991. \\n\\nThe 328 was awarded certification in October 1993. First customer deliveries also occurred in October 1993. \\n\\nThe 328 design incorporates an all new fuselage section for three abreast seating (offering more width per passenger than the 727/737) combined with the same basic supercritical wing of the earlier Dornier 228. Clean aerodynamics give the 328 excellent high speed cruise and climb performance. Composite materials are used in a number of areas (particularly the tail) to reduce weight and the blades on the Hartzell props are composite. The flightdeck features a five screen Honeywell Primus 2000 EFIS avionics system, while with heads-up displays the 328 can be qualified for Cat IIIa landings. \\n\\nIndustrial partners on the 328 include Daewoo Heavy Industries (fuselage), Aermacchi (nose), Westland (nacelles) and Israel Aircraft Industries (wing), accounting for 40% of the aircraft''s construction. \\n\\nVariants of the 328 are the initial production standard 328-100, the standard 328-110 with a larger dorsal fin, heavier weights and greater range, the 328-120 with PW119C engines and improved short field performance and the 328-130 with progressive rudder authority reduction with increasing airspeed. \\n\\nAt various times Dornier studied 50 seat stretches of the 328, but all were abandoned. Dornier also studied building a 328 demonstrator powered by hydrogen. The liquid hydrogen fuel would have been stored in two external tanks under the wings and outboard of the engines.\\n\\nThe last 328 was delivered to Air Alps Aviation in Austria in October 1999. The 328JET regional jet development is described separately.\\n\\nFairchild Aerospace acquired 80% of Dornier in early June 1996 to form Fairchild Dornier GmbH, but production of the 328 had stopped already before the Fairchild Dornier name became effective August 8, 2000.", "Dimensions": "Wing span 20.98m (68ft 10in), length 21.22m (69ft 8in), height 7.24m (23ft 9in). Wing area 40.0m2 (430.6sq ft).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Dornier 328JET", "Generation": "", "Height_m": "", "IATA_Code": "FRJ", "ICAO_Code": "J328", "Length_m": "21.28", "MTOW_kg": "9344", "Manufacturer": "Dornier", "Max_Pax": "", "Max_Speed_kmh": "750", "Mission_Type": "Passenger", "Model": "328JET", "Name": "Dornier 328", "Origin": "Germany", "Performance": "328-110 - Max cruising speed 620km/h (335kt). Design cruising altitude 25,000ft or optionally 31,000ft. Range with 30 passengers and reserves at max cruising speed and 25,000ft cruising altitude 1665km (900nm), at 31,000ft 1850km (1000nm).", "Powerplant_Desc": "Two 1625kW (2180shp) takeoff rated Pratt & Whitney Canada PW119B turboprops driving six blade Hartzell propellers.", "Powerplants": "Two 26.9kN (6050lb) Pratt & Whitney Canada PW306B turbofans.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "1370", "Range_nm": "740", "Record_Status": "active", "Role": "30 seat regional turboprop airliner", "Seating_Config": "Flightcrew of two. Typical passenger seating for 30 to 33 at three abreast, max seating for 39 at four abreast.", "Service_Ceiling_ft": "000", "Source_URL": "https://www.airliners.net/aircraft-data/dornier-328/212", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Standard seating for 32 to 34 passengers three abreast at 79cm (31in). \\nEnvoy 3 seats 12 to 14 in a typical corporate configuration, or up to 19.", "Units_Built": "Total 328 production of 112, incl 105 production aircraft. 95 in service in late 2002.", "WTC": "M", "Weights": "328-110 - Operating empty 8920kg (19,665lb), max takeoff 13,990kg (30,842lb).", "Wingspan_m": "20.98"}'),
(50709, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "Airliners.net", "Category": "1P", "Common_Name": "GA8 Airvan", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The GA-8 Airvan is the second all new aircraft design from Australian manufacturer Gippsland Aeronautics, and has been designed as a utility transport to replace the popular Cessna 206/207 series and others such as the de Havilland Canada Beaver. \\n\\nDesign work on the Airvan began in early 1994 and prototype construction commenced soon after. This prototype flew for the first time on March 3 1995 and publicly appeared at the Australian International Airshow and Aerospace Expo at Avalon later that month after having completed just eight flying hours. \\n\\nAt that time Gippsland Aeronautics anticipated that the Airvan could be certificated within 12 months, all being well. Unfortunately the prototype subsequently crashed during spinning trials in February 1996, pushing back somewhat the planned certification and entry into service dates. \\n\\nThe prototype Airvan was powered by a 185kW (250hp) Textron Lycoming O-540 driving a two blade propeller. A second prototype flew in August 1996, powered by a 225kW (300hp) IO-540. This was to be replaced with a 225kW (300hp) IO-580 but production aircraft will have an IO-540-K as detailed above. \\n\\nOther Airvan design feature include its high mounted two spar wing which is based on the unit on the GA-200 ag aircraft, the square sided large volume fuselage with a large sliding freight door on the port side, and fixed landing gear designed for rough field operations. Wiplane floats will be offered as options. \\n\\nFirst customer deliveries are planned for 1999 following Australian and US FAA certification. The Airvan should prove to be a keenly priced competitor to Cessna''s new production 206H, which is expected to cost more and is slightly smaller (seating six rather than eight). Gippsland Aeronautics also sees the Airvan as a worthy replacement for ageing 206/207s and DHC Beavers which have had to soldier on in service due to the lack of a suitable, cost effective replacement type.", "Dimensions": "Wing span 12.37m (40ft 7in), length 8.79m (28ft 10in), height 2.82m (9ft 3in). Wing area 19.3m2 (208.0sq ft).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "GippsAero GA8 Airvan", "Generation": "", "Height_m": "", "IATA_Code": "GA8", "ICAO_Code": "GA8", "Length_m": "", "MTOW_kg": "", "Manufacturer": "GippsAero", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "GA8 Airvan", "Name": "Gippsland GA-8 Airvan", "Origin": "Australia", "Performance": "Max cruising speed 240km/h (130kt), economical cruising speed 222km/h (120kt). Initial rate of climb 750ft/min. Service ceiling 20,000ft. Range with max fuel 1205km (650nm), range with max payload 185km (100nm).", "Powerplant_Desc": "One 225kW (300hp) Textron Lycoming IO-540-KA5 fuel injected flat six driving a three blade constant speed propeller.", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "Eight seat utility light aircraft", "Seating_Config": "Single pilot and passenger side-by-side with up to six passengers in the main cabin behind them. Main cabin can also configured to carry freight.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/gippsland-ga-8-airvan/227", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "Six deliveries expected in 1999. Planned annual production rate of 150 from 2001.", "WTC": "", "Weights": "Empty 862kg (1900lb), max takeoff 1815kg (4000lb).", "Wingspan_m": ""}'),
