(50713, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Eight seat utility amphibian", "Bibliography": "Airliners.net", "Category": "2P", "Common_Name": "G-21 Goose", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The Goose began life in the pre WW2 days as Grumman''s first design intended for civilian use, but most of the type''s production ultimately was against military orders placed during WW2. \\n\\nThe Goose''s first flight occurred in June 1937. Grumman''s already extensive experience in building fighters for the US Navy was reflected in the Goose''s rugged construction, features of which included a braced tailplane and deep two step hull. A retractable undercarriage was another feature. Initial civil production machines were designated the G-21A. \\n\\nThe arrival of WW2 saw the Goose (a name originally bestowed on the aircraft by Britain''s Royal Air Force) enter military service with a number of allied air arms, the largest operator being the US Navy. Military orders from the US, Britain and Canada accounted for much of the Goose''s 300 unit production run. \\n\\nPostwar, surplus Gooses found their way into service with commercial operators worldwide, their unique amphibious capability and rugged construction ensuring their popularity in the coming decades. \\n\\nA number of Gooses have been converted to turboprop power, McKinnon Enterprises (initially based in the US, and then Canada) first fitting Gooses with four 255kW (340hp) Lycoming GSO480 piston engines, and then with two Pratt & Whitney Canada PT6s. Two versions of the latter were developed, the Turboprop Goose and the G-21G TurboGoose which introduced enlarged cabin windows and retractable wingtip floats.", "Dimensions": "G-21A - Wing span 14.95m (49ft 0in), length 11.70m (38ft 4in), height 3.66m (12ft 0in). Wing area 34.8m2 (375sq ft). TurboGoose - Wing span 15.49m (50ft 10in), length 12.06m (39ft 7in). Wing area 35.1m2 (377.6sq ft).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Grumman G-21 Goose", "Generation": "", "Height_m": "", "IATA_Code": "GRG", "ICAO_Code": "G21", "Length_m": "11.70", "MTOW_kg": "2460", "Manufacturer": "Grumman", "Max_Pax": "", "Max_Speed_kmh": "323", "Mission_Type": "Passenger", "Model": "G-21 Goose", "Name": "Grumman G-21 Goose", "Origin": "United States of America", "Performance": "G-21A - Max speed 323km/h (175kt), cruising speed 307km/h (166kt). Initial rate of climb 1300ft/min. Service ceiling 22,000ft. Range with max fuel 1285km (695nm). TurboGoose - Max speed 390km/h (210kt). Service ceiling 20,000ft. Range with standard fuel 2575km (1390nm).", "Powerplant_Desc": "G-21A - Two 335kW (450hp) Pratt & Whitney R985AN6 Wasp nine cylinder piston radial engines driving two blade constant speed propellers. TurboGoose - Two 505kW (680shp) Pratt & Whitney Canada PT6A27 turboprops driving three blade propellers.", "Powerplants": "G-21A - Two 335kW (450hp) Pratt & Whitney R985AN6 Wasp nine cylinder piston radial engines driving two blade constant speed propellers. TurboGoose - Two 505kW (680shp) Pratt & Whitney Canada PT6A27 turboprops driving three blade propellers.", "Production_Count": "", "Production_Status": "active", "Range_km": "1285", "Range_nm": "695", "Record_Status": "active", "Role": "Eight seat utility amphibian", "Seating_Config": "Flightcrew of two. Main cabin passenger seating for six or seven in piston engined Goose, TurboGoose seats up to 12.", "Service_Ceiling_ft": "1300", "Source_URL": "https://www.airliners.net/aircraft-data/grumman-g-21-goose/230", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Main cabin passenger seating for six or seven in piston engined Goose, TurboGoose seats up to 12.", "Units_Built": "Total Goose production exceeded 300 aircraft, most of which were originally delivered to military customers. Production ceased in 1945. Small numbers of radial and turbine powered Gooses remain in service worldwide.", "WTC": "", "Weights": "G-21A - Empty 2460kg (5425lb), max takeoff 3630kg (8000lb). TurboGoose - Empty equipped 3040kg (6700lb), max takeoff weight 5670kg (12,500lb).", "Wingspan_m": "14.95"}'),
(50714, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "2T", "Common_Name": "G-73 Turbo Mallard", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Gulfstream G-73 Turbo Mallard", "Generation": "", "Height_m": "", "IATA_Code": "GRM", "ICAO_Code": "G73T", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Gulfstream", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "G-73 Turbo Mallard", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "", "Weights": "", "Wingspan_m": ""}'),
(50715, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Corporate transport and regional airliner", "Bibliography": "Airliners.net", "Category": "2T", "Common_Name": "G-159 Gulfstream I", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "Grumman developed the Gulfstream I turbine powered executive transport to replace the many hundred war surplus piston twins performing such missions in the mid 1950s. \\n\\nDesign work began in 1956, with first flight of the Gulfstream I prototype occurring on August 14 1958. FAA Type certification was awarded on May 21 1959 and deliveries of production aircraft followed from that June. Notably, the Gulfstream I was the first US twin engined corporate transport to be certificated to cruise at 30,000ft. \\n\\nAs the first in the Gulfstream line, the GI established the basic fuselage cross section that carries through today to the Gulfstream IV and V. Other features were the RollsRoyce Dart turboprops which gave the I good high speed cruise performance and an auxiliary power unit allowing independent operations from remote strips, providing power for the air conditioning and electrical systems prior to engine start. \\n\\nWhile primarily designed as a corporate transport, a large number of the standard fuselage Gulfstream Is were also used as commuter airliners, seating up to 24 passengers. Military Gulfstream Is were built for the US Navy (navigator training TC-4s) and US Coast Guard (VIP VC-4s). Production of the standard fuselage I ceased in 1969. \\n\\nIn 1979, by which time Grumman''s design rights were purchased by the newly established Gulfstream American Corporation, Gulfstream began offering stretched airliner conversions of the base GI. These aircraft were stretched by 3.25m (10ft 8in), allowing seating for up to 38 passengers at three abreast. Known as the G-159C Gulfstream IC the first conversion flew on October 25 1979, and production conversions were delivered from November 1980. However, only five were converted.", "Dimensions": "I - Wing span 23.92m (78ft 6in), length 19.43m (63ft 9in), height 6.94m (22ft 9in). Wing area 56.7m2 (610.3sq ft).\\nIC - Same except for length 22.97m (75ft 4in), height 7.01m (23ft 0in).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Gulfstream G-159 Gulfstream I", "Generation": "", "Height_m": "", "IATA_Code": "GRS", "ICAO_Code": "G159", "Length_m": "19.43", "MTOW_kg": "9942", "Manufacturer": "Gulfstream", "Max_Pax": "", "Max_Speed_kmh": "560", "Mission_Type": "Passenger", "Model": "G-159 Gulfstream I", "Name": "Grumman G-159 Gulfstream I", "Origin": "United States of America", "Performance": "I - High speed cruise 560km/h (302kt), economical cruising speed 463km/h (250kt). Range with a 1245kg (2740lb) payload, max fuel and reserves 4087km (2206nm). \\n C - Max cruising speed 555km/h (300kt). Range with max payload 805km (435nm).", "Powerplant_Desc": "Two 1485kW (1990hp) RollsRoyce Dart Mk.5298X or 8E turboprops driving four blade Rotol propellers.", "Powerplants": "Two 1485kW (1990hp) RollsRoyce Dart Mk.5298X or 8E turboprops driving four blade Rotol propellers.", "Production_Count": "", "Production_Status": "active", "Range_km": "4087", "Range_nm": "2206", "Record_Status": "active", "Role": "Corporate transport and regional airliner", "Seating_Config": "I - Flightcrew of two. Typical corporate layouts seat between 10 and 14 passengers. Commuter airliner seating for 19 or high density seating for up to 24. \\nIC - Flightcrew of two. Seating for between 32 and 38 at three abreast.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/grumman-g-159-gulfstream-i/236", "Status": "In Service", "Typical_Capacity": "I - Flightcrew of two. Typical corporate layouts seat between 10 and 14 passengers. Commuter airliner seating for 19 or high density seating for up to 24. \\nIC - Flightcrew of two. Seating for between 32 and 38 at three abreast.", "Units_Built": "200 Gulfstream Is built when production ceased in February 1969 in favour of the jet powered Gulfstream II. Approximately 110 remain in corporate use while a further 48 are in airline service. Five Gulfstream G1C conversions performed. In 1998 two were in use as corporate transports and one as an airliner.", "WTC": "", "Weights": "I - Empty equipped 9942kg (21,900lb), max takeoff 15,935kg (35,100lb). \\nIC - Empty 10,747kg (23,639lb), max takeoff 16,300kg (36,000lb).", "Wingspan_m": "23.92"}'),
(50716, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "Hawker 1000", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The Hawker 1000 was the largest member of the DH/HS/BAe-125/Hawker 800 series of corporate jets. \\n\\nThe Hawker 1000 was based on the smaller Hawker 800, and until 1997 the two types were in production side by side in the famous de Havilland plant in Hatfield. The 1000 differs from the 800 in a number of respects however and features a stretched fuselage. The 1000 is identifiable via its seven main cabin windows per side, whereas the 800 has six, and the 0.84m (2ft 9in) stretch (achieved by small fuselage plugs in front of and behind the wing) allowing an increase in max seating to 15. However as it is optimised for long range intercontinental work, the typical Hawker 1000 configuration seats one less than the smaller Hawker 800. \\n\\nOther important changes include Pratt & Whitney Canada PW-305 turbofans (in place of the AlliedSignal TFE-731 on the Hawker 800), extra fuel in the extended forward wing fairing, new lightweight systems, revised and more efficient cabin interior with increased headroom, EFIS cockpit and certification to the latest US FAR and European JAR requirements. \\n\\nBritish Aerospace launched the BAe-125-1000 program in October 1989. The first BAe-125-1000 development aircraft first flew on June 16 1990, with a second following on November 26 that year. These two were followed by the first production aircraft which participated in an 800 hour flight test development program, culminating in UK certification being granted on October 21 1991 (FAA certification followed on October 31 1991). The first production aircraft was delivered in December 1991. \\n\\nAs is the case with the BAe-125-800, the BAe-125-1000 became the Hawker 1000 from mid 1993 when Raytheon purchased British Aerospace''s Corporate Jets division. However, the 1000 never enjoyed the popularity of the 800 and production ceased in 1997 with the delivery of the 52nd aircraft. \\n\\nThe 1000''s largest customer is Executive Jet Aviation (including the NetJets fractional ownership program), which early 2002 has 27 in service (including 13 of the last 14 built).", "Dimensions": "Wing span 15.66m (51ft 4in), length 16.42m (53ft 10in), height 5.21m (17ft 1in). Wing area 34.8m2 (374.0sq ft).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Hawker-Beechcraft Hawker 1000", "Generation": "", "Height_m": "", "IATA_Code": "H21", "ICAO_Code": "H25C", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Hawker-Beechcraft", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "Hawker 1000", "Name": "Raytheon Hawker 1000", "Origin": "United Kingdom and USA", "Performance": "Max cruising speed 867km/h (468kt), economical cruising speed 745km/h (402kt). Service ceiling 43,000ft. Range with max payload 5750km (3105nm), range with max fuel and NBAA VFR reserves 6205km (3350nm).", "Powerplant_Desc": "Two 23.1kN (5200lb) Pratt & Whitney Canada PW-305 turbofans.", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "Mid size corporate jet", "Seating_Config": "Flightcrew of two. Standard main cabin seating for eight comprising club seating for four at the front of the cabin, a three seat couch and a single seat. Max seating for 15.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/raytheon-hawker-1000/332", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "Production ceased after 52 built.", "WTC": "", "Weights": "Empty 7810kg (17,220lb), max takeoff 14,060kg (31,000lb).", "Wingspan_m": ""}'),
