(50720, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "2T", "Common_Name": "HS.748", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "2", "Engine_Type": "Turboprop", "First_Flight_Year": "", "Full_Designation": "BAe HS.748", "Generation": "", "Height_m": "", "IATA_Code": "HS7", "ICAO_Code": "A748", "Length_m": "", "MTOW_kg": "", "Manufacturer": "BAe", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "HS.748", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "M", "Weights": "", "Wingspan_m": ""}'),
(50721, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Turboprop regional airliner", "Bibliography": "Airliners.net", "Category": "2T", "Common_Name": "IL-114", "Country_Origin": "Russia", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The Ilyushin Il-114 has been designed to fill what could ultimately be a very large requirement to replace ageing fleets of turboprop airliners, including the Antonov An-24, in service on regional routes within Russia and other CIS states. \\n\\nWhile only just entering service now in the late 1990s, Ilyushin finalised the Il-114''s basic design and configuration in 1986. However the first prototype did not fly until March 29 1990. In total, three prototypes were built plus two static test airframes, with the original intention being to achieve certification and service entry in 1993. However the test program was delayed, caused at least in part by the crash of one of the prototypes on takeoff during a test flight in mid 1993. Russian certification was finally awarded on April 26 1997. \\n\\nThe Il-114 is of conventional configuration, but 10% of its structure by weight is of composites and advanced metal alloys, including titanium. It features low noise six blade composite construction propellers, and it can operate from unpaved airfields. \\n\\nThe Il-114 is the basic airliner and forms the basis for a number of developments. The Il-114T is a freighter developed for Uzbekistan Airlines. It is fitted with a 3.31 x 1.78m (10ft 10in x 5ft 10in) freight door in the rear port fuselage and a removable roller floor. \\n\\nThe Il-114M will feature more powerful TV7M117 engines and increased max takeoff weight allowing a payload of 7000kg (15,430lb) to be carried. \\n\\nLike many current Russian airliner programs, a westernised version of the Il-114 is under consideration. This is the Pratt & Whitney Canada PW127 powered Il-114-100 (formerly Il-114PC), which would feature improved fuel economy and range performance \\n\\nThe Il-114P is a military maritime patrol variant while the Il-114FK is designed for elint, reconnaissance and cartographic work and would feature a glazed nose and raised flightdeck.", "Dimensions": "Wing span 30.00m (98ft 5in), length 26.88m (88ft 2in), height 9.32m (30ft 7in). Wing area 81.9m2 (881.6sq ft).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Ilyushin IL-114", "Generation": "", "Height_m": "", "IATA_Code": "I14", "ICAO_Code": "I114", "Length_m": "26.88", "MTOW_kg": "15000", "Manufacturer": "Ilyushin", "Max_Pax": "", "Max_Speed_kmh": "500", "Mission_Type": "Passenger", "Model": "IL-114", "Name": "Ilyushin Il-114", "Origin": "Russia", "Performance": "Max speed 500km/h (270kt), cruising speed 470km/h (254kt). Range with 64 passengers and reserves 1000km (540nm), with a 1500kg (3300lb) payload 4800km (2590nm).", "Powerplant_Desc": "Two 1840kW (2466shp) Klimov TV7117S turboprops driving six blade constant speed SV-34 propellers", "Powerplants": "Two 1840kW (2466shp) Klimov TV7117S turboprops driving six blade constant speed SV-34 propellers", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "1000", "Range_nm": "540", "Record_Status": "active", "Role": "Turboprop regional airliner", "Seating_Config": "Flightcrew of two. Seating for 64 at four abreast and 75cm (30in) pitch.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/ilyushin-il-114/256", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Seating for 64 at four abreast and 75cm (30in) pitch.", "Units_Built": "Original requirement for 350 from various successors to Aeroflot in Russia. Approximately 15 built thus far.", "WTC": "", "Weights": "Operating empty 15,000kg (33,070lb), max takeoff 23,500kg (50,045lb).", "Wingspan_m": "30.00"}'),
(50722, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Long range widebody airliner and freighter", "Bibliography": "Airliners.net", "Category": "4J", "Common_Name": "IL-96", "Country_Origin": "Russia", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "Despite resembling the larger Il-86, the Il-96-300 is essentially a new design, incorporating a number of advanced technologies and new engines aimed at improving on the uncompetitive Il-86. \\n\\nDevelopment of Russia''s second widebody airliner began in the mid 1980s, resulting in the Il-96''s first flight on September 28 1988. Two other flying prototypes were built, as were two airframes to be used for static and ground testing. Commonality in some areas with the Il-86 allowed a 1200 flight hour certification program, resulting in Russian certification being awarded on December 29 1992. The Il-96-300 entered service with Aeroflot Russian International Airlines the following year. \\n\\nThe Il-96-300 is based on the older and larger Il-86, but it features a number of new technologies previously the exclusive domain of modern western built airliners. These include a triplex flybywire flight control system, a six screen EFIS flightdeck (however three flightcrew are retained, and not two as on most modern western designs), some composite construction (including the flaps and main deck floors), and winglets. The modern PS-90 turbofans are designed to comply with ICAO Stage 3 noise limits (something the Il-86 cannot conform to) and the Il-86''s unique lower deck airstair design was deleted. \\n\\nPerhaps the Il-96-300''s greatest claim to fame though is that it forms the basis for the stretched and westernised (with Pratt & Whitney PW-2337s and Collins digital avionics) Il-96M and Il-96T, described separately.", "Dimensions": "Wing span over winglets 60.11m (197ft 3in), length 55.35m (181ft 7in), height 17.55m (57ft 7in). Wing area 391.6m2 (4215.0sq ft).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Ilyushin IL-96", "Generation": "", "Height_m": "", "IATA_Code": "IL9", "ICAO_Code": "IL96", "Length_m": "64.70", "MTOW_kg": "132400", "Manufacturer": "Ilyushin", "Max_Pax": "", "Max_Speed_kmh": "830", "Mission_Type": "Passenger", "Model": "IL-96", "Name": "Ilyushin Il-96-300", "Origin": "Russia", "Performance": "Cruising speed 850 to 900km/h (460 to 485kt). Long range cruising speed M0.78, hi-speed cruising M0.80, max speed M0.84. Range with max payload of 37,5 tonne (82,675lb) and reserves 9000km (4850nm), with 30 tonne (66,140lb) payload 10,000km (5400nm), with 15 tonne (33,070lb) payload 12,000km (6500nm).", "Powerplant_Desc": "Four 160.0kN (35,970lb) Aviadvigatel (Soloviev) PS-90A turbofans.", "Powerplants": "Four 164.6kN (37,000lb) Pratt & Whitney PW2337 turbofans.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "482", "Range_nm": "6195", "Record_Status": "active", "Role": "Long range widebody airliner", "Seating_Config": "Flightcrew of three, comprising two pilots and flight engineer. Basic single class seating for 300 at nine abreast in two cabins. Three class arrangement seats 235 comprising 22 first class at six abreast and 102cm (40in) pitch, 40 business class at eight abreast and 90cm (35in) pitch, and 173 economy class at nine abreast and 87cm (34in) pitch. Forward lower freight hold accommodates six LD3 containers or pallets (9000kg/19,840lb), rear hold accommodates 10 LD3s or pallets (15,000kg/33,070lb).", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/ilyushin-il-96-300/253", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Three class seating for 18 first class passengers at 152cm (60in) pitch, 44 business class at 92cm (36in) pitch and 250 economy class at 86cm (34in) pitch. Two class seating for 85 business class and 250 economy class passengers. Single class seating for 375 passengers in three separated cabins seating 124, 162 and 89. Underfloor freight holds can accommodate up to 32 standard LD3 containers. Il-96T Freighter can carry max payload of 92 tonnes (202,820lb) with international standard containers or pallets.", "Units_Built": "Approximately 15 Il-96-300s have been built, of which six are in service with Aeroflot and three with Domodedovo Civil Aviation Enterprise and others in Russian government service (including one used as a presidential transport).", "WTC": "", "Weights": "Operating empty 121,500kg (267,860lb), max takeoff 250,000kg (551,160lb), max landing 183,000kg (403,450lb), max tankage 150,000liters (39,625gallon).", "Wingspan_m": "60.11"}'),
(50723, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Medium to long range medium capacity airliner", "Bibliography": "Airliners.net", "Category": "4J", "Common_Name": "IL-62", "Country_Origin": "Russia", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The four engined Il-62 was the Soviet Union''s first long range jetliner designed for intercontinental flights such as Moscow to New York nonstop. \\n\\nThe prototype Il-62 was first unveiled in September 1962. Due to the unavailability of the chosen Kuznetsov turbofans this aircraft made the type''s first flight powered by four 75.0kN (16,750lb) Lyulka AL7 turbojets. Other design features of this new jet included a wing sweep of 35°, three section ailerons, double slotted trailing edge flaps, two upper surface spoilers and fixed drooping leading edge extension on the outer two thirds of the wings to combat limited control at low speed, a characteristic of Ttail aircraft. The four engines are rear mounted either side of the fuselage in pairs. Only the outer two engines are fitted with thrust reversers. \\n\\nThe Il-62 did not enter passenger revenue service until March 1967, with its first long range intercontinental service taking place in September 1967 when an example flew from Moscow to Montreal. \\n\\nThe improved Il-62M appeared at the 1971 Paris Airshow and introduced more economical Soloviev D30KU turbofans, increased fuel capacity and modified mechanised cargo holds capable of housing containers. The Il-62M entered service in 1974. \\n\\nThe Il-62MK was announced in 1978. It features an increased max takeoff weight of 167,000kg (368,170lb) which allows a maximum of 195 passengers to be carried. \\n\\nLow rate production of the Il-62 ceased in 1994, although the type remains an important part of many former Soviet airlines'' fleets, including Aeroflot Russian International Airlines.", "Dimensions": "Wing span 43.20m (141ft 9in), length 53.12m (174ft 4in), height 12.35m (40ft 6in). Wing area 279.6m2 (3009sq ft).", "Engine_Count": "4", "Engine_Type": "Turbojet", "First_Flight_Year": "", "Full_Designation": "Ilyushin IL-62", "Generation": "", "Height_m": "", "IATA_Code": "IL6", "ICAO_Code": "IL62", "Length_m": "53.12", "MTOW_kg": "66400", "Manufacturer": "Ilyushin", "Max_Pax": "", "Max_Speed_kmh": "900", "Mission_Type": "Passenger", "Model": "IL-62", "Name": "Ilyushin Il-62", "Origin": "Russia", "Performance": "Il-62 - Cruising speed 820 to 900km/h (440kt to 485kt). Range with max payload and reserves 6700km (3610nm), range with 10 tonne (22,045lb) payload 9200km (4965nm). Il-62M - Speeds same. Range with max payload 7800km (4210nm), range with 10 tonne (22,045lb) payload 10,000km (5400nm).", "Powerplant_Desc": "Il-62 - Four 103.0kN (23,150lb) Kuznetsov NK84 turbofans. Il-62M - Four 107.9kN (24,250lb) Soloviev D30KU turbofans.", "Powerplants": "Il-62 - Four 103.0kN (23,150lb) Kuznetsov NK84 turbofans. Il-62M - Four 107.9kN (24,250lb) Soloviev D30KU turbofans.", "Production_Count": "", "Production_Status": "active", "Range_km": "6700", "Range_nm": "3610", "Record_Status": "active", "Role": "Medium to long range medium capacity airliner", "Seating_Config": "Flightcrew of five comprising two pilots, flight engineer, navigator and radio operator. Max seating for 174 in Il-62M, 186 in Il-62 and 195 in Il-62MK at six abreast in two cabins. Alternative configurations include 114 at five abreast, or 85 first class passengers.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/ilyushin-il-62/250", "Status": "In Service", "Typical_Capacity": "Flightcrew of five comprising two pilots, flight engineer, navigator and radio operator. Max seating for 174 in Il-62M, 186 in Il-62 and 195 in Il-62MK at six abreast in two cabins. Alternative configurations include 114 at five abreast, or 85 first class passengers.", "Units_Built": "Over 250 of all models built, of which over 75 were exported. Low rate production of Il-62M believed to have ceased during 1994. Over 120 remain in service.", "WTC": "H", "Weights": "Il-62 - Empty 66,400kg (146,390lb), operating empty 69,400kg (153,000lb), max takeoff 162,200kg (375,150lb). Il-62M - Operating empty 71,500kg (157,360lb), max takeoff 165,500kg (363,760lb).", "Wingspan_m": "43.20"}'),
(50724, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Medium to long range freighter", "Bibliography": "Airliners.net", "Category": "4J", "Common_Name": "IL-76", "Country_Origin": "Russia", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The Ilyushin Il-76 (which has the NATO reporting name of `Candid'') was developed as a replacement for the turboprop powered Antonov An-12, mainly for military use. \\n\\nDevelopment under the design leadership of G V Novozhilov in the late 1960s resulted in the type''s first flight on March 25 1971. Series production commenced in 1975 and the first examples entered Aeroflot service that year. In the now classic military freighter configuration, the Il-76 features a high mounted wing passing above the fuselage, four engines, Ttail, rear loading ramp and freight doors. \\n\\nThe Il-76 was also designed with short field performance in mind, operating from austere strips. To this end the Il-76 features wide span triple slotted trailing edge flaps, upper surface spoilers and near full span leading edge slats for short field performance, while the aircraft rides on a total of 20 low pressure tyres, the front nose unit featuring four wheels, the main wheel bogies having two rows of four tyres each. Freight handling is largely mechanised, requiring only two freight handlers which can be carried as part of the standard crew complement of seven. \\n\\nCivil versions developed from the basic Il-76 include the Il-76T with additional fuel; the Il-76TD with increased takeoff and payload weights and D30KP2s which retain their power output to higher altitudes; and the Il-76MP firefighter. \\n\\nThe stretched PS90 powered Il-76MF, which first flew on August 1 1995, will be built in Tashkent. Stage 3 compliant, it is primarily intended for the Russian air force. Ilyushin also plans to build a CFM56 powered version of this aircraft.", "Dimensions": "Wing span 50.50m (165ft 8in), length 46.59m (152ft 10in), height 14.76m (48ft 5in). Wing area 300.0m2 (3229.2sq ft). Il-76MF - Same except for length which is approx 53m (174ft).", "Engine_Count": "4", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Ilyushin IL-76", "Generation": "", "Height_m": "", "IATA_Code": "IL7", "ICAO_Code": "IL76", "Length_m": "46.59", "MTOW_kg": "170000", "Manufacturer": "Ilyushin", "Max_Pax": "", "Max_Speed_kmh": "850", "Mission_Type": "Passenger", "Model": "IL-76", "Name": "Ilyushin Il-76", "Origin": "Russia", "Performance": "Il-76T - Max speed 850km/h (460kt), cruising speed 750 to 800km/h (405 to 430kt). Max range with reserves 6700km (3615nm), range with 40 tonne (88,185lb) payload 5000km (2700nm). Il-76TD - Speeds same. Range with max payload 3650km (1970nm), with 20 tonne (44,090lb) payload 7300km (3940nm). Il-76MF - Cruising speed range 750 to 780km/h (405 to 420kt). Range with 40 tonne (88,185lb) payload 5200km (2805nm).", "Powerplant_Desc": "Four 117.7kN (26,455lb) Aviadvigatel (Soloviev) D30KP turbofans. Il-76MF - Four 156.9kN (35,275lb) Aviadvigatel PS90ANs.", "Powerplants": "Four 117.7kN (26,455lb) Aviadvigatel (Soloviev) D30KP turbofans. Il-76MF - Four 156.9kN (35,275lb) Aviadvigatel PS90ANs.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "6700", "Range_nm": "3615", "Record_Status": "active", "Role": "Medium to long range freighter", "Seating_Config": "Flightcrew of five including two pilots, flight engineer, navigator and radio operator, plus two freight handlers. Il-76MP firefighting conversion can carry 44 tonnes (97,000lb) of fire retardant in two tanks.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/ilyushin-il-76/251", "Status": "In Service", "Typical_Capacity": "Flightcrew of five including two pilots, flight engineer, navigator and radio operator, plus two freight handlers. Il-76MP firefighting conversion can carry 44 tonnes (97,000lb) of fire retardant in two tanks.", "Units_Built": "Over 900 Il-76s of all models built, most for the Russian military, but over 300 are in service with Aeroflot and other civilian operators.", "WTC": "H", "Weights": "Il-76T - Max takeoff 170,000kg (374,785lb). Il-76TD - Max takeoff 190,000kg (418,875lb). Il-76MF - Operating empty 101,000kg (222,665lb), max payload 52,000kg (114,640lb), max takeoff 200,000kg (440,925lb).", "Wingspan_m": "50.50"}'),
(50725, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Medium range turboprop airliner", "Bibliography": "Airliners.net", "Category": "4T", "Common_Name": "IL-18", "Country_Origin": "Russia", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The Ilyushin Il-18 enjoyed one of the longest production runs of any turboprop airliner in the world and played a significant role in developing air services in Russia''s remote regions in the 1960s and 1970s. \\n\\nThe Il-18 was developed in response to a mid 1950s Aeroflot requirement for an economical 75 to 100 seat medium range airliner. The prototype Il-18 (named Moskva) was powered by four 2985kW (4000shp) Kuznetsov SN4 turboprops and flew for the first time on July 4 1957. The first Il-18 entered Aeroflot service on April 20 1959. \\n\\nInitial production Il-18s could seat 75 passengers and were powered by the Kuznetsov engines, but only the first 20 aircraft built were so powered before the 2985kW (4000shp) Ivchenko AI20 became the standard powerplant. From there on only minor changes characterised the Il-18''s development life. \\n\\nThe first new production model was the Il-18B which had a reconfigured interior to seat 84 passengers. The Il-18V entered service in 1961. It became the standard Aeroflot version and could seat 90 to 100 passengers, depending on configuration. The Il-18I introduced more powerful 3170kW (4250ehp) AI20Ms, while seating could be increased to 122 in summer with the deletion of the rear coat closet (essential in Russian winters) and fitting extra seats. The Il-18D is similar to the I but has extra fuel capacity with an additional centre section tank. On the Il-18D and Il-18I the APU is in the belly of the fuselage, rather than in the tail. \\n\\nThe Il-18 has the NATO reporting name of `Coot''. Like the Lockheed Electra, the Il-18 also formed the basis of a maritime patrol and anti submarine warfare aircraft, the Il38 `May''. \\n\\nMost Il-18s are now flown by secondary operators on regional routes and on charters as they have been replaced by more modern and efficient jet equipment on primary routes.", "Dimensions": "Wing span 37.40m (122ft 9in), length 35.90m (117ft 9in), height 10.17m (33ft 4in). Wing area 140m2 (1507sq ft).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Ilyushin IL-18", "Generation": "", "Height_m": "", "IATA_Code": "IL8", "ICAO_Code": "IL18", "Length_m": "35.90", "MTOW_kg": "35000", "Manufacturer": "Ilyushin", "Max_Pax": "", "Max_Speed_kmh": "675", "Mission_Type": "Passenger", "Model": "IL-18", "Name": "Ilyushin Il-18", "Origin": "Russia", "Performance": "Max cruising speed 675km/h (365kt), economical cruising speed 625km/h (337kt). Range with max payload and reserves 3700km (1995nm), with max fuel and reserves 6500km (3510nm).", "Powerplant_Desc": "Il-18D - Four 3170kW (4250shp) Ivchenko AI20M turboprops driving four blade constant speed propellers.", "Powerplants": "Il-18D - Four 3170kW (4250shp) Ivchenko AI20M turboprops driving four blade constant speed propellers.", "Production_Count": "", "Production_Status": "active", "Range_km": "3700", "Range_nm": "1995", "Record_Status": "active", "Role": "Medium range turboprop airliner", "Seating_Config": "Flightcrew of five comprising two pilots, flight engineer, navigator and radio operator. Initial Il-18s seated 75, the Il-18B 84, Il-18C 90 to 100, Il-18D and Il-18E 110 or max 122.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/ilyushin-il-18/249", "Status": "In Service", "Typical_Capacity": "Flightcrew of five comprising two pilots, flight engineer, navigator and radio operator. Initial Il-18s seated 75, the Il-18B 84, Il-18C 90 to 100, Il-18D and Il-18E 110 or max 122.", "Units_Built": "Estimated production of over 600 aircraft for civilian operators, all initially delivered to airlines in the former Soviet Union, Eastern Europe, China, Cuba and various client states in Africa and Asia. Approximately 50 remain in service.", "WTC": "", "Weights": "Empty equipped (with 90 seats) 35,000kg (77,160lb), max takeoff 64,000kg (141,095lb).", "Wingspan_m": "37.40"}'),
(50726, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Medium range widebody airliner", "Bibliography": "Airliners.net", "Category": "4J", "Common_Name": "IL-86", "Country_Origin": "Russia", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "Russia''s first widebody airliner, the Il-86 has endured a very chequered career. It has suffered from poor fuel economy, reports of failing to meet its design range, and has been produced in only relatively modest numbers. \\n\\nIl-86 development was announced at the 1971 Paris Airshow. But a protracted development program followed and the first examples did not enter service until almost a decade later in late 1980. Antonov, Tupolev and Ilyushin were all asked to respond to Aeroflot''s requirement for a widebody airliner, with Ilyushin''s design proving successful. \\n\\nThe Il-86 initially was similar in configuration to the narrowbody Il-62, with four rear mounted turbofans and a Ttail. However the same problems that affects most Ttail designs such as poor low speed handling, plus the heavy structural weight needed to support the four engines caused a rethink, resulting in the adoption of a conventional tail and under wing mounted engine configuration. \\n\\nAlthough a conventional design, one unusual feature of the Il-86 is that - where airport aerobridges are not provided - passengers can board the aircraft via airstairs leading to a lower deck baggage stowage area, before climbing a fixed internal staircase to the main passenger cabin. \\n\\nThe Il-86 was first unveiled in prototype form in 1976. The first of two prototypes flew for the first time on December 22 1976, while the first production aircraft flew on October 24 1977. Airline service began in December 1980 (Aeroflot had previously hoped to have it in service in time for the 1980 Moscow Olympic Games). About 100 had been built when production ended in 1994. \\n\\nPlans to equip the Il-86 with CFM International CFM56 turbofans to dramatically improve fuel economy, range and reducing noise levels to within ICAO Stage 3 limits have been discussed at various times, but the cost of such an upgrade has so far has proved prohibitive.", "Dimensions": "Wing span 48.06m (157ft 8in), length 59.94m (195ft 4in), height 15.81m (51ft 10in). Wing area 320m2 (3444sq ft).", "Engine_Count": "4", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Ilyushin IL-86", "Generation": "", "Height_m": "", "IATA_Code": "ILW", "ICAO_Code": "IL86", "Length_m": "59.94", "MTOW_kg": "208000", "Manufacturer": "Ilyushin", "Max_Pax": "", "Max_Speed_kmh": "950", "Mission_Type": "Passenger", "Model": "IL-86", "Name": "Ilyushin Il-86", "Origin": "Russia", "Performance": "Max cruising speed 950km/h (513kt), typical cruising speed between 900km/h (485kt) and 950km/h (513kt). Design range with 40 tonne (88,185lb) payload 3600km (1945nm), with max fuel 4600km (2480nm).", "Powerplant_Desc": "Four 127.5kN (28,660lb) KKBM (Kuznetsov) NK86 turbofans.", "Powerplants": "Four 127.5kN (28,660lb) KKBM (Kuznetsov) NK86 turbofans.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "3600", "Range_nm": "1945", "Record_Status": "active", "Role": "Medium range widebody airliner", "Seating_Config": "Flightcrew of three comprising two pilots and flight engineer, with provision for a navigator. Max seating for 350 at nine abreast. Mixed two class seating for 234 comprising 28 six abreast in forward cabin and 206 eight abreast in other two cabins. Lower deck freight holds can accommodate up to 16 standard LD3 containers if some lower deck carry on baggage racks are omitted.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/ilyushin-il-86/252", "Status": "In Service", "Typical_Capacity": "Flightcrew of three comprising two pilots and flight engineer, with provision for a navigator. Max seating for 350 at nine abreast. Mixed two class seating for 234 comprising 28 six abreast in forward cabin and 206 eight abreast in other two cabins. Lower deck freight holds can accommodate up to 16 standard LD3 containers if some lower deck carry on baggage racks are omitted.", "Units_Built": "103 built (including four military command posts). Appoximately 90 were in service in late 1998, all with Russian and CIS operators and one Chinese airline.", "WTC": "H", "Weights": "Max takeoff 208,000kg (458,560lb).", "Wingspan_m": "48.06"}'),
(50727, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "19 seat regional airliner", "Bibliography": "Airliners.net", "Category": "2T", "Common_Name": "Jetstream 31", "Country_Origin": "United Kingdom", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The successful Jetstream 31 traces its ancestry to the Turboméca Astazou powered Handley Page HP-137 Jetstream 1. \\n\\nThe HP-137 was designed as early ago as 1965, and flew for the first time on August 18 1967. Initial Handley Page production aircraft were powered by 635kW (850hp) Astazou XIVs and named Jetstream 1 (36 built), but deliveries were delayed by excess weight and drag problems. To overcome these problems Handley Page developed the Jetstream 2 with more powerful 800kW (1073shp) Astazou XIVCs. However Handley Page ran into serious financial difficulties in the late 1960s (causing the US Air Force to cancel an order for 10 Garrett TPE331 powered C-10A Jetstreams [3Ms]) and it folded in 1969, bringing to an end development of the more powerful Jetstream 2 and plans to market a civil version of the 3M in the USA. \\n\\nA few unfinished aircraft were completed by Terravia, and development of the Jetstream 2 resumed in 1970 as the Jetstream 200 under the control of the newly formed Jetstream Aircraft in collaboration with Scottish Aviation. Scottish Aviation later assumed overall responsibility for the Jetstream and built a number as navigation and multi-engine trainers for Britain''s military services as the Jetstream T1 and T2. Development continued after Scottish Aviation was merged into British Aerospace in 1977, and work on the Jetstream 31 (or J31) began in 1978. The first flight of the Garrett TPE331 powered Jetstream 31 (a converted HP-137) occurred on March 28 1980. The first production aircraft flew in March 1982, UK certification was granted in June 1982. In British Naval service the J31 is designated the Jetstream T3. \\n\\nSubsequent development led to the Super 31, certificated in October 1988. The Super 31 (or unofficially J32) features uprated engines, higher weights and better performance. The last J31/J32 was built in 1993. \\n\\nSince 1997 British Aerospace Asset Management has been offering for sale or lease the upgraded J32EP (Enhanced Performance). Its minor aerodynamic and drag improvements enhance payload range and hot and high performance.", "Dimensions": "Wing span 15.85m (52ft 0in), length 14.37m (47ft 2in), height 5.37m (17ft 6in). Wing area 25.1m2 (270sq ft).", "Engine_Count": "2", "Engine_Type": "Turboprop", "First_Flight_Year": "", "Full_Designation": "BAe Jetstream 31", "Generation": "", "Height_m": "", "IATA_Code": "J31", "ICAO_Code": "JS31", "Length_m": "14.37", "MTOW_kg": "4360", "Manufacturer": "BAe", "Max_Pax": "", "Max_Speed_kmh": "482", "Mission_Type": "Passenger", "Model": "Jetstream 31", "Name": "British Aerospace Jetstream 31/Super 31", "Origin": "United Kingdom", "Performance": "J31 - Max cruising speed 482km/h (260kt), long range cruising speed 426km/h (230kt). Initial rate of climb 2200ft/min. Range with 19 pax and reserves 1185km (640nm), 1760km (950nm) with 12 pax or 2130km (1150nm) with nine pax. \\nSuper 31 - Max cruising speed 490km/h (264kt), long range cruising speed 452km/h (244kt). Initial rate of climb 2240ft/min. Range with 19 pax and reserves 1192km (643nm).", "Powerplant_Desc": "J31 - Two 700kW (940shp) Garret TPE331-10 turboprops driving four blade constant speed propellers. \\nSuper 31 - Two 760kW (1020shp) TPE331-12UARs.", "Powerplants": "J31 - Two 700kW (940shp) Garret TPE331-10 turboprops driving four blade constant speed propellers. \\nSuper 31 - Two 760kW (1020shp) TPE331-12UARs.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "1185", "Range_nm": "640", "Record_Status": "active", "Role": "19 seat regional airliner", "Seating_Config": "Flightcrew of two. Main cabin seating for up to 19 at three abreast and 79cm (31in) pitch, or 12 passengers in a corporate shuttle configuration, or nine in an executive layout.", "Service_Ceiling_ft": "2200", "Source_URL": "https://www.airliners.net/aircraft-data/british-aerospace-jetstream-31super-31/55", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Main cabin seating for up to 19 at three abreast and 79cm (31in) pitch, or 12 passengers in a corporate shuttle configuration, or nine in an executive layout.", "Units_Built": "Total J31 deliveries of 381, including 161 Super J31s.", "WTC": "L", "Weights": "J31 - Operating empty 4360kg (9613lb), max takeoff 6950kg (15,322lb). \\nSuper 31 - Operating empty 4578kg (10,992lb), max takeoff 7350kg (16,204lb).", "Wingspan_m": "15.85"}'),
(50728, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "2T", "Common_Name": "Jetstream 32", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "2", "Engine_Type": "Turboprop", "First_Flight_Year": "", "Full_Designation": "BAe Jetstream 32", "Generation": "", "Height_m": "", "IATA_Code": "J32", "ICAO_Code": "JS32", "Length_m": "", "MTOW_kg": "", "Manufacturer": "BAe", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "Jetstream 32", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "L", "Weights": "", "Wingspan_m": ""}'),
(50729, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "29 seat regional turboprop airliner", "Bibliography": "Airliners.net", "Category": "2T", "Common_Name": "Jetstream 41", "Country_Origin": "United Kingdom", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The Jetstream 41 is a stretched and modernised development of the 19 seat Jetstream 31, designed to compete in the 29 seat commuter airliner class alongside such types as the Brasilia, Dornier 328 and Saab 340. \\n\\nThe Jetstream 41 (or J41) is based on the J31, but features a 4.88m (16ft) fuselage stretch, consisting of a 2.51m (8ft 3in) plug forward of the wing and a 2.36m (7ft 9in) stretch rear. The increased span wing (with reworked ailerons and flaps) is mounted lower on the fuselage so that it does not carry through the fuselage and interrupt the interior cabin aisle, unlike on the Jetstream 31. Other airframe modifications included a new reprofiled six piece windscreen and extended wing root fairing with greater baggage capacity. More powerful AlliedSignal TPE331 turboprops, mounted in new nacelles with increased ground clearance, drive advanced five blade McCauley propellers. The flightdeck has modern EFIS glass displays. \\n\\nDevelopment work on the J41 was announced in mid 1989, resulting in the type''s first flight on September 25 1991. Three further aircraft were also used in the flight test program, with European JAA certification being awarded on November 23 1992. The first delivery occurred two days later on November 25. \\n\\nFrom mid 1994, all aircraft delivered benefited from various payload and range performance improvements, resulting from uprated engines and a higher maximum takeoff weight. \\n\\nThe J41 was initially known as the BAe Jetstream 41, but BAe''s establishment of a separate Jetstream Aircraft division in mid 1993 saw the name simplified to just Jetstream 41. From January 1996 the J41 became part of the Aero International (Regional) stable, but in May 1997 BAe announced that it was terminating J41 production. \\n\\nField Aircraft of the UK and Pilatus of Switzerland were risk sharing partners, while Gulfstream was to build 200 wingsets.", "Dimensions": "Wing span 18.29m (60ft 0in), length 19.25m (63ft 2in), height 5.74m (18ft 10in). Wing area 32.6m2 (350.8sq ft).", "Engine_Count": "2", "Engine_Type": "Turboprop", "First_Flight_Year": "", "Full_Designation": "BAe Jetstream 41", "Generation": "", "Height_m": "", "IATA_Code": "J41", "ICAO_Code": "JS41", "Length_m": "19.25", "MTOW_kg": "6350", "Manufacturer": "BAe", "Max_Pax": "", "Max_Speed_kmh": "547", "Mission_Type": "Passenger", "Model": "Jetstream 41", "Name": "British Aerospace Jetstream 41", "Origin": "United Kingdom", "Performance": "Max speed 547km/h (295kt), economical cruising speed 482km/h (260kt). Service ceiling 26,000ft. Range (initial production) with 29 passengers and reserves 1263km (681nm), definitive production standard 1433km (774nm).", "Powerplant_Desc": "Two 1120kW (1500shp) AlliedSignal TPE33114GR/HR turboprops driving five blade constant speed McCauley propellers on initial production aircraft, later two 1230kW (1650shp) TPE33114s.", "Powerplants": "Two 1120kW (1500shp) AlliedSignal TPE33114GR/HR turboprops driving five blade constant speed McCauley propellers on initial production aircraft, later two 1230kW (1650shp) TPE33114s.", "Production_Count": "", "Production_Status": "active", "Range_km": "1263", "Range_nm": "681", "Record_Status": "active", "Role": "29 seat regional turboprop airliner", "Seating_Config": "Flightcrew of two. Main cabin seating for up to 29 at three abreast, seating for 27 with galley. Corporate shuttle configured J41s seat 16 at two abreast.", "Service_Ceiling_ft": "000", "Source_URL": "https://www.airliners.net/aircraft-data/british-aerospace-jetstream-41/56", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Main cabin seating for up to 29 at three abreast, seating for 27 with galley. Corporate shuttle configured J41s seat 16 at two abreast.", "Units_Built": "Orders for the Jetstream 41 stood at 100 in May 1997 when BAe announced it was terminating production.", "WTC": "M", "Weights": "Empty 6350kg (14,000lb), max takeoff initial production 10,433kg (23,100lb), definitive max takeoff 10,895kg (24,000lb).", "Wingspan_m": "18.29"}'),
