(50737, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "2J", "Common_Name": "Douglas MD-83", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "McDonnell Douglas MD-83", "Generation": "", "Height_m": "", "IATA_Code": "M83", "ICAO_Code": "MD83", "Length_m": "", "MTOW_kg": "", "Manufacturer": "McDonnell", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "Douglas MD-83", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "M", "Weights": "", "Wingspan_m": ""}'),
(50738, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Short to medium range airliner", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "Douglas MD-81", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The popular MD-80 series is a stretched and improved development of the McDonnell Douglas DC-9. \\n\\nThe origins of the MD-80 lie in 1975 testing where a standard DC-9 was fitted with improved, more efficient, higher bypass ratio JT8D-200 series turbofans. MDC originally proposed fitting the new engines (which meet Stage 3 noise limits) to a development designated the DC-9-55, which would have featured two JT8D-209s and a 3.86m (12ft 8in) stretched fuselage over the 50. \\n\\nInstead MDC developed the DC-9 Super 80 (or DC-9-80), combining the new engines with a further stretched fuselage, increased span wing and other improvements. Launched in October 1977, the Super 80 first flew on October 18 1979. Certification for the initial Super 80 model, the 81, was granted in July 1981. The first customer delivery was to Swissair in September 1980. \\n\\nMcDonnell Douglas renamed the DC-9-80 the MD-80 in 1983. The MD-80 designation however is a generic designation for the series and does not apply to a certain model type. The specific MD-80 models are the initial MD-81, the MD-82 with more powerful JT8D-217s, the extended range MD-83 with extra fuel and more efficient JT8D-219s, and the MD-88 (first flight August 1987) with the JT8D-219s of the MD-83 with an EFIS flightdeck and redesigned cabin interior, with other improvements. The shorter fuselage but longer range MD-87 is described separately under McDonnell Douglas. \\n\\nInitial sales of the Super 80 were slow until American Airlines placed an initial order for 67 MD-82s (with options on 100) in early 1984 (American now operates a fleet of 260 MD-80s), kickstarting what went on to become a highly successful program - the 1000th MD-80 was delivered in March 1992. \\n\\nFollowing the 1997 merger of Boeing and McDonnell Douglas the future of the Douglas airliners were reviewed. In December 1997 Boeing announced its decision to drop the MD-80 and MD-90 once current orders were fulfilled. An April 1998 TWA order for 24 MD-83s will see the MD-80 remain in production until January 2000.", "Dimensions": "Wing span 32.87m (107ft 10in), length 45.06m (147ft 10in), height 9.02m (29ft 7in). Wing area 112.3m2 (1209sq ft).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "McDonnell Douglas MD-81", "Generation": "", "Height_m": "", "IATA_Code": "M81", "ICAO_Code": "MD81", "Length_m": "45.06", "MTOW_kg": "35329", "Manufacturer": "McDonnell", "Max_Pax": "", "Max_Speed_kmh": "925", "Mission_Type": "Passenger", "Model": "Douglas MD-81", "Name": "McDonnell Douglas MD-81/82/83/88", "Origin": "United States of America", "Performance": "MD-81 - Max speed 925km/h (500kt), long range cruising speed 813km/h (440kt). Range with 155 passengers and reserves 2897km (1564nm). \\nMD-88 - Speeds same. Range with 155 passengers and reserves 4850km (2620nm).", "Powerplant_Desc": "MD-81 - Two 82.3kN (18,500lb) Pratt & Whitney JT8D-209 turbofans. \\nMD-88 - Two 93.4kN (21,000lb) JT8D-219s.", "Powerplants": "MD-81 - Two 82.3kN (18,500lb) Pratt & Whitney JT8D-209 turbofans. \\nMD-88 - Two 93.4kN (21,000lb) JT8D-219s.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "2897", "Range_nm": "1564", "Record_Status": "active", "Role": "Short to medium range airliner", "Seating_Config": "Flightcrew of two. Max seating for 172. Typical two class seating for 142, comprising 14 premium and 128 economy class pax.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/mcdonnell-douglas-md-81828388/109", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Max seating for 172. Typical two class seating for 142, comprising 14 premium and 128 economy class pax.", "Units_Built": "Total MD-80 series (inc MD-87) 1191 aircraft, of which 132 MD-81, 569 MD-82, 265 MD-83, 150 MD-88 (and 75 MD-87, see separate entry).", "WTC": "M", "Weights": "MD-81 - Operating empty 35,329kg (77,888lb), max takeoff 63,505kg (140,000lb), or 67,810kg (149,500lb) with JT8D-217As. \\nMD-88 - Operating empty 35,369kg (77,976lb), max takeoff 67,810kg (149,500lb).", "Wingspan_m": "32.87"}'),
(50739, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Short to medium range airliner", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "Douglas MD-87", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The McDonnell Douglas MD-87 is a shortened version of the successful MD-80 series. \\n\\nA reversal of the trend from the DC-9 to the MD-80 series, the MD-87 combines the advanced features introduced on the MD-80 (most notably the Pratt & Whitney JT8D-200 engines) into a 5.3m (17ft 5in) shorter length fuselage similar in length to the DC-9-30. \\n\\nThe MD-87 features the 39.75m (130ft 5in) fuselage length; plus an EFIS flightdeck (the MD-87 was the first aircraft of the MD-80 series to introduce EFIS, with two flight management system controls, displays and cockpit) and an optional Sundstrand Head-Up Display; Pratt & Whitney JT8D-217C turbofans (which are approximately 2% more efficient than the 217A); the cruise performance package improvements introduced on late production MD-80s, including the extended low drag tail cone, fillet fairing between the engine pylons and the fuselage and low drag flap hinge fairings; and increased height fin to compensate for the loss of moment arm due to the shorter fuselage. \\n\\nThe MD-87 was optionally available with extra front and rear cargo compartment auxiliary fuel tanks to extend range, and other engines in the JT8D-200 series. In other respects the MD-87 is essentially identical to the MD-80 series. \\n\\nMcDonnell Douglas launched development of the MD-87 on January 3 1985, following the placement of launch orders from Finnair and Austrian in December 1984. First flight took place on December 4 1986 and US FAA certification was granted on October 21 1987. \\n\\nMD-87 sales were relatively small and mainly to traditional Douglas customers. Notable operators include Iberia (with 24), SAS (18) and Japan Air System (eight). Other operators include e.g. Finnair, Aero Lloyd, Aeromexico, Great American, Austrian, Spanair, Reno Air, and Midway. \\n\\nBy the time Boeing and McDonnell Douglas had merged in 1997 all MD-87 orders had been fulfilled and Boeing no longer actively offers the type.", "Dimensions": "Wing span 32.86m (107ft 10in), length 39.75m (130ft 5in), height 9.30m (30ft 6in). Wing area 112.3m2 (1209.0sq ft).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "McDonnell Douglas MD-87", "Generation": "", "Height_m": "", "IATA_Code": "M87", "ICAO_Code": "MD87", "Length_m": "39.75", "MTOW_kg": "33237", "Manufacturer": "McDonnell", "Max_Pax": "", "Max_Speed_kmh": "925", "Mission_Type": "Passenger", "Model": "Douglas MD-87", "Name": "McDonnell Douglas MD-87", "Origin": "United States of America", "Performance": "Max speed 925km/h (500kt), long range cruising speed 811km/h (438kt). Range with 130 passengers and reserves 4393km (2372nm), or optionally 5248km (2833nm). Range with max fuel 5522km (2980nm), or optionally 6764km (3650nm),", "Powerplant_Desc": "Two 68.9kN (20,000lb) Pratt & Whitney JT8D-217C turbofans. Other JT8D-200 series engines available optionally.", "Powerplants": "Two 68.9kN (20,000lb) Pratt & Whitney JT8D-217C turbofans. Other JT8D-200 series engines available optionally.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "4393", "Range_nm": "2372", "Record_Status": "active", "Role": "Short to medium range airliner", "Seating_Config": "Flightcrew of two. Max single-class seating for 139. Typical two class seating for 109, comprising 12 premium and 97 economy class pax.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/mcdonnell-douglas-md-87/278", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Max single-class seating for 139. Typical two class seating for 109, comprising 12 premium and 97 economy class pax.", "Units_Built": "Of total MD-80 sales of 1191, 75 were for MD-87s.", "WTC": "", "Weights": "Operating empty with standard fuel 33,237kg (73,274lb), operating empty with optional fuel 33,965kg (74,880lb), max takeoff 63,505kg (140,000lb), optionally 67,810kg (149,500lb).", "Wingspan_m": "32.86"}'),
(50740, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "2J", "Common_Name": "Douglas MD88 Freighter", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "McDonnell Douglas MD88 Freighter", "Generation": "", "Height_m": "", "IATA_Code": "M8F", "ICAO_Code": "MD88", "Length_m": "", "MTOW_kg": "", "Manufacturer": "McDonnell", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "Douglas MD88 Freighter", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "", "Weights": "", "Wingspan_m": ""}'),
(50741, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Short to medium range airliner", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "Douglas MD-90", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The MD-90 is the largest member of the Douglas/McDonnell Douglas/Boeing DC-9/MD-80/MD-90/717 family, and is a stretched, IAE V2500 powered development of the MD-80. \\n\\nThe MD-90 program was launched in November 1988, first flight occurred on February 22 1993, and certification was awarded on November 16 1994. Launch customer was Delta, which has 31 on firm order, while other major customers include Saudi Arabian Airlines and Japan Air System. \\n\\nMost important of the changes introduced on the MD-90 are the two V2500 turbofans. At 111kN (25,000lb) thrust on the MD-90-30, the V2500s are the largest, heaviest and most powerful engines to be rear mounted on any airliner yet. More importantly though, the V2500 is highly regarded for its efficiency and fuel economy. \\n\\nOther changes to the MD-90 include the 1.4m (4ft 6in) fuselage stretch forward of the wing, allowing seating for an extra 10 passengers (in a two class arrangement). The stretch is forward of the wing to compensate for the extra weight of the engines. The MD-90 also features an EFIS glass flightdeck based on that in the MD88, and other detail improvements such as a revised passenger interior. \\n\\nThe basic MD-90 model is the MD-90-30 (Chinese built Trunkliners are designated the MD-90-30T and feature double bogey main landing gear). It is also offered in MD-90-30ER extended range form with extra fuel. The MD-90 has also been offered as the 50, a further extended range version with a higher maximum takeoff weight and extra fuel and the MD-90-55 high capacity variant capable of seating 187 in a single class with two extra doors in the forward fuselage to meet emergency evacuation requirements. \\n\\nFollowing the 1997 merger of Boeing and McDonnell Douglas, Boeing decided to cancel MD-90 production once outstanding orders were fulfilled.  The last of 114 US-built Md-90s was completed in 2000.", "Dimensions": "Wing span 32.87m (107ft 10in), length 46.51m (152ft 7in), height 9.33m (30ft 7in). Wing area 112.3m2 (1209.0sq ft).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "McDonnell Douglas MD-90", "Generation": "", "Height_m": "", "IATA_Code": "M90", "ICAO_Code": "MD90", "Length_m": "46.51", "MTOW_kg": "39915", "Manufacturer": "McDonnell", "Max_Pax": "", "Max_Speed_kmh": "809", "Mission_Type": "Passenger", "Model": "Douglas MD-90", "Name": "McDonnell Douglas MD-90", "Origin": "United States of America", "Performance": "MD-90-30 - Typical cruising speed at 35,000ft 809km/h (437kt). Range with 153 passengers 3862km (2085nm), or 4023km (2172nm) for standard -30ER, or 4425km (2389nm) for long range -30ER. MD-90-50 - Range with 153 passengers 5600km (3022nm). MD-90-55 - Range with 187 passengers 5005km (2700nm).", "Powerplant_Desc": "MD-90-30 - Two 111.2kN (25,000lb) International Aero Engines V2525D5 turbofans. MD-90-55 - Two 124.5kN (28,000lb) V2528D5s.", "Powerplants": "MD-90-30 - Two 111.2kN (25,000lb) International Aero Engines V2525D5 turbofans. MD-90-55 - Two 124.5kN (28,000lb) V2528D5s.", "Production_Count": "114", "Production_Status": "active", "Range_km": "3862", "Range_nm": "2085", "Record_Status": "active", "Role": "Short to medium range airliner", "Seating_Config": "Flightcrew of two. Two class seating for 12 premium class and 141 economy class passengers in MD-90-30, or max single class seating for 172. MD-90-55 max single class seating for 187.", "Service_Ceiling_ft": "000", "Source_URL": "https://www.airliners.net/aircraft-data/mcdonnell-douglas-md-90/110", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Two class seating for 12 premium class and 141 economy class passengers in MD-90-30, or max single class seating for 172. MD-90-55 max single class seating for 187.", "Units_Built": "A total of 114 MD-90s were built by McDonnell Douglas/Boeing, with production completed in 2000.  105 were in service in 2002. 3 MD-90-30Ts were built by Shenyang in China under the aborted Trunkliner program.", "WTC": "M", "Weights": "MD-90-30 - Operating empty 39,915kg (88,000lb) max takeoff 70,760kg (156,000lb). MD-90-55 - Operating empty 41,685kg (91,900lb), max takeoff 78,245kg (172,500lb).", "Wingspan_m": "32.87"}'),
(50742, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Five place multi purpose light utility helicopter", "Bibliography": "Airliners.net", "Category": "H", "Common_Name": "Bo 105", "Country_Origin": "Germany", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "In widespread military and civilian service, the BO 105 is MBB''s (now part of Eurocopter) most successful helicopter design. <p>Construction of the first of three prototypes began in 1964, the first of which made the type''s first flight on February 16 1967. This aircraft was powered by 236kW (317shp) Allison 250C18 turboshafts and featured a conventional main rotor hub, but the subsequent prototypes incorporated a new rigid hub with feathering hinges, plus composite blades and MANTurbo 6022 engines. The BO 105 reverted back to Allison 250 power with the second of two preproduction aircraft, flying in this form in January 1971. <p>Initial production was of the BO 105C which was available from 1970. The Allison 250C20 powerplant became standard from 1973. The BO 105 CB was introduced in 1975, and became the standard production model. It introduced uprated engines and a strengthened transmission. The BO 105 is now built in BO 105 CBS form with a slight 25cm (10in) fuselage stretch and extra window, allowing an extra passenger to be carried. <p>The BO 105 D has IFR instrumentation and was developed for the British offshore oil rig support market. The BO 105 L has more powerful engines and higher takeoff weight. The BO 105 LSA-3 is a hot and high version with Allison 250C28C engines and built exclusively in Canada by Eurocopter Canada. The BO 105 LSA-3 Super Lifter has been developed for aerial crane work and has a 2850kg (6283lb) max takeoff weight. <p>The EC Super Five is a high performance development of the BO 105 CBS with new main rotor blades. It was certificated in late 1993. <p>", "Dimensions": "Main rotor diameter 9.84m (32ft 4in), length including rotors 11.86m (38ft 11in), fuselage length 8.81m (28ft 11in), height to top of main rotor mast 3.02m (9ft 11in). Main rotor disc area 76.1m2 (818.6sq ft).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "MBB Bo 105", "Generation": "", "Height_m": "", "IATA_Code": "MBH", "ICAO_Code": "B105", "Length_m": "8.81", "MTOW_kg": "1300", "Manufacturer": "MBB", "Max_Pax": "", "Max_Speed_kmh": "240", "Mission_Type": "Passenger", "Model": "Bo 105", "Name": "Eurocopter BO 105 & EC Super Five", "Origin": "Germany", "Performance": "BO 105 CBS-4 - Max cruising speed 240km/h (129kt), long range cruising speed 204km/h (110kt). Initial rate of climb 1457ft/min. Hovering ceiling out of ground effect 1500ft. Range with standard fuel and max payload 555km (300nm), ferry range with auxiliary fuel tanks 1020km (550nm). Super Five - Max cruising speed 245km/h (132kt). Initial rate of climb 1870ft/min. Hovering ceiling out of ground effect 7960ft. Range 575km (310nm).", "Powerplant_Desc": "BO 105 CBS & Super Five - Two 313kW (420shp) Allison 250C20B turboshafts driving a four blade main rotor and two blade tail rotor.", "Powerplants": "BO 105 CBS & Super Five - Two 313kW (420shp) Allison 250C20B turboshafts driving a four blade main rotor and two blade tail rotor.", "Production_Count": "", "Production_Status": "active", "Range_km": "555", "Range_nm": "300", "Record_Status": "active", "Role": "Five place multi purpose light utility helicopter", "Seating_Config": "Total seating for five, including two pilots or one pilot and passenger in front bucket seats, and three passengers on rear bench seat. Behind rear seats and below the engine is a freight/baggage compartment, accessible by two clamshell doors in the rear of the fuselage.", "Service_Ceiling_ft": "1457", "Source_URL": "https://www.airliners.net/aircraft-data/eurocopter-bo-105-ec-super-five/205", "Status": "In Service", "Typical_Capacity": "Total seating for five, including two pilots or one pilot and passenger in front bucket seats, and three passengers on rear bench seat. Behind rear seats and below the engine is a freight/baggage compartment, accessible by two clamshell doors in the rear of the fuselage.", "Units_Built": "Approximately 1375 BO 105s of all models, including military versions, delivered thus far, including licence production in Canada, Indonesia, the Philippines and Spain.", "WTC": "", "Weights": "BO 105 CBS-4 - Empty 1300kg (2868lb), max takeoff 2500kg (5511lb).", "Wingspan_m": "9.84"}'),
