(50745, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Twin turboprop utility transport", "Bibliography": "Airliners.net", "Category": "2T", "Common_Name": "Mu-2", "Country_Origin": "Japan", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The MU-2 was one of postwar Japan''s most successful commercial aircraft types. \\n\\nDevelopment of the MU-2, Mitsubishi''s first indigenous postwar design, began in the late 1950s. Designed as a light twin turboprop transport suitable for a variety of civil and military roles, the MU-2 first flew on September 14 1963. This first MU-2 and the handful of MU-2As built were powered by Turboméca Astazou turboprops, all other models from the MU-2B onwards had Garrett TPE331s. \\n\\nThe MU-2 lineup can be divided up into two basic types, the standard fuselage and stretched fuselage models. The MU-2B, E, F, K, M, P and Solitaire feature the short fuselage, the others, including the Marquise, the stretched fuselage. The first stretched fuselage MU-2G flew on January 10 1969. \\n\\nThe MU-2 was progressively improved and upgraded throughout its production life. Notable changes include improved and more powerful TPE331 engines, and four blade propellers from the N and P models. \\n\\nMitsubishi established a production facility for MU-2s in San Angelo, Texas in the USA in 1967 to build MU-2s for the North American and world markets. The San Angelo Mitsubishi International facility became the sole source of MU-2 production until 1986 when the line finally closed. \\n\\nMitsubishi certificated all the civil TPE331 powered MU-2s as variants of the MU-2B and they were thus given the MU-2B type number followed by a number. However, these MU-2s were also given a separate marketing designation with a sequential suffix letter. The MU-2B-10 is e.g. the MU-2D, and the MU-2B-36A is the MU-2N.\\n\\nFour MU-2Cs and 16 MU-2Ks were delivered to the Japanese Army as LR-1s for the liaison and photo reconnaissance role, while 29 MU-2Es were delivered two the Japanese Air Force as search-and-rescue MU-2Ss, equipped with an extended \\"thimble\\" nose radome, increased fuel capacity, bulged observation windows, and a sliding entry door for dropping rafts.   \\n  \\nIn 2000 over 500 MU-2s were in use as corporate transports (mainly in the USA), while many have been converted as freighters.", "Dimensions": "MU-2B - Wing span 11.94m (39ft 2in), length 10.13m (33ft 3in), height 3.94m (12ft 11in). Wing area 16.5m2 (178sq ft). \\nMarquise - Same except for length 12.01m (39ft 5in), height 4.17m (13ft 8in).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Mitsubishi Mu-2", "Generation": "", "Height_m": "", "IATA_Code": "MU2", "ICAO_Code": "MU2", "Length_m": "10.13", "MTOW_kg": "2422", "Manufacturer": "Mitsubishi", "Max_Pax": "", "Max_Speed_kmh": "500", "Mission_Type": "Passenger", "Model": "Mu-2", "Name": "Mitsubishi MU-2", "Origin": "Japan", "Performance": "MU-2B - Max cruising speed 500km/h (270kt), economical cruising speed 440km/h (237kt). Initial rate of climb 2220ft/min. Max range with reserves 1930km (1040nm). \\nMarquise - Max cruising speed 571km/h (308kt), economical cruising speed 547km/h (295kt). Service ceiling 29,750ft. Range with max fuel and reserves 2585km (1395nm).", "Powerplant_Desc": "MU-2B - Two 430kW (575shp) Garrett AiResearch TPE331-25A turboprops driving three blade constant speed propellers. \\nMarquise - Two 535kW (715shp) Garrett TPE331-10-501Ms driving four blade constant speed propellers.", "Powerplants": "MU-2B - Two 430kW (575shp) Garrett AiResearch TPE331-25A turboprops driving three blade constant speed propellers. \\nMarquise - Two 535kW (715shp) Garrett TPE331-10-501Ms driving four blade constant speed propellers.", "Production_Count": "", "Production_Status": "active", "Range_km": "1930", "Range_nm": "1040", "Record_Status": "active", "Role": "Twin turboprop utility transport", "Seating_Config": "Flightcrew of one or two. Short fuselage models had typical seating for seven in main cabin, longer fuselage models up to 11. Many aircraft in various corporate configurations, or used as freighters.", "Service_Ceiling_ft": "2220", "Source_URL": "https://www.airliners.net/aircraft-data/mitsubishi-mu-2/288", "Status": "In Service", "Typical_Capacity": "Flightcrew of one or two. Short fuselage models had typical seating for seven in main cabin, longer fuselage models up to 11. Many aircraft in various corporate configurations, or used as freighters.", "Units_Built": "Over 800 built. Production comprised three MU-2As, 34 MU-2Bs, four military MU-2Cs (LR-1s), 18 MU-2Ds, 16 military SAR MU-2Ss (MU-2Es), 95 MU-2Fs, 46 MU-2Gs, 108 MU-2Js, 83 MU-2Ks, 36 MU-2Ls, 27 MU-2Ms, 36 MU-2Ns, 31 MU-2Ps, 130 plus Marquise and 60 plus Solitaires.", "WTC": "", "Weights": "MU-2B - Empty 2422kg (5340lb), max takeoff 4050kg (8930lb). \\nMarquise - Empty equipped 3470kg (7650lb), max takeoff 5250kg (11,575lb).", "Wingspan_m": "11.94"}'),
(50746, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "2J", "Common_Name": "/ SNIAS SN.601 Corvette", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Aerospatiale / SNIAS SN.601 Corvette", "Generation": "", "Height_m": "", "IATA_Code": "NDC", "ICAO_Code": "S601", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Aerospatiale", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "/ SNIAS SN.601 Corvette", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "", "Weights": "", "Wingspan_m": ""}'),
(50747, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "2T", "Common_Name": "Aero P180 Avanti II", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Piaggio Aero P180 Avanti II", "Generation": "", "Height_m": "", "IATA_Code": "P18", "ICAO_Code": "P180", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Piaggio", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "Aero P180 Avanti II", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "", "Weights": "", "Wingspan_m": ""}'),
(50748, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "Airliners.net", "Category": "1T", "Common_Name": "PC-12", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The PC-12 is a King Air class and size turboprop aimed at corporate transport and regional airliner operators. It is the latest in a line of single engined PT6 powered Pilatus products. \\n\\nPilatus announced it was developing the PC-12 at the National Business Aircraft Association''s annual convention in October 1989. First flight of the first of two prototypes occurred on May 31 1991. Certification was originally planned for mid 1993 but a redesign of the wings with the addition of winglets to ensure performance guarantees were met pushed this back, with Swiss certification awarded on March 30 1994 and US FAA FAR Part 23 approval following on July 15 1994. \\n\\nCompared to the King Air 200 twin, its major competitor, the PC-12''s most significant design feature is its use of a single PT6A-67B turboshaft. Internally the PC-12''s cabin is also longer (by 6cm/2.4in) and wider (by 15cm/6in) than the King Air 200''s, and the same height. The cockpit features EFIS displays and the PC-12 is certificated for single pilot operation while each PC-12 built features a standard cargo door in the rear fuselage. Weather radar is an option but has been fitted to all production aircraft thus far. From 1997 the increased 4.5 tonne MTOW has been standard. New, smaller winglets were introduced in 1998. \\n\\nThe PC-12 is offered in standard nine seat airliner form, in a four passenger seat/freight combi version and as a six place corporate transport. A pure freighter model is under consideration. The PC-12 Eagle is a military special missions platform. \\n\\nMost PC-12s built thus far have been corporate transports but recent important regulatory changes in Australia, Brazil, Canada and the USA have cleared single engine turboprops for IFR RPT operations in those nations. This has opened up new potential markets for the PC12 as a regional airliner, replacing older King Airs and elderly piston twins such as the Navajo Chieftain and Cessna 400 series.", "Dimensions": "Wing span 16.23m (52ft 3in), length 14.40m (47ft 3in), height 4.27m (14ft 0in). Wing area 25.8m2 (277.8sq ft).", "Engine_Count": "1", "Engine_Type": "Turboprop", "First_Flight_Year": "", "Full_Designation": "Pilatus PC-12", "Generation": "", "Height_m": "", "IATA_Code": "PL2", "ICAO_Code": "PC12", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Pilatus", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "PC-12", "Name": "Pilatus PC12", "Origin": "Switzerland", "Performance": "Max cruising speed at 25,000ft 500km/h (270kt), economical cruising speed 430km/h (232kt). Initial rate of climb 1680ft/min. Max operating altitude 30,000ft. Max range at economical cruising speed with VFR reserves 4187km (2260nm). Range at max cruising speed with IFR reserves 2965km (1600nm).", "Powerplant_Desc": "One 895kW (1200shp) takeoff rated Pratt & Whitney Canada PT6A67B turboprop driving a four blade constant speed Hartzell propeller.", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "Utility, regional airliner and corporate turboprop", "Seating_Config": "Flightcrew of one or two pilots (certificated for single pilot). Seating for nine in main cabin in regional airliner configuration. Corporate/executive transport configurations typically seat six in main cabin. Combi passenger/freight version seats four passengers in main cabin plus freight pallet.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/pilatus-pc12/297", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "Over 280 PC-12s delivered by end of April.", "WTC": "L", "Weights": "PC12 - Standard empty 2600kg (5732lb), max takeoff 4500kg (9920lb).", "Wingspan_m": ""}'),
