(50759, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "2T", "Common_Name": "SC-7 Skyvan", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Shorts SC-7 Skyvan", "Generation": "", "Height_m": "", "IATA_Code": "SHS", "ICAO_Code": "SC7", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Shorts", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "SC-7 Skyvan", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "", "Weights": "", "Wingspan_m": ""}'),
(50760, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "Superjet 100-95", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The Superjet 100 design was launched in 2000, with the aim being to produce a modern regional airliner for the traditional Eastern European/CIS markets. It is also intended to be attractive to Western customers due to lower purchase and operating costs than competing Western designs, but with the required safety and performance features that were often perceived as lacking in older  designs from the Soviet era, preventing sales to that market.\\n\\nSukhoi worked with new partners, notably including Boeing, as they developed the aircraft for the post-Cold War airline environment. The aircraft that emerged is modern and targeted to compete with close competitors such as the Embraer ERJ-190/195 and Bombardier designs, as well as the smaller Airbus and Boeing designs such as the A318 and 737-600.\\n\\nDevelopment was more protracted than expected, but successful, with the first of four prototypes flying on 19 May 2008. Certification was reasonably  straightforward, with a few problems requiring attention, particularly with the new engines. \\n\\nCustomer deliveries began in 2011 when Armenian airline Armavia took delivery of the first production aircraft, with Aeroflot taking its first aircraft later the same year.", "Dimensions": "SSJ 100-95 - Wing span 27.80m (91ft 2in), length 29.94m (98ft 3in). Wing area 84m2 (900sq ft).", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Sukhoi Superjet 100-95", "Generation": "", "Height_m": "", "IATA_Code": "SU9", "ICAO_Code": "SU95", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Sukhoi", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "Superjet 100-95", "Name": "Sukhoi Superjet 100", "Origin": "Russia", "Performance": "SSJ 100-95 - Max cruising speed 870km/h (470kt), typical cruising speed 828km/h (448kt). Range with typical payload 3048km.", "Powerplant_Desc": "SSJ 100-95 - Two 69kN/15,400lb (NTO) PowerJet SaM146 turbofans (78kN/17,500lb APR).", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "Regional jet airliner", "Seating_Config": "Flightcrew of two. \\nSSJ 100-95 - 86 to 103 passengers depending on configuration.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/sukhoi-superjet-100/408", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "The first production Superjet 100 was handed over to launch customer Armavia on 19 April 2011.", "WTC": "M", "Weights": "SSJ 100-95  - Empty 25,100kg (55,000lb), max takeoff 45,880kg (101,100lb).", "Wingspan_m": ""}'),
(50761, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "2J", "Common_Name": "Tu-204 Freighter", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "2", "Engine_Type": "Turbofan", "First_Flight_Year": "", "Full_Designation": "Tupolev Tu-204 Freighter", "Generation": "", "Height_m": "", "IATA_Code": "T2F", "ICAO_Code": "T204", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Tupolev", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "Tu-204 Freighter", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "", "Weights": "", "Wingspan_m": ""}'),
(50762, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Short to medium range airliner", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "Tu-334", "Country_Origin": "Russia", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The advanced technology Tu-334 100 seat jet was developed as a replacement for the aging Tu-134. \\n\\nDevelopment of a replacement for the Tu-134 began in the late 1980s, but it was not until August 1995 at the Moscow Airshow that the first prototype was displayed publicly. The aircraft made its first flight on December 8, 1999. \\n\\nThe Tu-334 was based on the much larger Tu-204 twinjet with Tupolev using as many Tu-204 features in the new design as practical to reduce development time and costs. Examples of this include an identical flightdeck and a shortened Tu-204 fuselage. In addition the Tu-334''s wing is based on the Tu-204''s, although the latter''s is a significantly larger unit. \\n\\nApart from commonality with the Tu-204, other notable Tu-334 design features were the rear fuselage mounted Progress D-436 turbofans, T-tail and fly-by-wire flight controls. \\n\\nIt was planned that the Tu-334 would be developed in a number of versions. The first was the basic Tu-334-100, while the Tu-334-120 was planned to be powered by the BMW Rolls-Royce BR710-48. The Tu-354 (previously Tu-334-200) would have been a stretched, 35m (115ft) long 110 to 126 seater (in a single class). Apart from the fuselage stretch, planned changes included more powerful D436T2 or BR715-55 turbofans, an increased span wing and four wheel main undercarriage units. \\n\\nThe Tu-334-100D would have been a longer range Tu-334-100 featuring the 100''s standard length fuselage but with more powerful engines, increased fuel capacity, a higher max takeoff weight and the increased span wings of the Tu-334-200. Tupolev also studied the Tu-334C, which would have been a freighter. \\n\\nDevelopment of the Tu-334 remained slow due to protracted budget problems and there were numerous delays.  Eventually, in 2009, after the rationalization of the Russian aviation industry, the TU-334 program was cancelled in favor of the Antonov An-148 and the Sukhoi Superjet 100.", "Dimensions": "Tu-334-100 - Wing span 29.77m (97ft 8in), length 31.26m (102ft 7in), height 9.38m (30ft 9in). Wing area 83.2m2 (895.8sq ft). Tu-334-100D - Same except for wing span 32.61m (107ft 0in). Wing area 100.0m2 (1076.4sq ft).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Tupolev Tu-334", "Generation": "", "Height_m": "", "IATA_Code": "T34", "ICAO_Code": "T334", "Length_m": "31.26", "MTOW_kg": "30050", "Manufacturer": "Tupolev", "Max_Pax": "", "Max_Speed_kmh": "820", "Mission_Type": "Passenger", "Model": "Tu-334", "Name": "Tupolev Tu-334", "Origin": "Russia", "Performance": "Tu-334-100 - Typical cruising speeds at 35,000ft 800 to 820km/h (430 to 442kt). Range with 102 passengers 2000km (1080nm). Tu-334-100D - Range with 102 passengers 4100km (2213nm). Tu-354 - Range with 126 passengers 2200km (1187nm).", "Powerplant_Desc": "Tu-334-100 - Two 73.6kN (16,535lb) ZMKB Progress D436T1 turbofans. Tu-334-100D - Two 80.5kN (18,100lb) D436T2s.", "Powerplants": "Tu-334-100 - Two 73.6kN (16,535lb) ZMKB Progress D436T1 turbofans. Tu-334-100D - Two 80.5kN (18,100lb) D436T2s.", "Production_Count": "", "Production_Status": "active", "Range_km": "2000", "Range_nm": "1080", "Record_Status": "active", "Role": "Short to medium range airliner", "Seating_Config": "Tu-334 - Flightcrew of two or three. Seats 102 in a single class arrangement at 78cm (31in) pitch six abreast, or alternatively 72 in a two class arrangement with 12 first class passengers at four abreast and 102cm (40in) pitch and 60 economy class passengers at 78cm (31in) pitch at six abreast.", "Service_Ceiling_ft": "000", "Source_URL": "https://www.airliners.net/aircraft-data/tupolev-tu-334/378", "Status": "In Service", "Typical_Capacity": "Tu-334 - Flightcrew of two or three. Seats 102 in a single class arrangement at 78cm (31in) pitch six abreast, or alternatively 72 in a two class arrangement with 12 first class passengers at four abreast and 102cm (40in) pitch and 60 economy class passengers at 78cm (31in) pitch at six abreast.", "Units_Built": "Two prototypes were built but the type never went into commercial production.", "WTC": "", "Weights": "Tu-334-100 - Empty 30,050kg (66,250lb), max takeoff 46,100kg (101,630lb). Tu-334-100D - Empty 34,375kg (75,785lb), max takeoff 54,420kg (119,975lb).", "Wingspan_m": "29.77"}'),
(50763, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "Airliners.net", "Category": "1T", "Common_Name": "TBM-700", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The TBM-700 is a high performance single engine turboprop powered light business and corporate transport. \\n\\nThe TBM-700 is mainly optimised as a business transport in competition with established twin turboprops, mainly Beech''s C90 King Air series. Unlike the similarly sized C90 King Airs though, the TBM-700''s single engine layout is a major conceptual difference. With its single PT6 turboprop, rather than two on the King Air, the TBM-700 offers significantly lower operating costs yet comparable performance. \\n\\nThe TBM-700 was originally developed in partnership between Socata (Aerospatiale''s General Aviation division) in France and Mooney in the USA, hence the TBM designation. The two companies formed TBM SA to build and market the TBM-700, with development responsibility for the project divided on a 70/30 basis between Socata and Mooney respectively. \\n\\nThe first of three TBM-700 prototypes first flew on July 14 1988. French certification was granted in January 1990. Shortly after the delivery of the first production aircraft in December 1990, Mooney withdrew from the program, leaving Socata with full responsibility for the aircraft. \\n\\nThe pressurised TBM-700 is of conventional design and construction, with a small amount of composite materials used in some areas. Flight controls, flaps and most of the empennage and fin are made from Nomex honeycomb and metal sheets. Leading edges and undercarriage doors meanwhile are made from a carbon and fibreglass composite. Entry to the cabin is through a split upward/downward opening door in the rear port fuselage. \\n\\nApart from the base aircraft the TBM-700 is offered as the TBM-700C freighter with a freight door and separate port side cockpit door. Development of the stretched TBM-700S ceased in 1995.", "Dimensions": "Wing span 12.68m (41ft 7in), length 10.64m (34ft 11in), height 4.35m (14ft 3in). Wing area 18.0m2 (193.8sq ft).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "DAHER-SOCATA TBM-700", "Generation": "", "Height_m": "", "IATA_Code": "TBM", "ICAO_Code": "TBM7", "Length_m": "", "MTOW_kg": "", "Manufacturer": "DAHER-SOCATA", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "TBM-700", "Name": "Socata TBM-700", "Origin": "France", "Performance": "Max cruising speed 555km/h (300kt), economical cruising speed 450km/h (243kt). Initial rate of climb 2380ft/min. Max certificated altitude 30,000ft. Range with max payload and reserves at max cruising speed 1666km (900nm), at economical cruising speed 1853km (1000nm). Range with max fuel at max cruising speed 2500km (1350nm), at economical cruising speed 2870km (1550nm).", "Powerplant_Desc": "One 520kW (700shp) flat rated Pratt & Whitney Canada PT6A-64 turboprop driving a four blade constant speed Hartzell propeller.", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "Single engine corporate turboprop", "Seating_Config": "Pilot and one passenger (or copilot) on flightdeck. Main cabin seating for up to five, or typical accommodation for four in a club arrangement. The TBM-700 is also offered as a freighter.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/socata-tbm-700/370", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "More than 125 in service worldwide. Total of 25 ordered for the French air force and army.", "WTC": "", "Weights": "Empty equipped 1860kg (4101lb), max takeoff 2984kg (6578lb).", "Wingspan_m": ""}'),
(50764, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Short range airliner", "Bibliography": "Airliners.net", "Category": "2J", "Common_Name": "Tu-134", "Country_Origin": "Russia", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "For many years the Tupolev Tu-134 was the standard short haul jet airliner in the Soviet Union and eastern Europe. \\n\\nThe Tupolev design bureau was responsible for the Soviet Union''s first jet powered airliner, the Tu-104 (which was based on the Tu-16 `Badger'' bomber), and the Tu-104''s smaller brother the Tu-124. Both of these short range jetliners suffered from a number of performance shortfalls however, thus prompting development of the Tu-134. \\n\\nThe initial Tu-134 design was based fairly closely on the Tu-124, and for a time was designated the Tu-124A. However Tupolev decided to reconfigure the aircraft to feature rear fuselage mounted engines and a Ttail, resulting in the new designation. \\n\\nSix development Tu-134s were built, with the first flying during 1962. Production began in 1964 although it was not until September 1967 that Aeroflot launched full commercial services. \\n\\nInitial production was of the standard fuselage length Tu-134, while the stretched Tu-134A entered Aeroflot service in the second half of 1970. Seating up to 76 in a single class, the Tu-134A differed from the Tu-134 in having a 2.10m (6ft 11in) fuselage stretch, a reprofiled nose, more powerful D30 engines and an APU. \\n\\nOther versions are the Tu-134B with a forward facing position for the third crew member between and behind the pilots, the Tu-134B1 which has a revised interior to seat up to 90 passengers without a galley, and the Tu-134B3 which can seat 96 with full galley and toilet facilities retained.", "Dimensions": "Tu-134 - Wing span 29.00m (95ft 2in), length 34.35m (112ft 8in), height 9.02m (29ft 7in). Wing area 127.3m2 (1370.3sq ft). Tu-134A - Same except length 37.05m (121ft 7in), height 9.14m (30ft 0in).", "Engine_Count": "2", "Engine_Type": "Turbojet", "First_Flight_Year": "", "Full_Designation": "Tupolev Tu-134", "Generation": "", "Height_m": "", "IATA_Code": "TU3", "ICAO_Code": "T134", "Length_m": "34.35", "MTOW_kg": "27500", "Manufacturer": "Tupolev", "Max_Pax": "", "Max_Speed_kmh": "900", "Mission_Type": "Passenger", "Model": "Tu-134", "Name": "Tupolev Tu-134", "Origin": "Russia", "Performance": "Tu-134 - Max cruising speed 900km/h (485kt), economical cruising speed 750km/h (405kt). Normal operating ceiling 39,730ft. Range with 7000kg (15,420lb) payload and reserves 2400km (1295nm), with 3000kg (6600lb) payload 3500km (1890nm). Tu-134A - Max cruising speed 900km/h (485kt), economical cruising speed 750km/h (405kt). Range with 5000kg (11,025lb) payload and reserves 3020km (1630nm).", "Powerplant_Desc": "Tu-134 - Two 64.5kN (14,490lb) Soloviev D30 turbofans. Tu-134A - Two 66.7kN (14,990lb) Soloviev D30 Series IIs.", "Powerplants": "Tu-134 - Two 64.5kN (14,490lb) Soloviev D30 turbofans. Tu-134A - Two 66.7kN (14,990lb) Soloviev D30 Series IIs.", "Production_Count": "", "Production_Status": "active", "Range_km": "2400", "Range_nm": "1295", "Record_Status": "active", "Role": "Short range airliner", "Seating_Config": "Flightcrew of three, comprising two pilots and a navigator. Tu-134 seats 72 in a single class. Tu-134A seats up to 84 passengers in a single class at four abreast, or 12 first class and 54 economy class at four abreast in a two class arrangement. Tu-134B3 can seat up to 96 in a single class.", "Service_Ceiling_ft": "730", "Source_URL": "https://www.airliners.net/aircraft-data/tupolev-tu-134/375", "Status": "In Service", "Typical_Capacity": "Flightcrew of three, comprising two pilots and a navigator. Tu-134 seats 72 in a single class. Tu-134A seats up to 84 passengers in a single class at four abreast, or 12 first class and 54 economy class at four abreast in a two class arrangement. Tu-134B3 can seat up to 96 in a single class.", "Units_Built": "Production estimated at over 700, most for Aeroflot, but approximately 170 exported to various east European airlines and other Soviet client states. Approx 365 were in service in late 1998.", "WTC": "M", "Weights": "Tu-134 - Operating empty 27,500kg (60,627lb), max takeoff 44,500kg (98,105lb). Tu-134A - Operating empty 29,050kg (64,045lb), max takeoff 47,000kg (103,600lb).", "Wingspan_m": "29.00"}'),
(50765, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Medium range airliner", "Bibliography": "Airliners.net", "Category": "3J", "Common_Name": "Tu-154", "Country_Origin": "Russia", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "Tupolev''s Tu-154 tri-jet remains the standard medium range airliner on domestic flights in Russia and other states of the former Soviet Union and to a lesser extent in eastern Europe and Iran. \\n\\nThe Tu-154 was developed to replace the turbojet powered Tupolev Tu-104, plus the An-10 and Il-18 turboprops. Design criteria in replacing these three relatively diverse aircraft included the ability to operate from gravel or packed earth airfields, to be able to fly at high altitudes above most Soviet Union air traffic, and good field performance. To meet these aims the initial Tu-154 design featured three Kuznetsov (now KKBM) NK-8 turbofans (which also powered the larger, longer range Il-62) giving a relatively good thrust to weight ratio, triple bogie main undercarriage units which retract into wing pods and a rear engine T-tail configuration. \\n\\nThe Tu-154 first flew on October 4 1968. The first production example was delivered to Aeroflot in early 1971, although regular commercial service did not begin until February 1972. \\n\\nThree Kuznetsov powered variants of the Tu-154 were built, the initial Tu-154, the improved Tu-154A with more powerful engines and a higher max takeoff weight, and the Tu-154B with a further increased max takeoff weight. Tu-154S is a freighter version of the Tu-154B. \\n\\nCurrent production is of the Tu-154M, which first flew in 1982. The major change introduced on the M was the far more economical, quieter and reliable Soloviev (now Aviadvigatel) turbofans. Low rate production continues. Meanwhile the proposed Tu-154M-2 with two PS-90A turbofans remains unbuilt.", "Dimensions": "Wing span 37.55m (123ft 3in), length 47.90m (157ft 2in), height 11.40m (37ft 5in). Wing area 201.5m2 (2168.4sq ft).", "Engine_Count": "3", "Engine_Type": "Turbojet", "First_Flight_Year": "", "Full_Designation": "Tupolev Tu-154", "Generation": "", "Height_m": "", "IATA_Code": "TU5", "ICAO_Code": "T154", "Length_m": "47.90", "MTOW_kg": "43500", "Manufacturer": "Tupolev", "Max_Pax": "", "Max_Speed_kmh": "975", "Mission_Type": "Passenger", "Model": "Tu-154", "Name": "Tupolev Tu-154", "Origin": "Russia", "Performance": "Tu-154 - Max cruising speed 975km/h (527kt), economical cruising speed 900km/h (486kt), long range cruising speed 850km/h (460kt). Range with max payload and reserves 3460km (1870nm), range with max fuel and 13,650kg (31,100lb) payload 5280km (2850nm). \\nTu-154M - Max cruising speed 950km/h (513kt). Range with max payload 3900km (2100nm), range with max fuel and 5450kg (12,015lb) payload 6600km (3563nm).", "Powerplant_Desc": "Tu-154 - Three 93.2kN (20,950lb) Kuznetsov NK-82 turbofans. \\nTu-154M - Three 103.6kN (23,380lb) Aviadvigatel (Soloviev) D-30KU-154-II turbofans.", "Powerplants": "Tu-154 - Three 93.2kN (20,950lb) Kuznetsov NK-82 turbofans. \\nTu-154M - Three 103.6kN (23,380lb) Aviadvigatel (Soloviev) D-30KU-154-II turbofans.", "Production_Count": "", "Production_Status": "discontinued", "Range_km": "3460", "Range_nm": "1870", "Record_Status": "active", "Role": "Medium range airliner", "Seating_Config": "Flightcrew of three or four. Typical single class seating for 158 to 164 at six abreast, or 167 in a high density layout for Tu-154; \\nTu-154M seats a maximum of 180 at six abreast and 75cm (29.5in) seat pitch.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/tupolev-tu-154/376", "Status": "In Service", "Typical_Capacity": "Flightcrew of three or four. Typical single class seating for 158 to 164 at six abreast, or 167 in a high density layout for Tu-154; \\nTu-154M seats a maximum of 180 at six abreast and 75cm (29.5in) seat pitch.", "Units_Built": "Approximately 900 Tu-154s of all models have been built, including approximately 325 Tu-154Ms. Approx 580 were in service in late 1998.", "WTC": "H", "Weights": "Tu-154 - Operating empty 43,500kg (95,900lb), max takeoff 90,000kg (198,415lb). \\nTu-154M - Basic operating empty 55,300kg (121,915lb), max takeoff 100,000kg (220,460lb).", "Wingspan_m": "37.55"}'),
