(50770, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Twin turboprop regional airliner", "Bibliography": "Airliners.net", "Category": "2T", "Common_Name": "YS-11", "Country_Origin": "Japan", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The only Japanese airliner to enter production since WW2, the YS-11 achieved a degree of success in its domestic market and in North America. \\n\\nThe YS-11 was a product of the Nihon Aircraft Manufacturing Company (or NAMC), a consortium of Fuji, Kawasaki, Mitsubishi, Nippi, Shin Meiwa (now Shin Maywa) and Showa. NAMC formed on June 1, 1959 to design and develop a short to medium range airliner, with particular attention being paid to meeting the specific operating requirements of the Japanese domestic airlines. \\n\\nNAMC selected the Rolls-Royce Dart over the Allison 501 to power the new airliner. Fuji was given responsibility for the tail unit, Kawasaki the wings and engine nacelles, Mitsubishi the forward fuselage and final assembly, Nippi the ailerons and flaps, Shin Meiwa the rear fuselage and Showa the light alloy honeycomb structural components. \\n\\nThe YS-11 first flew on August 30 1962 (a second prototype flew that December), and was awarded Japanese certification in August 1964. By that time the first production aircraft were under construction, and the type entered service with Toa Airways (now JAS) in April 1965. Initial production was of the YS-11-100, the follow up YS-11A-200 (first flight November 1967) was designed for export markets and featured an increased max takeoff weight. The YS-11A-300 was a combi passenger/freight model, while the YS-11A-400 was a pure freighter with a forward freight door. \\n\\nThe YS-11A-500, -600 and -700 were equivalent to the -200, -300 and -400, but with a 500kg (1100lb) greater max takeoff weight. Production ceased in February 1974. \\n\\nBy late 1998, 66 YS-11s remained in commercial service. The largest operators were All Nippon (6) and Japan Air Commuter (12).", "Dimensions": "Wing span 32.00m (105ft 0in), length 26.30m (86ft 4in), height 8.98m (29ft 6in). Wing area 94.8m2 (1020.4sq ft).", "Engine_Count": "2", "Engine_Type": "Turboprop", "First_Flight_Year": "", "Full_Designation": "NAMC YS-11", "Generation": "", "Height_m": "", "IATA_Code": "YS1", "ICAO_Code": "YS11", "Length_m": "26.30", "MTOW_kg": "15419", "Manufacturer": "NAMC", "Max_Pax": "", "Max_Speed_kmh": "470", "Mission_Type": "Passenger", "Model": "YS-11", "Name": "NAMC YS-11", "Origin": "Japan", "Performance": "200 - Max cruising speed 470km/h (253kt), economical cruising speed 452km/h (244kt). Range with max payload and no reserves 1090km (590nm), range with payload and no reserves 3215km (1736nm).", "Powerplant_Desc": "YS11A200 - Two 2280kW (3060shp) RollsRoyce Dart 54210K turboprops driving four blade constant speed propellers.", "Powerplants": "YS11A200 - Two 2280kW (3060shp) RollsRoyce Dart 54210K turboprops driving four blade constant speed propellers.", "Production_Count": "", "Production_Status": "active", "Range_km": "1090", "Range_nm": "590", "Record_Status": "active", "Role": "Twin turboprop regional airliner", "Seating_Config": "Flightcrew of two. Typical single class seating in main cabin for 60 at four abreast and 86cm (34in) pitch. The combi YS11A300 accommodates freight in the forward portion of the main cabin with seating for 46 behind that.", "Service_Ceiling_ft": "", "Source_URL": "https://www.airliners.net/aircraft-data/namc-ys-11/287", "Status": "In Service", "Typical_Capacity": "Flightcrew of two. Typical single class seating in main cabin for 60 at four abreast and 86cm (34in) pitch. The combi YS11A300 accommodates freight in the forward portion of the main cabin with seating for 46 behind that.", "Units_Built": "182 YS-11s built comprising two prototypes, 48 series 100s, 83 Series 200s, 31 series 300s, eight series 400s, two series 500s and eight series 600s. Production total includes 23 for Japanese military. 66 remained in service at late 1998.", "WTC": "M", "Weights": "200 - Operating empty 15,419kg (33,993lb), max takeoff 24,500kg (54,010lb).", "Wingspan_m": "32.00"}'),
(50771, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "", "Bibliography": "", "Category": "", "Common_Name": "A330-700 Beluga XL", "Country_Origin": "", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "", "Dimensions": "", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Airbus A330-700 Beluga XL", "Generation": "", "Height_m": "", "IATA_Code": "", "ICAO_Code": "A337", "Length_m": "", "MTOW_kg": "", "Manufacturer": "Airbus", "Max_Pax": "", "Max_Speed_kmh": "", "Mission_Type": "Passenger", "Model": "A330-700 Beluga XL", "Name": "", "Origin": "", "Performance": "", "Powerplant_Desc": "", "Powerplants": "", "Production_Count": "", "Production_Status": "active", "Range_km": "", "Range_nm": "", "Record_Status": "active", "Role": "", "Seating_Config": "", "Service_Ceiling_ft": "", "Source_URL": "", "Status": "In Service", "Typical_Capacity": "", "Units_Built": "", "WTC": "", "Weights": "", "Wingspan_m": ""}'),
(50772, 22581, NULL, 'Global/Aircraft', 'aircraft_types.csv', '{"Aircraft_Type": "Four or six place business, utility & advanced pilot training twin", "Bibliography": "Airliners.net", "Category": "", "Common_Name": "Baron", "Country_Origin": "United States of America", "Data_Source": "merged", "Date_Added": "2026-05-23", "Date_Modified": "2026-05-23", "Development_Story": "The successful and long running Baron line is widely regarded as the most successful of its class, and has comfortably outlasted its main rivals from Piper and Cessna in production. <p>Development of the Baron began in the late 1950s, the first to fly, the Model 9555 on February 29 1960, essentially being a reengined development of the Model 95 Travel Air (Beech''s first light twin, which first flew in August 1956). As a result the Baron can lay claim to Bonanza and T34 Mentor lineage, as the Travel Air combined the fuselage of the former with the tail of the latter, plus twin engines, a new wing and other new features. Some 720 Travel Airs were built from the late 1950s to the late 1960s. <p>The first Barons were delivered during early 1961, although these early production examples were soon followed off the line in 1962 by the improved A55. The subsequent B55 of 1965 is a definitive Baron model and remained in production until 1982, during which time it was continually refined. During the B55''s model life other variants entered production, these included the more powerful C55, D55 and E55. In the meantime the turbocharged Baron 56TC appeared in 1967 and the A56TC in 1970, although these were produced only in limited numbers. <p>The Model 58 is a stretched version of the 55, and first entered production in 1970. It remains in production today, having evolved somewhat in production during that time. Versions include the pressurised 58P and the turbocharged 58TC. Both are powered by 240kW (325hp) Teledyne Continental TSIO520s. Current production (now under the Raytheon Aircraft Company banner) runs at around 40 per year. <p>", "Dimensions": "B55 - Wing span 11.53m (37ft 10in), length 8.53m (28ft 0in), height 2.92m (9ft 7in). Wing area 18.5m2 (199.2sq ft). 58 - Wing span 11.53m (37ft 10in), length 9.09m (29ft 10in), height 2.97m (9ft 9in). Wing area 18.5m2 (199.2sq ft).", "Engine_Count": "", "Engine_Type": "", "First_Flight_Year": "", "Full_Designation": "Beechcraft Baron", "Generation": "", "Height_m": "", "IATA_Code": "", "ICAO_Code": "BE58", "Length_m": "8.53", "MTOW_kg": "1468", "Manufacturer": "Beechcraft", "Max_Pax": "", "Max_Speed_kmh": "373", "Mission_Type": "Passenger", "Model": "Baron", "Name": "Raytheon Beechcraft Baron", "Origin": "United States of America", "Performance": "B55 - Max speed 373km/h (201kt), max cruising speed 348km/h (188kt), long range cruising speed 320km/h (173kt). Initial rate of climb 1693ft/min. Range with reserves 1836km (990nm). 58 - Max speed 386km/h (208kt), cruising speed 367km/h (198kt). Initial rate of climb 1735ft/min. Range with reserves 2920km (1575nm).", "Powerplant_Desc": "B55 - Two 140kW (260hp) Continental IO470L fuel injected horizontally opposed flat six piston engines driving two blade constant speed propellers. 58 - Two 225kW (300hp) Teledyne Continental IO550C engines driving three blade constant speed McCauley propellers.", "Powerplants": "B55 - Two 140kW (260hp) Continental IO470L fuel injected horizontally opposed flat six piston engines driving two blade constant speed propellers. 58 - Two 225kW (300hp) Teledyne Continental IO550C engines driving three blade constant speed McCauley propellers.", "Production_Count": "", "Production_Status": "active", "Range_km": "1836", "Range_nm": "990", "Record_Status": "active", "Role": "Four or six place business, utility & advanced pilot training twin", "Seating_Config": "Models 55 and 56 had standard seating for four, with some models offering an optional fifth seat. Model 58 has optional fifth and sixth seats.", "Service_Ceiling_ft": "1693", "Source_URL": "https://www.airliners.net/aircraft-data/raytheon-beechcraft-baron/325", "Status": "In Service", "Typical_Capacity": "Models 55 and 56 had standard seating for four, with some models offering an optional fifth seat. Model 58 has optional fifth and sixth seats.", "Units_Built": "Production of the Model 58 Baron continues, with more than 2500 of all variants built by late 1998.", "WTC": "", "Weights": "B55 - Empty 1468kg (3236lb), max takeoff 2313kg (5100lb). 58 - Empty 1619kg (3570lb), max takeoff 2495kg (5500lb).", "Wingspan_m": "11.53"}'),
